(7598, 2, 'అధీశుడు', 'n', 'సామంతులు సేవించే రాజు, ప్రభువు;   అధిరాజు, అధీశ్వరుడు, పాలకుడు, భూపతి', '', '', '', '', '2026-05-02 13:47:18'),
(7599, 2, 'అధునాతనం', 'n', 'ఇప్పటి కాలానికి చెందినవి, ఆధునికం;   నవీనం, ఆధునిక కాలం', '', '', '', '', '2026-05-02 13:47:18'),
(7600, 2, 'అధ్యక్షుడు', 'n', 'ప్రధానాధికారి;  అధినాథుడు, అధినేత, అధిపతి, అధిపుడు', '', '', '', '', '2026-05-02 13:47:18'),
(7601, 2, 'అధ్యాపకులు', 'n', 'వేదాలను చదివే వారు, చదువు చెప్పేవారు, గురువులు,   ఆచార్యులు, శిక్షకులు, శిక్షాకరులు', '', '', '', '', '2026-05-02 13:47:18'),
(7602, 2, 'అధ్యాయం', 'n', 'గ్రంథ భాగం, ప్రకరణం, వేద పఠ నారకాలం; వ్యతి అనధ్యాయం', '', '', '', '', '2026-05-02 13:47:18'),
(7603, 2, 'అధ్వానం', 'n', 'అమార్గం, అధ్వాన్నం', '', '', '', '', '2026-05-02 13:47:18'),
(7604, 2, 'అనంతం', 'n', 'నేర లేనిది, నాశరహితమైనది;   అంతరిక్షం, అంబరం', '', '', '', '', '2026-05-02 13:47:18'),
(7605, 2, 'అనంతరం', 'n', 'తరవాత హ్యా అవ్వల, ఆదట, ఆ పైన, ఆ మీద తరువాయి, పిమ్మట', '', '', '', '', '2026-05-02 13:47:18'),
(7606, 2, 'అనంతుడు', 'n', 'శ్రేష్ఠుడు, విష్ణువు, వాసుకి,   అచ్యుతుడు, అజుగుడు, అజయుడు', '', '', '', '', '2026-05-02 13:47:18'),
(7607, 2, 'అనద', 'v,n', 'దిక్కులేనిది, అశక్తుడు, అల్పుడు;  అనాథ, అనాథుడు', '', '', '', '', '2026-05-02 13:47:18'),
(7608, 2, 'అనర్గళం', 'n', 'అడ్డులేనిది', '', '', '', '', '2026-05-02 13:47:18'),
(7609, 2, 'అనలుడు', 'n', 'అగ్ని దేవుడు;   అంభోజుడు, అగ్గి, అగ్నిహోత్రం', '', '', '', '', '2026-05-02 13:47:18'),
(7610, 2, 'అనవరతం', 'n', 'ఎడతెగనిది, నిరంతరం; ప్యూ అనిశం, అవిరామం, అహర్నిశం', '', '', '', '', '2026-05-02 13:47:18'),
(7611, 2, 'అనాచారం', 'n', 'ఆచారం లేనిది;   కృష్ణాచారం, దురాచారం', '', '', '', '', '2026-05-02 13:47:18'),
(7612, 2, 'అనాథ', 'n', 'నాథుడు లేనిది;  అనద అనాద, అనపాశ్రయుడు', '', '', '', '', '2026-05-02 13:47:18'),
(7613, 2, 'అనావృష్టి', 'n', 'వాన లేకపోవడం;  కరవు, కాటకం, క్షామం, దుర్భిక్షం;  X  అతివృష్టి', '', '', '', '', '2026-05-02 13:47:18'),
(7614, 2, 'అనిత్యం', 'n', 'నిత్యం కానిది; శాశ్వతం కానిది; తాత్కాలికమైనది', '', '', '', '', '2026-05-02 13:47:18'),
(7615, 2, 'అనుగు', 'v', 'ప్రేమ, చెలికాడు, ముఖ్యుడు;  ప్రీతి, ప్రేముడి, వాత్సల్యం', '', '', '', '', '2026-05-02 13:47:18'),
(7616, 2, 'అనుగ్రహం', 'n', 'దయ, కరుణ;  అనుషంగం, ఆదరణ, కార్పణ్యం, కృప', '', '', '', '', '2026-05-02 13:47:18'),
(7617, 2, 'అనుబంధం', 'n', 'అనువర్తనం, చుట్టరికం, గ్రంథానికి చివర చేర్చిన భాగం;   పొత్తు, బంధం, సమాయోగం', '', '', '', '', '2026-05-02 13:47:18'),
(7618, 2, 'అనుభూతి', 'n', 'అనుభుక్తి, (మానసిక) అనుభవం;  అనుభోగం, ఉపలంభం, సంవేదన', '', '', '', '', '2026-05-02 13:47:18'),
(7619, 2, 'అనుమతి', 'n', 'సమ్మతి, ఆజ్ఞ,   అంగీకారం, అంగీకృతి, అనుజ్ఞ;  X  అసమ్మతి', '', '', '', '', '2026-05-02 13:47:18');
