(7620, 2, 'అనుయాయులు', 'n', 'వెంబడించే వారు, ఆశ్రితులు', '', '', '', '', '2026-05-02 13:47:18'),
(7621, 2, 'అనువు', 'v', 'అను కూల్యం, విధం, ఉపాయం;  అధీనం, ఆయత్తం, స్వాధీనం', '', '', '', '', '2026-05-02 13:47:18'),
(7622, 2, 'అనుష్టానం', 'n', 'ఆచారం, నడవడి, వాడుక;  సంప్రదాయం, సంవిత్తు, సమామ్నాయం', '', '', '', '', '2026-05-02 13:47:18'),
(7623, 2, 'అనూడ', 'n', 'పెండ్లికాని పడుచు;  కన్య, అనన్య, అవివాహిత', '', '', '', '', '2026-05-02 13:47:18'),
(7624, 2, 'అనూరుడు', 'n', 'తొడలు లేనివాడు;  పిచ్చుకుంటు, సూర్య సూతుడు', '', '', '', '', '2026-05-02 13:47:18'),
