(7626, 2, 'అన్నతం', 'n', 'అబద్దం, అసత్యమైనది', '', '', '', '', '2026-05-02 13:47:18'),
(7627, 2, 'అన్యోన్యం', 'n', 'పరస్పరం;  ఒండొండు, ఒండొకరుండు', '', '', '', '', '2026-05-02 13:47:18'),
(7628, 2, 'అపకారం', 'n', 'కీడు, ద్రోహం, చెడ్డపని;   అపక్రియ, అపచారం, హాని', '', '', '', '', '2026-05-02 13:47:18'),
(7629, 2, 'అపయశం', 'n', 'అపకీర్తి;  అపఖ్యాతి, అపప్రథ, అపవాదం, అప్రతిష్ఠ', '', '', '', '', '2026-05-02 13:47:18'),
(7630, 2, 'అపరాహ్లావేళ', 'n', 'పగటిని మూడు భాగాలుగా విభజిస్తే, అందులో చివరి భాగం', '', '', '', '', '2026-05-02 13:47:18'),
(7631, 2, 'అపర్ణ', 'n', 'పార్వతి;  అంబ, అంబిక, గిరిజ, చండి, దుర్గ', '', '', '', '', '2026-05-02 13:47:18'),
(7632, 2, 'అపహరణం', 'n', 'దొంగిలించుకొని పోవడం; మోసగించికొని పోవడం;  అపహరింత, అభిగ్రహం; చౌర్యం, దొంగపని', '', '', '', '', '2026-05-02 13:47:18'),
(7633, 2, 'అపహసించు', 'v', 'గేలిసేయు, నవ్వు;  ఉల్లసమాడు, గేలి పెట్టు, ఎగతాళి చేయు, పరియాచకం', '', '', '', '', '2026-05-02 13:47:18'),
(7634, 2, 'అపాయం', 'n', 'హాని, ప్రమాదం,  ఇక్కట్టు, కష్టం, ఇడుం, కీడు', '', '', '', '', '2026-05-02 13:47:18'),
(7635, 2, 'అపారం', 'n', 'ఇవతలి ఒడ్డు, ఈవలి దరి,  భూరి, మిక్కిలి, మెండు', '', '', '', '', '2026-05-02 13:47:18'),
(7636, 2, 'అపార్థం', 'n', 'తప్పు అర్థం;  వ్యర్థం, నిరసించు', '', '', '', '', '2026-05-02 13:47:18'),
(7637, 2, 'అపురూపం', 'v,n', 'అపూర్వం, పూర్వం లేనిది, ఎంతో ప్రియమైనది  అసామాన్యం, అసాధారణం', '', '', '', '', '2026-05-02 13:47:18'),
(7638, 2, 'అపూర్వం', 'v,n', 'పూర్వం లేనిది; అరుదు', '', '', '', '', '2026-05-02 13:47:18'),
(7639, 2, 'అపేక్ష', 'n', 'కోరిక, కాంక్ష;  అభికాంక్ష, అభిలాష అభీష్టం, ఆకాంక్ష', '', '', '', '', '2026-05-02 13:47:18'),
(7640, 2, 'అపోహ', 'n', 'లేనిది ఊహించడం అనుమానం', '', '', '', '', '2026-05-02 13:47:18'),
(7641, 2, 'అప్పగించు', '', 'వైక్రి ఒప్పగించు, అర్పించు;  ఒప్పచెప్పు, ఒప్పనం, దత్తం చేయు, దారవోయు', '', '', '', '', '2026-05-02 13:47:18'),
(7642, 2, 'అప్పుజుడు, సితుడు శుక్లం', 'n', 'తెల్లనిది,   తెలుపు, వెండి, మాసంలోని మొదటి పక్షం, ప్రభవాది సంవత్సరాల్లో ఒకటి, విష్కంభాది యోగాల్లో ఒకటి', '', '', '', '', '2026-05-02 13:47:18'),
(7643, 2, 'అప్రతిష్ట', 'n', 'అపకీర్తి, అగౌరవం;   అప ఖ్యాతి, ఆపయశం; వ్యతి ప్రతిష్ఠ', '', '', '', '', '2026-05-02 13:47:18'),
(7644, 2, 'అబద్దం', 'n', 'నిజంకానిది, అసంగతం, ప్రయోజనం లేనిది;  అనృతం, కల్ల, బూటకం', '', '', '', '', '2026-05-02 13:47:18'),
(7645, 2, 'అబల', 'n', 'స్త్రీ;  అంగన అతివ, ఇంతి, మగువ', '', '', '', '', '2026-05-02 13:47:18'),
(7646, 2, 'అభిజ్ఞానం', 'n', 'గురు, గుర్తుపట్టడం, జ్ఞానం, తెలివి; హ్యా ఎరుక చేతన, మతి', '', '', '', '', '2026-05-02 13:47:18'),
(7647, 2, 'అభినందన', 'n', 'సంతోషం, పొగడటం, ప్రోత్సాహపరచడం', '', '', '', '', '2026-05-02 13:47:18'),
(7648, 2, 'అభినయం', 'n', 'నటన', '', '', '', '', '2026-05-02 13:47:18'),
(7649, 2, 'అభినివేశం', 'n', 'అభిరుచి, ప్రవేశం, చొరవ, పట్టుదల, అభిలాష;  అచలం, పూనిక', '', '', '', '', '2026-05-02 13:47:18'),
(7650, 2, 'అభిభాషణ', 'v', 'సం వి ఉపన్యాసం', '', '', '', '', '2026-05-02 13:47:18'),
(7651, 2, 'అభిమతం', 'n', 'సమ్మతి, కోరిక;  అంగీకారం, అంగీకృతి, ఇష్టం', '', '', '', '', '2026-05-02 13:47:18'),
(7652, 2, 'అభిమానం', 'n', 'ప్రేమ, ఆత్మగౌరవం;  అనుగు, అనురక్తి, అనురాగం, అభిమతి', '', '', '', '', '2026-05-02 13:47:18'),
(7653, 2, 'అభిముఖం', 'n', 'ఎదురెదురుగా;  ఎదురు, ప్రతిముఖం, ముఖా ముఖి', '', '', '', '', '2026-05-02 13:47:18'),
(7654, 2, 'అభియోగం', 'n', 'నింద, ఆసక్తి, వ్యాజ్యం;  ఆరోపణం, ఆరోపం', '', '', '', '', '2026-05-02 13:47:18'),
(7655, 2, 'అభిరామం', 'n', 'మనోహరం;  మంజులం, మనోజ్ఞం, మనోరంజనం, రమ్యం', '', '', '', '', '2026-05-02 13:47:18'),
(7656, 2, 'అభిరుచి', 'n', 'అత్యాసక్తి, రుచి,  ఆసత్తి, శ్రద్ధ, సంసక్తి', '', '', '', '', '2026-05-02 13:47:18'),
(7657, 2, 'అభిషేకం', 'n', 'తడపడం, స్నానం, చేయించడం;  అవభృంధం, జలకం, తానం', '', '', '', '', '2026-05-02 13:47:18'),
(7658, 2, 'అభేదం', 'n', 'భేదంలేని, ఏకీభావం;  అభిన్నం, సమరసం', '', '', '', '', '2026-05-02 13:47:18'),
(7659, 2, 'అభ్యర్థన', 'n', 'కోరిక, మనవి, విన్నపం', '', '', '', '', '2026-05-02 13:47:18'),
(7660, 2, 'అభ్యర్థి', 'n', 'దరఖాస్తుదారుడు, ఎన్నికలలో పోటీ చేయు వ్యక్తి', '', '', '', '', '2026-05-02 13:47:18'),
(7661, 2, 'అభ్యాగతులు', 'n', 'వచ్చినవారు, భోజన సమయానికి వచ్చిన అతిథులు', '', '', '', '', '2026-05-02 13:47:18'),
(7662, 2, 'అభ్యాసం', 'n', 'అలవాటు, సాధన', '', '', '', '', '2026-05-02 13:47:18'),
