(7664, 2, 'అభ్యుదయం', 'n', 'శుభోదయం, వృద్ధి;   శుభం, కల్యాణం', '', '', '', '', '2026-05-02 13:47:18'),
(7665, 2, 'అభ్రమణి', 'n', 'సూర్యుడు;  అంశుడు, అంశుమాలి, అరుణ కిరణుడు, ఆదిత్యుడు', '', '', '', '', '2026-05-02 13:47:18'),
(7666, 2, 'అమడలు', 'v', 'జంట; సం యమళః;   జంట, జత, జోడు, ద్వయం', '', '', '', '', '2026-05-02 13:47:18'),
