(8072, 2, 'ఉట్టి', 'v', 'పాత్రలుంచడానికి వేలాడదీసిన చిక్కం;  ఉగ్గం, శిక్యం', '', '', '', '', '2026-05-02 13:47:18'),
(8073, 2, 'ఉట్టిపడు', 'v', 'స్రవించు, ఉన్నట్టుండి ఏర్పడు /వచ్చు;  అగపడు, అగు, అలరు', '', '', '', '', '2026-05-02 13:47:18'),
(8074, 2, 'ఉడిగం', 'v,n', 'సేవ, ఊడిగం;  ఉపచారం, చాకిరి, నౌకరి', '', '', '', '', '2026-05-02 13:47:18'),
(8075, 2, 'ఉడుకుబోతు', 'v,n', 'అసూయాపరుడు;  అంకకాడు, బలిమిడి , మచ్చరీడు, మాత్సర్యశీలుడు', '', '', '', '', '2026-05-02 13:47:18'),
(8076, 2, 'ఉడుత', 'v', 'చెట్టు మీద నివసించే జంతువు,  చమర పుచ్చం, వృక్షమర్కటిక, వృక్షశాయిక', '', '', '', '', '2026-05-02 13:47:18'),
(8077, 2, 'ఉడుపథం', 'n', 'నక్షత్రమార్గం, ఆకాశం;  అంబరం, అంతరిక్షం', '', '', '', '', '2026-05-02 13:47:18'),
(8078, 2, 'ఉడుపులు', 'v', 'దుస్తులు;  అంబరం, ఆచ్చాదనం', '', '', '', '', '2026-05-02 13:47:18'),
(8079, 2, 'ఉడుము', 'v', 'బల్లివంటి పెద్ద జంతువు;రూ ఉజుము;  గోధ, గోధి, గోధిక, నిహాక, పంచనఖం', '', '', '', '', '2026-05-02 13:47:18'),
(8080, 2, 'ఉడువీధి', 'n', 'ఆకాశమార్గం', '', '', '', '', '2026-05-02 13:47:18'),
(8081, 2, 'ఉతకడం', 'v', 'మురికి పోవడానికి వస్త్రాలను రాతి మీద కొట్టడం', '', '', '', '', '2026-05-02 13:47:18'),
(8082, 2, 'ఉత్కంఠ', 'n', 'కోరిన వస్తువును పొందటానికి తొందర, తహతహ  ఉత్సుకం, తమకం', '', '', '', '', '2026-05-02 13:47:18'),
(8083, 2, 'ఉత్కరం', 'n', 'మేలు, అతిశయం, అభివృద్ధి;  అభినందనం, కొనియాడు', '', '', '', '', '2026-05-02 13:47:18'),
(8084, 2, 'ఉత్కృష్టం', 'n', 'మేలైనది, అధికం;  ఉదాత్తం, మిక్కిలి, మిన్న', '', '', '', '', '2026-05-02 13:47:18'),
(8085, 2, 'ఉత్త', 'v,n', 'వట్టి, కేవలం, అసత్యం; సం వ్యర్థమ్, రిక్తమ్', '', '', '', '', '2026-05-02 13:47:18'),
(8086, 2, 'ఉత్తమం', 'n', 'శ్రేష్ఠం, ముఖ్యం,  ఉత్తాలం, ఉత్కృష్టం, ఉదాత్తం, నాణ్యం', '', '', '', '', '2026-05-02 13:47:18'),
(8087, 2, 'ఉత్తరం', 'n', 'లేఖ, జాబు, బదులు, ఒక దిక్కు;  ఉదీచి, కాబేరి', '', '', '', '', '2026-05-02 13:47:18'),
(8088, 2, 'ఉత్తరాయణం', 'n', 'సూర్యుడు డిసెంబరు 22వ తేదీన మకర రేఖను చేరి అచ్చటి నుండి ఉత్తర దిక్కుకు మరలునప్పటి నుండి ఆరునెలల కాలం, సంవత్సరంలో వచ్చే రెండు ఆయనాలలో ఒకటి', '', '', '', '', '2026-05-02 13:47:18'),
(8089, 2, 'ఉత్తరువు', 'v,', 'ఆజ్ఞ, అనుజ్ఞ, ఆదేశం, సెలవు; సం ఉత్తరమ్;  అనుశాసనం, ఆన, ఆనతి, పరమానా, హుకుం', '', '', '', '', '2026-05-02 13:47:18'),
(8090, 2, 'ఉత్తరేను', 'v', 'శైఖరిక, అపామార్గం, ఉత్తరేణి;  అపామార్గం, మయూరకం', '', '', '', '', '2026-05-02 13:47:18'),
(8091, 2, 'ఉత్తీర్ణుడు', 'n', 'దాటబడినవాడు; పరీక్షలలో కృతార్థుడైనవాడు', '', '', '', '', '2026-05-02 13:47:18'),
(8092, 2, 'ఉత్తేజం', 'n', 'ఉద్రేకాన్ని కలిగించేది, పేరణ, ఉద్దీపనం, ఉత్సాహాన్ని పుట్టించేది', '', '', '', '', '2026-05-02 13:47:18');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(8093, 2, 'ఉత్పత్తి', 'n', 'పుట్టుక, పుట్టేచోటు, తయారీ;  ఆవిర్భావం, ఆవిర్భూతం, ప్రాదుర్భావం', '', '', '', '', '2026-05-02 13:47:18'),
(8094, 2, 'ఉత్పలం', 'n', 'కలువ, నల్లకలువ;  కల్వ, కల్హారం, కువలయం', '', '', '', '', '2026-05-02 13:47:18'),
(8095, 2, 'ఉత్పాదకులు', 'n', 'ఉత్పత్తి చేసేవారు', '', '', '', '', '2026-05-02 13:47:18'),
(8096, 2, 'ఉత్పాదన శక్తి', 'n', 'నియతకాలంలో చేయగలిగిన కార్యం', '', '', '', '', '2026-05-02 13:47:18'),
(8097, 2, 'ఉత్ర్పేక్ష', 'n', 'ఊహ, ఒక అర్థాలంకారం;  అనుమ, అనుమితి, హృల్లేఖం, భావం', '', '', '', '', '2026-05-02 13:47:18'),
(8098, 2, 'ఉత్సంగం', 'n', 'ఒడి, తొడ, ఆలింగనం', '', '', '', '', '2026-05-02 13:47:18'),
(8099, 2, 'ఉత్సవం', 'n', 'ఊరేగింపు, పండుగ;  క్షణం, వేడుక, సంబరం', '', '', '', '', '2026-05-02 13:47:18'),
(8100, 2, 'ఉత్సహించు', 'v', 'యత్నించు, ఉత్సాహపడు, సంతోషపడు, ఉత్సాహించు,  మాను, పూనుకొను, సమకట్టు', '', '', '', '', '2026-05-02 13:47:18'),
(8101, 2, 'ఉత్సాహం', 'n', 'ప్రయత్నం, సంతోషం, కోరిక;  అంగద, అగ్గలిక', '', '', '', '', '2026-05-02 13:47:18'),
(8102, 2, 'ఉత్సేకం', 'n', 'అతిశయం, గర్వం, పొంగు;  అవలేపం, ఉద్దతి', '', '', '', '', '2026-05-02 13:47:18'),
(8103, 2, 'ఉదకం', 'n', 'నీరు,  తడి పేది, ఉదము;  అంబువు, ఘృతం, జలం', '', '', '', '', '2026-05-02 13:47:18'),
(8104, 2, 'ఉదజం', 'n', 'నీటిలో పుట్టేది, పద్మం;  అంబుజం, అంభోరుహం, కమలం, కుముదం', '', '', '', '', '2026-05-02 13:47:18'),
(8105, 2, 'ఉదధి', 'n', 'సముద్రం;  అంబుధి, అబ్ది, కడలి, జలధి', '', '', '', '', '2026-05-02 13:47:18'),
(8106, 2, 'ఉదయం', 'n', 'పుట్టుక, సృష్టి, ప్రాతఃకాలం;  ఉదిత, పొడుపు, ప్రొద్దు పొడుపు', '', '', '', '', '2026-05-02 13:47:18'),
(8107, 2, 'ఉదయించు', 'v', 'పుట్టు;  పొడతెంచు, పొడుచు', '', '', '', '', '2026-05-02 13:47:18'),
(8108, 2, 'ఉదరం', 'n', 'కడుపు;  కంజరం, పొట్ట, బొజ్జ, బొజ్జ', '', '', '', '', '2026-05-02 13:47:18'),
(8109, 2, 'ఉదాత్తం', 'n', 'గౌరవమైనది, ధారాళం, మనోహరమైనది;  ఉత్తమం, ఉత్కృష్టం', '', '', '', '', '2026-05-02 13:47:18'),
(8110, 2, 'ఉదారం', 'n', 'గొప్పది;  ఔదార్యం, దయాదాక్షిణ్యం', '', '', '', '', '2026-05-02 13:47:18'),
(8111, 2, 'ఉదారుడు', 'n', 'గొప్పవాడు, దాత;  దానశీలుడు, దానశూరుడు, వదాన్యుడు', '', '', '', '', '2026-05-02 13:47:18'),
(8112, 2, 'ఉదాసీనం', 'n', 'తటస్థంగా ఉండేది, ఏదీ పట్టించుకోకపోవడం;  అనాస్థ, పరాకు', '', '', '', '', '2026-05-02 13:47:18'),
(8113, 2, 'ఉదాహరణం', 'n', 'దృష్టాంతం, తార్కాణ;  ఉదాహారం, ఉదాహృతి, తార్కాణం', '', '', '', '', '2026-05-02 13:47:18'),
(8114, 2, 'ఉదాహరించు', 'v', 'ఉదాహరణంగా చెప్పు, ఉదాహరణంగా చూపు;  తార్కాణించు, దృష్టాంతీకరించు', '', '', '', '', '2026-05-02 13:47:18'),
(8115, 2, 'ఉద్ఘాటన', 'n', 'ఉగ్గడించడం, ప్రకటన, పైకిలాగడం, వెలికి చెప్పడం, అడ్డం లేకుండ చేయడం;  అంకుటం, కుంచిక', '', '', '', '', '2026-05-02 13:47:18'),
(8116, 2, 'ఉద్దతుడు', 'n', 'గర్వి; బహు ఉద్ధతులు;  గర్విష్ఠి పొగరుబోతు', '', '', '', '', '2026-05-02 13:47:18'),
(8117, 2, 'ఉద్దర', 'v', 'తాకట్టు,  ఉద్దరువు, గిరవు, తాకట్టు', '', '', '', '', '2026-05-02 13:47:18'),
(8118, 2, 'ఉద్దరించు', 'v', 'పెల్లగించు, మీదికెత్తు, రక్షించు;  ఉత్సాదించు, ఉప్పరమెత్తు, ఉప్పరించు', '', '', '', '', '2026-05-02 13:47:18'),
(8119, 2, 'ఉద్ది', 'v', 'జత, జట్టు;  ఈడు జోడు, జట్టి, దీటు, సరి, సాటి', '', '', '', '', '2026-05-02 13:47:18'),
(8120, 2, 'ఉద్దీడు', 'v', 'జతకాడు, మిత్రుడు, ఉద్దికాడు;  చెలికాడు, నెచ్చెలి, స్నేహితుడు', '', '', '', '', '2026-05-02 13:47:18'),
(8121, 2, 'ఉద్దేశం', 'n', 'గురి, తలంపు, నిశ్చయం,  అవధానం, ఉపధారణం', '', '', '', '', '2026-05-02 13:47:18'),
(8122, 2, 'ఉద్బోధ', 'n', 'కాసం, ఉపదేశం, మేల్కొనడం', '', '', '', '', '2026-05-02 13:47:18'),
(8123, 2, 'ఉద్యమం', 'n', 'యత్నం, సిద్ధం కావడం;  ఉద్యతి, కదలిక', '', '', '', '', '2026-05-02 13:47:18'),
(8124, 2, 'ఉద్యమించు', 'v', 'ప్రారంభించు, యత్నించు, మొదలు పెట్టు;  ఉత్సహించు, సమకట్టు', '', '', '', '', '2026-05-02 13:47:18'),
(8125, 2, 'ఉద్యానం', 'n, v', 'హారార్థం ఏర్పాటు చేసిన తోట;  ఆరామం, ఉపవనం, ప్రమదావనం, వాటిక', '', '', '', '', '2026-05-02 13:47:18'),
(8126, 2, 'ఉద్యానవనం', 'n', 'తోట, రమణీయమైన చెట్లు, లతలు, గుల్మాల తోట;  ఉపవనం, నందనం', '', '', '', '', '2026-05-02 13:47:18'),
(8127, 2, 'ఉద్యుక్తుడు', 'n', 'యత్నించువాడు, సంసిద్ధుడు', '', '', '', '', '2026-05-02 13:47:18'),
(8128, 2, 'ఉద్యోగం', 'n', 'యత్నం, పని, కొలువు, పాటుపడటం', '', '', '', '', '2026-05-02 13:47:18'),
(8129, 2, 'ఉద్రిక్తము', 'n', 'ఉద్రేకించినది', '', '', '', '', '2026-05-02 13:47:18'),
(8130, 2, 'ఉద్రేకం', 'n', 'అతిశయం, విజృంభణం,  అదటు, క్రోధం, రోషం, శఠం', '', '', '', '', '2026-05-02 13:47:18'),
(8131, 2, 'ఉద్విగ్నం', 'n', 'కలతబారింది, భయం కలిగినది, మనసు కుదురు లేనిది, వ్యాకులమైనది', '', '', '', '', '2026-05-02 13:47:18'),
(8132, 2, 'ఉద్వేగం', 'n', 'భయం, విరహం వల్ల కలిగే  దుః ఖం, కలత;  ఉద్వేజనం, వ్యాకులచిత్తత', '', '', '', '', '2026-05-02 13:47:18'),
(8133, 2, 'ఉనికి', 'v', 'ఉండటం, స్థితి, స్థానం, నివాసం', '', '', '', '', '2026-05-02 13:47:18'),
(8134, 2, 'ఉన్నతం', 'n', 'గొప్పది;  ఉచ్చం, ఊర్థ్యం', '', '', '', '', '2026-05-02 13:47:18'),
(8135, 2, 'ఉన్నతి', 'n', 'ఎత్తు, ఉచ్చస్థితి, ఔన్నత్యం;  పెంపు, సమున్నతి', '', '', '', '', '2026-05-02 13:47:18'),
(8136, 2, 'ఉన్ని', 'v', 'గొర్రె బొచ్చు', '', '', '', '', '2026-05-02 13:47:18'),
(8137, 2, 'ఉన్మాదం', 'n', 'వెర్రి, పిచ్చి,  తిక్క, మతిభ్రంశం, రిమ్మ', '', '', '', '', '2026-05-02 13:47:18'),
(8138, 2, 'ఉపకథ', 'n', 'ఒక కథలో వచ్చే అప్రధానమైన చిన్నకథ', '', '', '', '', '2026-05-02 13:47:18'),
(8139, 2, 'ఉపకారం', 'n', 'మేలు, ఉపకృతి;  ఉపక్రియ, హితం', '', '', '', '', '2026-05-02 13:47:18'),
