(8547, 2, 'కుడితి', 'v', 'బియ్యం మొదలైనవి కడిగిన నీళ్ళు;  కలి, కాంచికం, కూటినీళ్ళు, తరవాణి, పుల్లనీళ్ళు', '', '', '', '', '2026-05-02 13:47:18'),
(8548, 2, 'కుడుపు', 'v', 'తినేట్లు చేయు; విఅనుభవం, భోజనం;  కబళం, కూడు, భుక్తి', '', '', '', '', '2026-05-02 13:47:18'),
(8549, 2, 'కుడ్యం', 'n', 'గోడ, పూత, లేపనం;  ఇడుపు, భిత్తి, సాలం', '', '', '', '', '2026-05-02 13:47:18'),
(8550, 2, 'కుతూహలం', 'n', 'కోరిక, ఆనందం;  అభిరుచి, ఆసత్తి, ఉత్కంఠ, ఉబలాటం, తహతహ', '', '', '', '', '2026-05-02 13:47:18'),
(8551, 2, 'కుత్తుక', 'v,n', 'కంఠం;  కంబుక,  కంబువు, గళకం, గళం, గొంతు, గొంతుక', '', '', '', '', '2026-05-02 13:47:18'),
(8552, 2, 'కుత్సితం', 'n', 'నికృష్టం;  కుటిలం, బేరజం కుత్సిత దిలుడు, ఈ గుణవంత', '', '', '', '', '2026-05-02 13:47:18'),
(8553, 2, 'కుత్సితుడు', 'n', 'చెడ్డబుద్ది ఉన్నవాడు;  కుటిలుడు, కువాయడు', '', '', '', '', '2026-05-02 13:47:18'),
(8554, 2, 'కుదప', 'v', 'నారుమొక్క', '', '', '', '', '2026-05-02 13:47:18'),
(8555, 2, 'కుదుపు', 'v', 'కదలించు, ఇటుఅటు ఊపు', '', '', '', '', '2026-05-02 13:47:18'),
(8556, 2, 'కుదురు', 'v', 'అనుకూలమవు; నింపాది, నిమ్మళం', '', '', '', '', '2026-05-02 13:47:18'),
(8557, 2, 'కుబుసం', 'v', 'పాము పొర, తలుపు కింద మీద;  కంచుకం, కూసం, పొర ఉంచే కూసం', '', '', '', '', '2026-05-02 13:47:18'),
(8558, 2, 'కుబేరుడు', 'n', 'ఉత్తర దిక్పాలకుడు, ధనదుడు, రావణుని అన్న;  ధనపతి, రొక్కపు దొర', '', '', '', '', '2026-05-02 13:47:18'),
(8559, 2, 'కుమ్మరి', 'v', 'వికుండలు చేసి జీవించే జాతి;  కుంభకారుడు, కుంభి, ఘటీకారుడు, నూకరుడు', '', '', '', '', '2026-05-02 13:47:18'),
(8560, 2, 'కురులు', 'n', 'వెంట్రుకలు', '', '', '', '', '2026-05-02 13:47:18'),
(8561, 2, 'కులజులు', 'n', 'మంచి పుట్టుక కలవారు', '', '', '', '', '2026-05-02 13:47:18'),
(8562, 2, 'కులభేదం', 'n', 'కులాల మధ్య తేడా', '', '', '', '', '2026-05-02 13:47:18'),
(8563, 2, 'కులుకు', 'v', 'పోయు, వేయు, వెదచల్లు,', '', '', '', '', '2026-05-02 13:47:18'),
(8564, 2, 'కుళ్ళు', 'n', 'చెడు', '', '', '', '', '2026-05-02 13:47:18'),
(8565, 2, 'కువలయం', 'n', 'భూమండలం, నల్లకలువ; ఉత్పలం, కల్లారం', '', '', '', '', '2026-05-02 13:47:18'),
(8566, 2, 'కూకలు', 'v', 'కూతలు', '', '', '', '', '2026-05-02 13:47:18'),
(8567, 2, 'కూడు', 'v', 'అన్నం;  ఓవనం, బువ్వ, భుక్తి, మెతుకు, సాపాటు', '', '', '', '', '2026-05-02 13:47:18'),
(8568, 2, 'కూత', 'v', 'కూయడం;  అరుపు, ఊళ, రుతం', '', '', '', '', '2026-05-02 13:47:18'),
(8569, 2, 'కూన', 'v', 'వికుర్ర;  చంటిపాప, పట్టి, పసికందు, పాప, బాలకుడు, బుడుత', '', '', '', '', '2026-05-02 13:47:18'),
(8570, 2, 'కూర', 'v', 'విశాకం', '', '', '', '', '2026-05-02 13:47:18'),
(8571, 2, 'కూరిమి', 'n', 'స్నేహం;  గారాబు, నెయ్యం, ప్రియం', '', '', '', '', '2026-05-02 13:47:18');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(8572, 2, 'కూలిపోవు', 'n', 'పడిపోవు', '', '', '', '', '2026-05-02 13:47:18'),
(8573, 2, 'కృతకృత్యుడు', 'n', 'నెరవేరిన పనిగల వాడు; కృతార్థుడు, విదథుడు', '', '', '', '', '2026-05-02 13:47:18'),
(8574, 2, 'కృతన్నుత', 'n', 'చేసిన మేలు మరచిపోవడం', '', '', '', '', '2026-05-02 13:47:18'),
(8575, 2, 'కృతారుడు', 'n', 'ధన్యుడు, తలచిన పనినెరవేర్చుకొనినవాడు;  కృతకృత్యుడు, ధన్యజీవి', '', '', '', '', '2026-05-02 13:47:18'),
(8576, 2, 'కృత్యం', 'n', 'పని, వ్యాపారం;వియ, చేత, వ్యాసంగం', '', '', '', '', '2026-05-02 13:47:18'),
(8577, 2, 'కృత్రిమ', 'n', 'సహజం కానిది, మనుష్యులు చేసింది;  కృతకం, నకిలీ', '', '', '', '', '2026-05-02 13:47:18'),
(8578, 2, 'కృప', 'n', 'దయ, కనికరం;  అనుగ్రహం, ఆదరణ, కటాక్షం, కారుణ్యం, జాలి', '', '', '', '', '2026-05-02 13:47:18'),
(8579, 2, 'కృపణులు', 'n', 'కుత్సితులు', '', '', '', '', '2026-05-02 13:47:18'),
(8580, 2, 'కృషి', 'n', 'సేద్యం, వ్యవసాయం;  కర్షణం, పొలంపని, సాగుబడి', '', '', '', '', '2026-05-02 13:47:18'),
(8581, 2, 'కృష్ణవేణి', 'n', 'కృష్ణవేణి అనే నది; కృష్ణానది; కృష్ణ, కృష్ణాతటిని, కృష్ణాతరంగిణి', '', '', '', '', '2026-05-02 13:47:18'),
(8582, 2, 'కెరటం', 'v', 'అల;  అక్కలి, అర్గళం, ఉత్కలిక, ఊర్మి, జలలత, తరగ', '', '', '', '', '2026-05-02 13:47:18'),
(8583, 2, 'కెరలిన', 'v', 'ఆగ్రహించిన, విజృంభించిన', '', '', '', '', '2026-05-02 13:47:18'),
(8584, 2, 'కేకిసలు', 'v', 'చప్పట్లు', '', '', '', '', '2026-05-02 13:47:18'),
(8585, 2, 'కేరళ్ళు', 'n', 'ప్రవాహాలు', '', '', '', '', '2026-05-02 13:47:18'),
(8586, 2, 'కేలు', 'v', 'విచేయి, తొండం;  కరం, చెట్ట, పాణి, హస్తకం', '', '', '', '', '2026-05-02 13:47:18'),
(8587, 2, 'కైచేయు', 'v', 'అలంకరించు', '', '', '', '', '2026-05-02 13:47:18'),
(8588, 2, 'కైవల్యం', 'n', 'ముక్తి, మోక్షం;  దివ్యపదం, పరమగతి, పరమపదం', '', '', '', '', '2026-05-02 13:47:18'),
(8589, 2, 'కైవసం', 'v', 'అధీనం, వశం;  స్వాధీనం, హవాలా, హస్తగతం', '', '', '', '', '2026-05-02 13:47:18'),
(8590, 2, 'కైవారం', 'n', 'స్తోత్రం;  అభినుతి, కొనియాడటం, ప్రశస్తి, శ్లాఘం', '', '', '', '', '2026-05-02 13:47:18'),
(8591, 2, 'కొంటెవాడు', 'v', 'చిలిపి పనులు చేసేవాడు', '', '', '', '', '2026-05-02 13:47:18'),
(8592, 2, 'కొండ', 'v', 'పర్వతం; అచలం, అద్రి, శైలం, శిఖరి', '', '', '', '', '2026-05-02 13:47:18'),
(8593, 2, 'కొండముచ్చులు', 'v', 'నల్లని మూతిఉన్న కోతులు', '', '', '', '', '2026-05-02 13:47:18'),
(8594, 2, 'కొండ్ర', 'v', 'వ్యవసాయదారునికి ఉండే భూమి', '', '', '', '', '2026-05-02 13:47:18'),
(8595, 2, 'కొటారు', 'v', 'ధాన్యరాసులుంచే చోటు,కోటారు, కొట్టరువు;  కొటారం, ఖలం, ఖల్వ', '', '', '', '', '2026-05-02 13:47:18'),
(8596, 2, 'కొట్టం', 'v', 'విపసువులను కట్టే చోటు; సంగోష్ఠమ్; గోగ్రంధి, గోష్ఠం, పెంటపట్టు', '', '', '', '', '2026-05-02 13:47:18'),
(8597, 2, 'కొడవలి', 'v', 'కోసే ఆయుధం, లవిత్రం, చిన్న పిడితో వంపు తిరిగి అంచునకు చిన్న రంపగరి ఉండే కత్తి;  ఖడ్గకం, దాత్రం, లవిత్రం, లిక్కి', '', '', '', '', '2026-05-02 13:47:18'),
(8598, 2, 'కొనియాడు', 'v', 'నుతించు, స్తుతించు;  అంకించు, అగ్గించు, అభినందించు, ప్రణుతించు, శ్లాఘించు', '', '', '', '', '2026-05-02 13:47:18'),
(8599, 2, 'కొనుగోలు', 'v', 'క్రయం', '', '', '', '', '2026-05-02 13:47:18'),
(8600, 2, 'కొప్పు', 'v', 'దోపిన వెండ్రుకల ముడి;  కబం, కబ్భరం, కేశపాణి, కేశబంధం, క్రొమ్ముడి, జుట్టుముడి, మౌళి, శిఖ', '', '', '', '', '2026-05-02 13:47:18'),
(8601, 2, 'కొమరుండు', 'v', 'వికొడుకు, కుమార స్వామి;  కుమారుడు, కుఱ్ఱవాడు, కొమరుడు, పిల్లవాడు', '', '', '', '', '2026-05-02 13:47:18'),
(8602, 2, 'కొమ్మ', 'v', 'స్త్రీ, శాఖ, విటపం, శిఖ, సురిగ', '', '', '', '', '2026-05-02 13:47:18'),
(8603, 2, 'కొయ్య', 'v', 'కర్ర, మాను, మూర్ఖుడు,  కట్టె, కాష్ఠం, కొయ్య, కోల, మొద్దు', '', '', '', '', '2026-05-02 13:47:18'),
(8604, 2, 'కొలది', 'v', 'పరిమితి, బలం, స్థితి, విధం', '', '', '', '', '2026-05-02 13:47:18'),
(8605, 2, 'కొలను', 'n', 'దేవతలను పూజిస్తూ పాడే పాట, కల్యాణం, జాతర, తిరునాళ్ళు', '', '', '', '', '2026-05-02 13:47:18'),
(8606, 2, 'కొలువు', 'v', 'ఆస్థానం, సేవ;  ఆస్థ, ఓలగం, దర్భారు, పేరోలగం', '', '', '', '', '2026-05-02 13:47:18'),
(8607, 2, 'కొల్లాయి', 'v', 'చిన్న అంగవస్త్రం', '', '', '', '', '2026-05-02 13:47:18'),
(8608, 2, 'కోక', 'v', 'వలువ, చీర;  ఉడుపు, చేల, చేలం', '', '', '', '', '2026-05-02 13:47:18'),
(8609, 2, 'కోట', 'v', 'విదుర్గపురం, పట్టణం చుట్టు ఉన్న ప్రహారి;  కిల్లా, ఖిల్లా, గడి, దుర్గం', '', '', '', '', '2026-05-02 13:47:18'),
(8610, 2, 'కోతలు', 'n', 'బడాయి మాటలు', '', '', '', '', '2026-05-02 13:47:18'),
(8611, 2, 'కోన', 'v', 'విఅడవి; సం కాననమ్;  కటకం, కనుమ, కొండపగలు', '', '', '', '', '2026-05-02 13:47:18'),
(8612, 2, 'కోనేరు', 'v', '(కోన + ఏరు) చుట్టూ కే నలుచదరపు గుంట, పుష్కరిణి;  తిరుకొలను, తిరుకోళము', '', '', '', '', '2026-05-02 13:47:18'),
(8613, 2, 'కోపం', '', 'సంకినుక, క్రోధం', '', '', '', '', '2026-05-02 13:47:18'),
(8614, 2, 'కోమలి', 'n', 'చక్కనైన స్త్రీ;  అంగన, అంచన, అబల, అబ్జముఖి', '', '', '', '', '2026-05-02 13:47:18'),
(8615, 2, 'కోలాటం', 'v', 'చేతులలో కోలలుంచుకొని ఆడెడి ఆట; రెండు చేతులలోను కర్రముక్కలు ఉంచుకొని వదం పాడుతూ గుండ్రంగా తిరుగుతూ లయానుకూలంగా అడుగులు వేస్తూ ఒకరి చేతి కర్రలను వేరొకరి చేతి కర్రలకు తగిలిస్తూ ఆడే సామూహిక ఆట, హల్లీనం', '', '', '', '', '2026-05-02 13:47:18'),
(8616, 2, 'కోలాహలం', 'n', 'కలకలం, ఒకానొక కొండ;  గోల, రంతు, రొద, సందడి', '', '', '', '', '2026-05-02 13:47:18'),
(8617, 2, 'కోవ', 'v', 'క్రమం;  ఆనువంశికం, తరతరం', '', '', '', '', '2026-05-02 13:47:18'),
(8618, 2, 'కోవెల', 'v', 'గుడి, దేవాలయం, దేవళం, పికం, కోవిల', '', '', '', '', '2026-05-02 13:47:18'),
(8619, 2, 'కోశం', 'n', 'పుస్తకం, నిఘంటువు, బొక్కసం, కత్తిఒర;  అభిదానం, పదనిధి, శబ్దకోశం, శబ్ద సంగ్రహం, శబ్దసాగరం', '', '', '', '', '2026-05-02 13:47:18'),
