(9488, 2, 'తెకతేర', 'v', 'విణ సొంతంగా 1 కడు సులభంగా, మిక్కిలి, అనాయాసంగా; 2 నిష్కారణంగా, వ్యర్థంగా; 3 బొత్తిగా సంబంధంలేనిది;', '', '', '', '', '2026-05-02 13:47:18'),
(9489, 2, 'తెగ', '', 'దేవి 1 సజాతీయ సమూహం,   గుంపు, పక్షం, పక్క, అల్లెత్రాడు, జాతి, రీతి, పొడవు, ఖండితంగా, నిశ్శేషంగా (విధం)', '', '', '', '', '2026-05-02 13:47:18'),
(9490, 2, 'తెగడు', 'v', 'నిందించు, తిరస్కరించు,   దూషించు, ఆక్షేపించు, పరిహసించు, ఉపేక్షించు, నిర్ణయించు, ఏర్పాటుచేయు,', '', '', '', '', '2026-05-02 13:47:18'),
