(9493, 2, 'తెగు', 'v', 'సాహసించు,  ఖండితమగు, భిన్నమగు, చచ్చు, నశించు, ముగియు, ఆగు, విరమించు, మారు, సాహసించు, పరిష్కరింపబడు, సాధ్యమగు, శేషం లేకుండా భాగింపబడు', '', '', '', '', '2026-05-02 13:47:18'),
(9494, 2, 'తెచ్చు', 'v', '1 తీసుకొనివచ్చు, రప్పించు, 2 సంపాదించు', '', '', '', '', '2026-05-02 13:47:18'),
(9495, 2, 'తెట్టె(లు)గట్టు', 'v', 'రాశిపడు, పోగుపడు', '', '', '', '', '2026-05-02 13:47:18'),
(9496, 2, 'తెడ్డు', 'n', '1 కొయ్య గరిటె; పడవ నడపడానికి ఉపయోగించే సాధన విశేషం , బ్రెడ్డు  గరిటె, కంచి, ఖజ, ఖజాక, ఖజిక, చట్టువం, చాటువు, తండువు, తర్థువు, దర్వి', '', '', '', '', '2026-05-02 13:47:18');
