(9505, 2, 'తెమలు', 'v', 'కదలు; వి ప్రవాహం ,   తొట్రుపడు, చలించు, జంకు, అసత్యమగు, తిరుగు, మరలు, విరియు, పట్టుదప్పు, జారు, పోవు, నశించు, వెళ్ళు, బయలువేడలు, ముగియు, తెరపి చేసుకొను', '', '', '', '', '2026-05-02 13:47:18'),
(9506, 2, 'తెమ్మెర', 'n', 'చల్లగాలి; మంద మారుతం; వాయువు, గాలి', '', '', '', '', '2026-05-02 13:47:18'),
(9507, 2, 'తెర', 'n', 'వెనక ఉన్నవారు కనబడకుండా వేలాడగట్టే మరుగు చీర, తిరస్కరిణి, యవనిక,  అల, తరంగం, పరంపర, వరస;  అడ్డు వల, పరదా, అపటి, కాండపటం, గండవడం, జవనిక', '', '', '', '', '2026-05-02 13:47:18'),
(9508, 2, 'తెరగు', 'n', 'విధం, ప్రకారం, పద్ధతి, తేరవు  తెఱంగునన్ వలచినట్టు చేయుడు', '', '', '', '', '2026-05-02 13:47:18'),
(9509, 2, 'తెరపి', 'n', 'అవకాశం, ఎడం, సందు', '', '', '', '', '2026-05-02 13:47:18'),
(9510, 2, 'తెరలు', 'v', 'నీళ్ళు మొ  సలసల కాగిపొంగు, తెరు,  తొలగు, బయలుదేరు, కలగు, చచ్చు, సలసల మరుగు, అభిప్రాయభేదం', '', '', '', '', '2026-05-02 13:47:18'),
(9511, 2, 'తెరవ', 'n', 'స్త్రీ, భార్య (తె జు+వాయి) , రహస్యం దాచనేరనిది', '', '', '', '', '2026-05-02 13:47:18'),
