(9518, 2, 'తెలుపు', 'v', 'ఎరిగించు, చెప్పు,విశదీకరించు, స్పష్టం చేయు, సూచించు, ప్రకటించు, చాటించు, బోధించు, తేర్చు, ఊరడించు, మేలుకొలుపు', '', '', '', '', '2026-05-02 13:47:18'),
(9519, 2, 'తెల్ల', 'n', 'ధవళీమ, తెల్లకాంతి, ధావళ్యం, తెలుపు, తెల్ల', '', '', '', '', '2026-05-02 13:47:18'),
(9520, 2, 'తెల్లబోవు', 'v', 'వెలవెలబోవు, నిర్విజ్ఞుడగు', '', '', '', '', '2026-05-02 13:47:18'),
(9521, 2, 'తెల్లవారు', 'v', 'ఉదయమగు, వేగు తెలివి మందలించు; వీవర్లమగు, పాలిపోవు; నిస్సారమగు, చెడిపోవు', '', '', '', '', '2026-05-02 13:47:18'),
