(10336, 2, 'నాశం', 'n', 'చేటు, మరణం,   చేటు, మరణం, అదర్శనం, పలాయనం, గోచరంకాకపోవడం', '', '', '', '', '2026-05-02 13:56:30'),
(10337, 2, 'నాశనం', 'n', 'నశింపజేయడం, కనబడకుండా చేయడం', '', '', '', '', '2026-05-02 13:56:30'),
(10338, 2, 'నాస', 'n', 'ముక్కు రూ నాసిక,   పుష్కరం, (ఏనుగు తొండం  అగ్రం), ద్వారం పై ఉండే అడ్డకమ్మి, ధ్వని, వాసకం', '', '', '', '', '2026-05-02 13:56:30'),
(10339, 2, 'నాస్తి', '', 'సంఅవ్యలేదు', '', '', '', '', '2026-05-02 13:56:30'),
(10340, 2, 'నాస్తికుడు', '', 'దేవుడిని నమ్మనివాడు (వేద ప్రామాణ్యాన్ని, అంగీకరించనివాడు) , 1 ఈ లోకం తప్ప పరలోకం లేదనేవాడు 2 భగవంతుడు లేడనే వాడు 3 వేదాలలో నమ్మకం లేనివాడు', '', '', '', '', '2026-05-02 13:56:30'),
(10341, 2, 'నింగి', 'n', 'ఆకాశం, అంతరిక్షం, స్వర్గం', '', '', '', '', '2026-05-02 13:56:30'),
(10342, 2, 'నిండు', 'v', 'జలాదులచే పూర్లమవడం  నెరవేరు, పూర్తవు, సమాప్తమవు', '', '', '', '', '2026-05-02 13:56:30'),
(10343, 2, 'నిండుకున్నాయి', 'v', 'అయిపోయి నాయి', '', '', '', '', '2026-05-02 13:56:30');
