(10355, 2, 'నిక్షిప్తం', 'n', '(భూమిలో) ఉన్నది పాతబడినది, పూడ్చబడినది, విడువబడినది, ఇల్లడ పెట్ట బడినది, ఉంపబడినది, పూడ్చబడినది', '', '', '', '', '2026-05-02 13:56:30'),
(10356, 2, 'నిఖిలం', 'n', 'సర్వం, అంతా', '', '', '', '', '2026-05-02 13:56:30'),
(10357, 2, 'నిగడు', 'v', '1 నిక్కి, పైకిలేచు,   నిక్క, వ్యాపించు, బయల్దేరు, మార్కొను, వెలువడు, మీదికి వచ్చు, విజృంభించు, పుట్టు, యత్నించు, చక్కబడు, ఒప్పు, చచ్చు, అతిశయించు, ప్రవహించు, స్వస్థతనొందు, పరుగెత్తు, చాగు', '', '', '', '', '2026-05-02 13:56:30'),
(10358, 2, 'నిగనిగలాడు', '', 'డివినిగనిగ అని ప్రకాశించడం', '', '', '', '', '2026-05-02 13:56:30'),
(10359, 2, 'నిగళం', 'n', 'సంకెల రూ నిగడం,   సంకెల, ఏనుగు కాలి సంకెల, మింగడం', '', '', '', '', '2026-05-02 13:56:30'),
(10360, 2, 'నిగూఢ గుప్తం', 'n', 'రహస్యంగా దాచుకొన్నది', '', '', '', '', '2026-05-02 13:56:30'),
(10361, 2, 'నిగ్గదీయు', 'v', 'నిలబెట్టు, నిలదీసి అడుగు', '', '', '', '', '2026-05-02 13:56:30'),
(10362, 2, 'నిగ్గు', 'n', 'కాంతి ,   కాంతి, జిడు, కిరణం, పరిమళాతిశయం, సారం, వర్ణలేశం, పస', '', '', '', '', '2026-05-02 13:56:30'),
(10363, 2, 'నిగ్రహం', 'n', 'అడ్డగించు, అణచడం,   బెదరుమాట, శిక్ష, నింద, వైద్యం, పిడి, మారణక్రియ, మేర, చెట్లు, అడ్డగింపు, హస్తక్రియలు', '', '', '', '', '2026-05-02 13:56:30'),
