(10376, 2, 'నిత్య విద్యార్థి', 'n', 'ఎల్లప్పుడూ చదువుకునేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(10377, 2, 'నిత్య సంతుష్టుడు', 'n', 'ఎల్లప్పుడూ సంతోషంగా ఉండేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(10378, 2, 'నిత్య స్మరణీయురాలు', 'n', 'ఎల్లప్పుడూ స్మరింపదగినది', '', '', '', '', '2026-05-02 13:56:30'),
(10379, 2, 'నిత్యకర్మం', '', 'నంవి1 ఎప్పుడూ చేయవలసిన పని 2 చేయకుంటే ప్రత్యవాయం కలిగే శాస్త్ర విహిత కర్మం చనిపోయినవారికి పదిరోజుల వరకు ప్రతిదినం చేసే శ్రాద్ధకర్మ', '', '', '', '', '2026-05-02 13:56:30'),
(10380, 2, 'నిత్యకల్యాణం', 'n', 'ఎడతెగని శుభం, ఎల్లప్పుడూ కలిగే శుభం', '', '', '', '', '2026-05-02 13:56:30'),
(10381, 2, 'నిత్యాగ్నిహోత్రాలు', 'n', 'ఎల్లప్పుడూ ఉండే అగ్నులు', '', '', '', '', '2026-05-02 13:56:30'),
(10382, 2, 'నిత్యాగ్నిహోత్రులు', 'n', 'ప్రతి దినమూ హోమాదులు చేస్తూ అగ్ని చల్లారకుండా రక్షించు కొనేవారు', '', '', '', '', '2026-05-02 13:56:30'),
(10383, 2, 'నిత్యావసరాలు', 'n', 'ప్రతిదినం అవసరమైనవి', '', '', '', '', '2026-05-02 13:56:30'),
(10384, 2, 'నిదర్శనం', 'n', 'ఉదాహరణం, దృష్టాంతం,   చూపేది, తెలిపేది, బోధించేది, ప్రమాణం', '', '', '', '', '2026-05-02 13:56:30'),
(10385, 2, 'నిదానం', '', 'నంవి మూలకారణం, తొందరపడకుండా విచారించడం నెమ్మదితనం \',   రోగనిర్ణయం, శుద్ధి, నిలకడ, పలుపు, రోగ హేతువు', '', '', '', '', '2026-05-02 13:56:30'),
(10386, 2, 'నిద్ర', 'n', 'నిదుర, కూర్కు  శయనం, స్వానం, స్వప్నం, సంవేశం, నిద్దుర, కునుకు, కూర్కు, కనుమోడ్పునిద్రాహారాలు', '', '', '', '', '2026-05-02 13:56:30'),
(10387, 2, 'నిద్రాణం', 'n', 'నిదురించేది, ముకుళించేది', '', '', '', '', '2026-05-02 13:56:30'),
(10388, 2, 'నిధులు', 'n', 'ధనం, డబ్బులు', '', '', '', '', '2026-05-02 13:56:30'),
(10389, 2, 'నినాదం', 'n', 'ధ్వని, మోత రూ నినదం', '', '', '', '', '2026-05-02 13:56:30'),
(10390, 2, 'నిపుణుడు', 'n', 'ప్రవీణుడు, నేర్పరి నిప్పు', '', '', '', '', '2026-05-02 13:56:30'),
(10391, 2, 'నిబంధన', '', 'సంవీణ ప్రతిబంధన, ఏర్పాటు,   కారణం, బంధనం, కట్టుపాటు, ఊత, స్థానం, వీణా తంత్రులు కట్టే స్థానం కూర్పబడినది', '', '', '', '', '2026-05-02 13:56:30'),
(10392, 2, 'నిబద్దత', 'n', 'కట్టుబడడం', '', '', '', '', '2026-05-02 13:56:30'),
(10393, 2, 'నిబిడ', 'n', 'దిట్టమైన, సాంద్రమైన', '', '', '', '', '2026-05-02 13:56:30'),
(10394, 2, 'నిబిడీకృతం', 'n', 'నిబిడంగా చేయబడినది, దట్టంగా చేయబడినది **** ప్రజాసేవ చేయాలనే దీక్ష వీరందరి లోనూ నిబిడీకృతమై ఉండటం వల్లనే వారి సొంత పనులు వదులుకొని తోటి దీన మానవ సేవకు పూనుకున్నారు', '', '', '', '', '2026-05-02 13:56:30'),
(10395, 2, 'నిబ్బరం', 'n', 'దిట్టతనం, దృఢం రూ నిబ్బరికం,   నిశ్చయం, నిలుకడ, పరవశత, సూటి, గుర్రపు పరుగు, నిదానం', '', '', '', '', '2026-05-02 13:56:30'),
(10396, 2, 'నిమగ్నం', 'n', 'మునిగిన, లీనం', '', '', '', '', '2026-05-02 13:56:30'),
(10397, 2, 'నిమిత్తం', 'n', 'కారణం, హేతువు,   కారణం, గురి, నామమాత్ర కారణం, శకునం, గుర్తు ముసలి కొక్కెర వచ్చి నయనంబులు నిమీలించి యాహారంబు మాని దుష్కరంబయిన తపంబు చేయుదానివలె పిలువంబడి యుండెను', '', '', '', '', '2026-05-02 13:56:30'),
(10398, 2, 'నిమురు', 'v', 'వాత్సల్యంతో చేతితో రాయు, తాకు రూ నివురు', '', '', '', '', '2026-05-02 13:56:30'),
