(11205, 2, 'పీట', 'n', 'కర్ర మొ  వాటిలో కూర్చోవడానికి ఉపయోగపడేటట్లు చేయబడిన పలక', '', '', '', '', '2026-05-02 13:56:30'),
(11206, 2, 'పీఠం', 'n', 'ఆసనం, పీట', '', '', '', '', '2026-05-02 13:56:30'),
(11207, 2, 'పీఠిక', 'n', '1 గ్రంథం మొదట రాసేదాని పుట్టుపూర్వోత్తరాలు 2 ఆసనంవిషయ సూచిక, అవతారిక, అనుక్రమణిక, భూమిక, విన్నపం, తొలిపలుకు', '', '', '', '', '2026-05-02 13:56:30'),
(11208, 2, 'పీడ', 'n', 'బాధ,  కీడు, కృప, సిగదండ, సరళ వృక్షం, పాడుచేయడం, అతిక్రమించడం, గంప', '', '', '', '', '2026-05-02 13:56:30'),
