(11211, 2, 'పీడితులు', 'n', 'బాధితులు, పీడింపబడే వారు', '', '', '', '', '2026-05-02 13:56:30'),
(11212, 2, 'పీత', 'n', '1 ఎండ్రకాయ, కర్కటం, 2 n  పసుపు 3 తాగబడిన', '', '', '', '', '2026-05-02 13:56:30'),
