INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(11226, 2, 'పుండరీకం', 'n', 'తెల్లతామర, పులి,  ప్రకాశించేది, అష్టదిగ్గజాలలో ఒకటి,మంగళ ప్రదమైనది, శుభకర్మమును చేసేది,  తీర్థ విశేషం, పెద్ద పులి, తెల్లగొడుగు, ఆగ్నేయ దిక్కులోని ఏనుగు, తియ్యమామిడి చెట్టు, పట్టుపురుగు, ఒక యజ్ఞం, చంద్రుని విల్లు, వరుణుని శంఖం, కప్ప, తెల్లచెరకు', '', '', '', '', '2026-05-02 13:56:30'),
(11227, 2, 'పుండు', 'n', 'వ్రణం, కురుపు, పుంభావం', '', '', '', '', '2026-05-02 13:56:30'),
(11228, 2, 'పుక్కిటి పురాణం', 'n', 'నిరాధారమైన కథ, అసత్యవార్త,  పుక్కిలి నుండి బయలువెడలిన వ్యర్థ వాక్య ప్రసంగం  అక్కర మాలిన కల్పితకథ', '', '', '', '', '2026-05-02 13:56:30'),
(11229, 2, 'పుక్కిలింత', 'n', 'పుక్కిలించడం, గండూషం', '', '', '', '', '2026-05-02 13:56:30'),
(11230, 2, 'పుచ్చం', 'n', 'తోక, లాంగూలం;', '', '', '', '', '2026-05-02 13:56:30'),
