(11232, 2, 'పుచ్చుకొను', 'v', 'తీసికొను, తాగు,   స్వీకరించు, ఆకర్షించు, ఆరగించు, అవహరించు, వశం చేసుకొను, కొను', '', '', '', '', '2026-05-02 13:56:30'),
