(11248, 2, 'పుత్రిక', 'n', 'కూతురు,  దుర్గ, లక్కదూరి పుత్తళిక', '', '', '', '', '2026-05-02 13:56:30'),
(11249, 2, 'పుత్రుడు', 'n', 'కొడుకు,  పున్నామ నరకం నుంచి రక్షించేవాడు విశే', '', '', '', '', '2026-05-02 13:56:30'),
