(11640, 2, 'ప్రత్యుపకారం', 'n', 'ఉపకారానికి  బదులు ఉపకారం', '', '', '', '', '2026-05-02 13:56:30'),
(11641, 2, 'ప్రత్యూష', 'n', 'ప్రాతఃకాలం, వేకువ, ప్రత్యూషం, సూర్యకిరణాలచే దహింప మొదలు పెట్టేది', '', '', '', '', '2026-05-02 13:56:30'),
(11642, 2, 'ప్రత్యేక తరహా', 'n', 'వేరే విధం', '', '', '', '', '2026-05-02 13:56:30'),
(11643, 2, 'ప్రత్యేకత', '', 'నంవివిశేషగుణం, విశేషధర్మం', '', '', '', '', '2026-05-02 13:56:30'),
(11644, 2, 'ప్రత్యేకాధికారి', 'n', 'వేరే అధికారి (స్పెషలాఫీసర్)', '', '', '', '', '2026-05-02 13:56:30'),
