(11646, 2, 'ప్రథమ గణ్యత', 'n', 'మొదట ఎంచడం', '', '', '', '', '2026-05-02 13:56:30'),
(11647, 2, 'ప్రథమ చికిత్స', 'n', 'మొదటి ప్రతిక్రియ, మొదటగా చేయదగిన చికిత్స', '', '', '', '', '2026-05-02 13:56:30'),
(11648, 2, 'ప్రథమశ్రేణి', 'n', 'మొదటి వరుస', '', '', '', '', '2026-05-02 13:56:30'),
(11649, 2, 'ప్రథమార్ధం', 'n', 'మొదటి సగం', '', '', '', '', '2026-05-02 13:56:30'),
(11650, 2, 'ప్రథముడు', 'n', 'మొదటివాడు', '', '', '', '', '2026-05-02 13:56:30'),
(11651, 2, 'ప్రదక్షిణం', 'n', '1 దేవతాదులను ఉద్దేశించి కుడికి తిరిగి రావడం, దేవతాదుల నుద్దేశించి కుడివైపుగా ముమ్మారు తిరగడం, 2 కుడి', '', '', '', '', '2026-05-02 13:56:30'),
(11652, 2, 'ప్రదర్శనం', 'n', 'విశదపరచి చూపడం', '', '', '', '', '2026-05-02 13:56:30'),
(11653, 2, 'ప్రదర్శించు', 'v', 'చూపు, విశదపరచు', '', '', '', '', '2026-05-02 13:56:30'),
(11654, 2, 'ప్రదానం', 'n', '1 ఇవ్వడం, 2 ప్రకృష్ట దానం, గొప్ప త్యాగం', '', '', '', '', '2026-05-02 13:56:30'),
(11655, 2, 'ప్రదీప్తాం', '', 'నంవిమిక్కిలి ప్రకాశమానం', '', '', '', '', '2026-05-02 13:56:30'),
(11656, 2, 'ప్రదేశం', 'n', 'చోటు, దేశం,  చూపడం, గోడ', '', '', '', '', '2026-05-02 13:56:30'),
(11657, 2, 'ప్రదోషం', 'n', 'దోషం, మునిమాపు , కార్యారంభానికి దోషయుక్తమైన', '', '', '', '', '2026-05-02 13:56:30'),
(11658, 2, 'ప్రధానం', 'n', 'ప్రశస్తం, ముఖ్యం,   ముఖ్యం, సత్వరజస్తమో గుణాత్మిక అయిన ప్రకృతి, పరమాత్మ, బుద్ధి, కార్యసహాయుడు', '', '', '', '', '2026-05-02 13:56:30'),
(11659, 2, 'ప్రధానవేదిక', 'n', 'ముఖ్యమైన వేదిక', '', '', '', '', '2026-05-02 13:56:30'),
(11660, 2, 'ప్రధానాంశం', 'n', 'ముఖ్యమైన విషయం', '', '', '', '', '2026-05-02 13:56:30'),
(11661, 2, 'ప్రధానోపాధ్యాయుడు', '', 'నంవి హెడ్ మాస్టర్, పెద్దసారు వేళ', '', '', '', '', '2026-05-02 13:56:30'),
(11662, 2, 'ప్రపంచం', 'n', 'సంసారం, లోకం, విస్తారం, వ్యాఖ్యానం,వి,ధ్యం, ప్రతారణం, వ్యత్యాసం, రచన, భూ లోకం', '', '', '', '', '2026-05-02 13:56:30'),
(11663, 2, 'ప్రపంచ విజేతలు', 'n', 'ప్రపంచాన్ని జయించినవారు', '', '', '', '', '2026-05-02 13:56:30'),
(11664, 2, 'ప్రపంచరీతి', 'n', 'లోక పద్దతి', '', '', '', '', '2026-05-02 13:56:30'),
(11665, 2, 'ప్రప్రథమ', 'n', 'మొట్టమొదటి', '', '', '', '', '2026-05-02 13:56:30'),
(11666, 2, 'ప్రఫుల్లం', 'n', 'వికసించినది, ఉల్లసిల్లు నది,   నవ్వేది, ప్రకాశించేది', '', '', '', '', '2026-05-02 13:56:30'),
(11667, 2, 'ప్రబంధం', 'n', 'అష్టాదశ వర్ణనాది లక్షణాలు కలిగిన గ్రంథం, ప్రకృష్టమైన బంధం కలది', '', '', '', '', '2026-05-02 13:56:30'),
(11668, 2, 'ప్రబంధ పద్దతి', 'n', 'కావ్యపద్ధతి', '', '', '', '', '2026-05-02 13:56:30'),
(11669, 2, 'ప్రబల', 'n', 'చాలా బలమైన', '', '', '', '', '2026-05-02 13:56:30'),
(11670, 2, 'ప్రబల విశ్వాసం', 'n', 'గట్టి నమ్మకం', '', '', '', '', '2026-05-02 13:56:30'),
(11671, 2, 'ప్రబలు', 'v', 'వర్ధిల్లు, అతిశయించు, ఉండు', '', '', '', '', '2026-05-02 13:56:30'),
(11672, 2, 'ప్రబోధం', 'n', 'సందేశం, చక్కగా బోధించడం,  జాగరణం, జాగ్రత్త, జ్ఞానం, వికాసం, వివరణం', '', '', '', '', '2026-05-02 13:56:30'),
(11673, 2, 'ప్రబోధించు', 'v', 'చక్కగా తెలుపు, జ్ఞానోప దేశం చేయు, ప్రేరించు', '', '', '', '', '2026-05-02 13:56:30'),
(11674, 2, 'ప్రభంజనుడు', 'n', 'వాయువు ,వృక్ష శాఖాదులను విరుగ గొట్టేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(11675, 2, 'ప్రభ', 'n', 'దీప్తి, కాంతి', '', '', '', '', '2026-05-02 13:56:30'),
(11676, 2, 'ప్రభవ', 'n', 'ఒకానొక సంవత్సరం', '', '', '', '', '2026-05-02 13:56:30'),
(11677, 2, 'ప్రభవించు', 'v', 'జనించు, పుట్టు ప్రభాకరుడు', '', '', '', '', '2026-05-02 13:56:30'),
(11678, 2, 'ప్రభాతం', 'n', 'వేకువ, తెల్లవారడానికి ముందు నాలుగు గడియల కాలం, ప్రకాశింప మొదలు పెట్టేది', '', '', '', '', '2026-05-02 13:56:30'),
(11679, 2, 'ప్రభాత పవనం', 'n', 'వేకువగా,', '', '', '', '', '2026-05-02 13:56:30'),
(11680, 2, 'ప్రభావం', 'n', 'శక్తి, మహాత్మ్యం,   కోశదండంవల్ల కలిగే తేజస్సు, సామర్థ్యం, విక్రమం, శాంతి, ఉద్భవం', '', '', '', '', '2026-05-02 13:56:30'),
(11681, 2, 'ప్రభుత్వం', 'n', 'సర్కారు, అధికారం', '', '', '', '', '2026-05-02 13:56:30'),
(11682, 2, 'ప్రభుత్వోద్యోగి', 'n', 'సర్కారు నౌకరు (గవర్నమెంటు ఎంప్లాయి)', '', '', '', '', '2026-05-02 13:56:30'),
(11683, 2, 'ప్రభువు', 'n', '1 స్వామి, ఏలిక, 2 సమర్థుడు', '', '', '', '', '2026-05-02 13:56:30'),
(11684, 2, 'ప్రభూత', 'n', 'పుట్టిన, కలిగిన', '', '', '', '', '2026-05-02 13:56:30');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(11685, 2, 'ప్రభృతులు', 'n', 'మొదలైనవారు,', '', '', '', '', '2026-05-02 13:56:30'),
(11686, 2, 'ప్రమత్తులు', 'n', 'వెర్రివారు,1 మిక్కిలి మత్తుగొన్నవారు, 2 ప్రమాదాన్ని పొందినవారు; ,  ఉన్మత్తులు, మిక్కిలి మత్తు గొన్నవారు, ఏమరుపాటుగలవారు, ఉల్లంఘించినవారు, కాముకులు, ప్రమాద పడినవారు', '', '', '', '', '2026-05-02 13:56:30'),
(11687, 2, 'ప్రమాణం', 'n', 'కొలత, సైజు ,   హద్దు, నిరూపణం, సత్యవాది, యధార్థజ్ఞానం, ఐక్యం, తర్కశాస్త్రం, హేతువు, హ్రస్వాక్షరం మాత్ర, ప్రత్యక్షాదీ జ్ఞాన కారణం', '', '', '', '', '2026-05-02 13:56:30'),
(11688, 2, 'ప్రమాణస్వీకారం', 'n', 'పదవీబాధ్యతలు స్వీకరించేటప్పుడు చేసే ప్రమాణం', '', '', '', '', '2026-05-02 13:56:30'),
(11689, 2, 'ప్రమాదం', 'n', 'అపాయం, ఏమరపాటు, మిక్కిలి మతు', '', '', '', '', '2026-05-02 13:56:30'),
(11690, 2, 'ప్రమిద', 'n', 'దీపపాత్రం', '', '', '', '', '2026-05-02 13:56:30'),
(11691, 2, 'ప్రముఖుడు', 'n', 'ప్రధానుడు, శ్రేష్ఠుడు, పూజ్యుడు,   అభిముఖుడు, ప్రథముడు, మాన్యుడు, సమూహం, పున్నాగం', '', '', '', '', '2026-05-02 13:56:30'),
(11692, 2, 'ప్రమేయం', '', 'ఎంవిణయధార్థంగా తెలుసుకో దగింది, పాత్ర, జ్ఞానం', '', '', '', '', '2026-05-02 13:56:30'),
(11693, 2, 'ప్రమోదం', 'n', 'హర్షం, ఉబ్బు,  ఆనందం', '', '', '', '', '2026-05-02 13:56:30'),
(11694, 2, 'ప్రమోషన్', 'n', 'ఉన్నత స్థితి కలుగ జేయడం', '', '', '', '', '2026-05-02 13:56:30'),
(11695, 2, 'ప్రమోషించు', 'v', '1 మోసపుచ్చు, మోసగించు, 2 దొంగిలించు', '', '', '', '', '2026-05-02 13:56:30'),
(11696, 2, 'ప్రయత్నం', 'n', 'విడువని పూనిక, మిక్కిలి యత్నం', '', '', '', '', '2026-05-02 13:56:30'),
(11697, 2, 'ప్రయాణం', 'n', 'పయనం, ప్రస్థానం,   దాడి, ఏనుగుల నేత్రపూర్వ ప్రదేశం', '', '', '', '', '2026-05-02 13:56:30'),
(11698, 2, 'ప్రయాణీకులు', 'n', 'ప్రయాణం చేసేవారు', '', '', '', '', '2026-05-02 13:56:30'),
(11699, 2, 'ప్రయాస', 'n', 'ప్రయత్నం , క్లేశం, ప్రయాసం,  ప్రయత్నం, పరిశ్రమం, అవిద్యాది పంచకం (అవిద్య, అస్మిత, రాగం, ద్వేషం, మరణ భయ', '', '', '', '', '2026-05-02 13:56:30'),
(11700, 2, 'ప్రయోగం', 'n', 'వినియోగం, నిదర్శనం,  వ్యవహారం, ప్రదర్శనం, ఆచరణం, సంకలనం, అర్పణం, వడ్డికిచ్చుట, గుర్రం ఒక', '', '', '', '', '2026-05-02 13:56:30'),
(11701, 2, 'ప్రయోజకత్వం', '', 'నంవికార్యం  నెరవేర్చడం, లాభం', '', '', '', '', '2026-05-02 13:56:30'),
(11702, 2, 'ప్రయోజనం', 'n', 'లాభం, కార్యం', '', '', '', '', '2026-05-02 13:56:30'),
(11703, 2, 'ప్రయోజనాత్మకంగా', 'n', '(ఆచరణా త్మకంగా) ఫలవంతంగా,', '', '', '', '', '2026-05-02 13:56:30'),
(11704, 2, 'ప్రలాపం', 'n', 'అర్థంలేని మాట,   సంభాషణం, పలవరం ఏడ్పు', '', '', '', '', '2026-05-02 13:56:30'),
(11705, 2, 'ప్రల్లదం', 'n', 'పరుషం, కఠినం,   పారుష్యం, దుర్భాషణం, దుష్కార్యం, దౌష్ట్యం, వ్యర్థ భాషణం', '', '', '', '', '2026-05-02 13:56:30'),
(11706, 2, 'ప్రళయం', 'n', ',జగత్తు దీనిలో పూర్తిగా లయమవుతుంది', '', '', '', '', '2026-05-02 13:56:30'),
(11707, 2, 'ప్రళయ (కాలరుద్రుడు)', 'n', 'కల్పాంతం (లో శివుడు),', '', '', '', '', '2026-05-02 13:56:30'),
(11708, 2, 'ప్రవచనం', 'n', 'అర్ధాను సంధానంతో చెప్పడం,  చక్కగా మాట్లాడడం, వేదాది శాస్త్రం, మాట, బౌద్ధుల – ముఖ్య సిద్దాంతం', '', '', '', '', '2026-05-02 13:56:30'),
(11709, 2, 'ప్రవర్తన', 'n', '1 ప్రవర్తిల్లడం, నడవడి, 2 నడపడం రూప్రవర్తనం', '', '', '', '', '2026-05-02 13:56:30'),
