(12072, 2, 'బిళ్ళ', 'n', 'బింబం, గుండ్రని వస్తువు, (సూర్యచంద్రుల) బింబం, ఖండం, గుండ్రపుదిండు, గుండ్రని వస్తువు, గుండ్రని పలక, కర్ణభూషా విశేషం, గుండ్రని నెత్తురుగడ్డ, బంగారు బిళ్ళ, కపిల రాట్నం', '', '', '', '', '2026-05-02 13:56:30'),
(12073, 2, 'బిస్కట్లు', 'n', 'రొట్టెబిళ్ళలు, పల్చటి సన్నని కేక్ వంటి పదార్థం', '', '', '', '', '2026-05-02 13:56:30'),
(12074, 2, 'బీగం', '', 'దేవి తలుపులకు వేసే తాళం,  తాళం, తాళం చెవి బీచ్', '', '', '', '', '2026-05-02 13:56:30'),
(12075, 2, 'బీజం', 'n', 'విత్తు,విత్తనం, గర్బా దానం, కారణం, అంకురం, విత్తడం', '', '', '', '', '2026-05-02 13:56:30'),
(12076, 2, 'బీజావాపనం', 'n', 'విత్తనాలు విత్తడం, బీజవాపం', '', '', '', '', '2026-05-02 13:56:30'),
(12077, 2, 'బీటలువారు', 'v', 'బద్దలవు, పగులు', '', '', '', '', '2026-05-02 13:56:30'),
(12078, 2, 'బీదరికం', 'n', 'పేదతనం, దారిద్ర్యం, దైన్యం', '', '', '', '', '2026-05-02 13:56:30'),
(12079, 2, 'బీదసాదలు', 'n', 'నిరు పేదలు, సామాన్యులు', '', '', '', '', '2026-05-02 13:56:30'),
(12080, 2, 'బీభత్సం', 'n', 'రోత,  పాపి, అసహ్యించుకొనేది, ఒక రసం', '', '', '', '', '2026-05-02 13:56:30'),
(12081, 2, 'బీభత్సుడు', 'n', 'అర్జునుడు ,యుద్ధ రంగాన్ని మృతకళేబరాలచే రోత పుట్టించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12082, 2, 'బీర', 'n', 'కాయకూరలలో ఒక తీగ; కోశాతికి; కర్కశచ్చద, వుంటాలి, జాంగలం, జాలిని, ధామార్గవ, పీతక, పీతపుష్ప', '', '', '', '', '2026-05-02 13:56:30'),
(12083, 2, 'బీరువా', 'v', 'దేవిఅంతస్తులుగా అడు పుల్లలమర్చిన బిగపు పెట్టె', '', '', '', '', '2026-05-02 13:56:30'),
(12084, 2, 'బీళ్ళు', 'n', 'దున్నని ఎండిన నేలలు, దున్నని భూములు', '', '', '', '', '2026-05-02 13:56:30'),
(12085, 2, 'బుంగమూతి', 'n', 'చిన్న మూతి, అలక  వంటి వాటివల్ల మాట్లాడకుండా మూతి ముడుచుకొని ఉండు', '', '', '', '', '2026-05-02 13:56:30'),
(12086, 2, 'బుక్క', 'n', 'గంధపుపొడి, సుగంధ చూర్ణం, అన్నపుముద్ద రూ బుక్కా, బుక్కాం', '', '', '', '', '2026-05-02 13:56:30'),
(12087, 2, 'బుగబుగ', 'n', 'పరిమళం వ్యాపించడానికి అనుకరణం,  ఒలుకుడు, పారడం  వంటి వాటి ధ్వనికి అనుకరణం, పరిమళం, ఐశ్వర్యాదులవల్ల కలిగే మిట్టు పాటు', '', '', '', '', '2026-05-02 13:56:30'),
(12088, 2, 'బుగ్గలు', 'n', 'చెక్కిళ్ళు,  పర్వతాల నుంచి సంతత ధారగా పైకి ఉబికి వచ్చే నీరు, నీటి బుడగలు, చెక్కిళ్ళు, గాలి బుడగలు', '', '', '', '', '2026-05-02 13:56:30'),
(12089, 2, 'బుగ్గి', 'n', 'బూడిద, దుమ్ము, ధూళి', '', '', '', '', '2026-05-02 13:56:30'),
(12090, 2, 'బుచ్చి', 'n', 'చిన్న, అల్పం', '', '', '', '', '2026-05-02 13:56:30'),
(12091, 2, 'బుజ్జగించు', 'v', 'పలాలించు, మంచి మాటలతో సముదాయించు, స్తుతించు, పొగడు', '', '', '', '', '2026-05-02 13:56:30'),
(12092, 2, 'బుజ్జి', 'n', 'చిన్న, చిట్టి, అల్పం', '', '', '', '', '2026-05-02 13:56:30'),
(12093, 2, 'బుట్ట', 'n', 'పుష్పాదులుంచే తట్ట, వేళ్ళతో అల్లిన బుట్ట,బుట్టి', '', '', '', '', '2026-05-02 13:56:30'),
(12094, 2, 'బుడమ', 'n', 'ఒక జాతి దోస బుడిబుడి', '', '', '', '', '2026-05-02 13:56:30'),
(12095, 2, 'బుడుత', 'n', 'పొట్టివాడు,   వామనుడు, లేత, బిడ్డ, కుమారుడు', '', '', '', '', '2026-05-02 13:56:30'),
(12096, 2, 'బుడ్డి', 'n', 'చిన్నమూతిగల చిన్న కుండ,బుడ్డిగ,  కమండలువు, చిన్న మూతి ఉన్న చిన్న కుండ, గాజు సీసా', '', '', '', '', '2026-05-02 13:56:30'),
(12097, 2, 'బుత్విజుడు', 'v', 'యజ్ఞము చేయించేవాడు;  ఋత్విక్కు, యాజకుడు, యాజయిత', '', '', '', '', '2026-05-02 13:56:30'),
(12098, 2, 'బుద్దుడు', 'n', 'శాక్యముని; అక్షర చణుడు, అద్వయ వాది, అర్కబం ధువు, కనిష్ఠకుడు, కులి శాసనుడు, ఖసముడు, పేశుడు, గౌతముడు, జినుడు, తథాగతుడు, తమోవహుడు, త్రిశరణుడు, తీర్ధకుడు, దశభూమీ శుడు, దాశారుడు, ద్వాద శాఖ్యు, ధర్మచక్షుడు, వంచజ్ఞానుడు, భగవంతుడు, మహాబలుడు, మహా బోధి, మాయా దేవీసుతుడు, మార జిత, లోకజితు, శాక్యముని, శాక్యసింహుడు, శౌధోదని, శ్రీఘనుడు, శ్వేతకేతుడు, షడభిజ్ఞుడు, దశబలుడు, సమంత భద్రుడు, సర్వజుడు, సమదర్శి, సర్వార్థసిద్ధుడు, సుగతుడు, తెలియబడినవాడు, జాగరి తుడు, తెలివిగలవాడు, పండితుడు', '', '', '', '', '2026-05-02 13:56:30'),
(12099, 2, 'బుద్ధి', 'n', 'మతి, మనీష తెలివి,   జ్ఞానం, వివేకం, మనస్సు, ప్రతిభ, తెప్పరిల్లడం, ఆలోచన', '', '', '', '', '2026-05-02 13:56:30'),
(12100, 2, 'బుద్బుదప్రాయం', 'n', 'నీటి బుడగ వంటిది', '', '', '', '', '2026-05-02 13:56:30'),
(12101, 2, 'బుధవారం', 'n', 'ఏడు వారాలలో ఒకటి, సౌమ్యవారం', '', '', '', '', '2026-05-02 13:56:30'),
(12102, 2, 'బుధుడు', 'n', 'పండితుడు, తెలిసిన వాడు ,అన్నిటిని ఎరిగినవాడు,   ఒక గ్రహం, వేలు, వృద్దుడు, బుద్ధిమంతుడు, మేలుకొన్నవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12103, 2, 'బురఖా', 'n', 'ముసుగు (ఆచ్చా దనం), గవు సెన', '', '', '', '', '2026-05-02 13:56:30'),
(12104, 2, 'బురద', 'n', 'పంకం; అసలు, అడుసు, ఊబి, కర్ధమం, పంకం, రొంపి, జంబాలం, నిషద్వరం, బంద, బాడె, రొచ్చు', '', '', '', '', '2026-05-02 13:56:30'),
(12105, 2, 'బురుజు', 'n', 'కోటకొమ్ము, మూలలందు గుండ్రంగా నిర్మించిన నిర్మాణాలు 2 చిన్న గంట', '', '', '', '', '2026-05-02 13:56:30'),
(12106, 2, 'బుర్ర', 'n', 'తల, శిరం, కొబ్బరికాయ  వంటి వాటి గుల్ల, వీణ  వంటి వాటి కమర్చే సొరకాయ, పాముల వాని నాగస్వరం, తలపుర్రె', '', '', '', '', '2026-05-02 13:56:30'),
(12107, 2, 'బుర్రకథలు', 'n', 'వంతలు వాయిస్తూ చెప్పే కథలు', '', '', '', '', '2026-05-02 13:56:30'),
(12108, 2, 'బుర్రమీసం', 'n', 'లావుగా ఉన్న మీసం బుర్రుపిట్ట', '', '', '', '', '2026-05-02 13:56:30'),
(12109, 2, 'బులుపు', 'n', 'ఉబలాటం, అభిలాష, విలాసం, బింకం బుల్లి వంతులమ్మ', '', '', '', '', '2026-05-02 13:56:30'),
(12110, 2, 'బుల్డోజర్', 'n', 'భూమిని సమంగా చేసే యంత్రం', '', '', '', '', '2026-05-02 13:56:30'),
(12111, 2, 'బువ్వ', 'n', 'అన్నం, వంటకం, ఓగిరం', '', '', '', '', '2026-05-02 13:56:30'),
(12112, 2, 'బుషభం', '', 'నంవిఎదు,  ఆనడ్వాహం, ధుర్యం, వరీవర్దం', '', '', '', '', '2026-05-02 13:56:30'),
(12113, 2, 'బుష్కోట్లు', 'n', 'చొక్కాలు', '', '', '', '', '2026-05-02 13:56:30'),
(12114, 2, 'బుస', 'n', '1 పాములు  వంటి వాటి పూత్కారం, 2 నిట్టూర్పు', '', '', '', '', '2026-05-02 13:56:30'),
(12115, 2, 'బూచి', 'n', 'భూతం, పిశాచం పిలలన భయ పెట్టడానికి వాడేమాట', '', '', '', '', '2026-05-02 13:56:30'),
(12116, 2, 'బూజు', 'n', '1 దుర్గంధం, పుస్తు, 2 ఎండ సోకకపోవడంవల్ల తడి వస్తువుల పై పట్టే మకిలి', '', '', '', '', '2026-05-02 13:56:30'),
(12117, 2, 'బూటకం', 'n', '1 మోసం, మాయ, 2 కల్లమాట', '', '', '', '', '2026-05-02 13:56:30'),
(12118, 2, 'బూట్లు', 'n', 'కాలిజోడు', '', '', '', '', '2026-05-02 13:56:30'),
(12119, 2, 'బూడిదపాలు', 'n', 'వృథా, వ్యర్థం', '', '', '', '', '2026-05-02 13:56:30'),
(12120, 2, 'బూడిదలో పోసిన పన్నీరు', '', 'జా వ్యర్థం, నిష్ప్రయోజనం', '', '', '', '', '2026-05-02 13:56:30'),
(12121, 2, 'బూర', 'n', 'ఊదే వాద్య విశేషం, కాహళి భేదం, బాకా ఊదేటువంటి', '', '', '', '', '2026-05-02 13:56:30');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(12122, 2, 'బూరుగు', 'n', 'శాల్మలి వృక్షం  కంటక ద్రుమం, కఠ్కటి, చిరంజీవి, తులిని, తూలఫల, దారణి, దీర్ఘ ద్రుమం, దురారోహం, నకులి, పిచులం, మోచకి, మోద, యమవృక్షం, రక్టోత్సలం, రోచనం, శ్రీమూలం, స్థిరజీవిక, స్థూలకంటిక', '', '', '', '', '2026-05-02 13:56:30'),
(12123, 2, 'బృందం', 'n', 'గుంపు, సమూహం', '', '', '', '', '2026-05-02 13:56:30'),
(12124, 2, 'బృందావనం', 'n', 'గోకులానికి సమీపంలోని అడవి, తులసికోట, కృష్ణుడు నివసించే తులసి తోట, రాఘవేంద్ర స్వామి సమాధి పొందిన స్థలం', '', '', '', '', '2026-05-02 13:56:30'),
(12125, 2, 'బృహత్కార్యక్రమం', 'n', 'పెద్ద కార్యక్రమం, పెద్దపని', '', '', '', '', '2026-05-02 13:56:30'),
(12126, 2, 'బృహన్నల', 'n', 'విరాటనగరంలో అజ్ఞాత వాసం నాటి అర్జునుని పేరు', '', '', '', '', '2026-05-02 13:56:30'),
(12127, 2, 'బృహస్పతి', 'n', 'దేవతల గురువు,  వాక్కులకు ప్రభువు సురాచార్యుడు, గీష్పతి, దీషణుడు, గురువు, జీవుడు, ఆంగిరసుడు, వాచస్పతి, చిత్ర శిఖండిజుడు, ఆర్యుడు, సూరి, వాగీ శుడు, వచసాంపతి,  సురగురువు, ఒక గ్రహం, ఒక ముని', '', '', '', '', '2026-05-02 13:56:30'),
(12128, 2, 'బెంగ', 'n', 'కలవరం, మనోవ్యాకులత, విరహవ్యథ, కేక', '', '', '', '', '2026-05-02 13:56:30'),
(12129, 2, 'బెకబెక', 'n', 'కప్పలు కూయడంలోని ధ్వనికి అనుకరణం', '', '', '', '', '2026-05-02 13:56:30'),
(12130, 2, 'బెగడు', 'n', 'భయపడు,బెగ్గడు,  కలతనొందు, బెంగ పెట్టుకొని దుఃఖపడు, కంపించు', '', '', '', '', '2026-05-02 13:56:30'),
(12131, 2, 'బెగ్గురుపిట్ట, స్త్రీ మొలనూలు, పక్షి, (దే) వినోదం సారస్యం', 'n', 'సరసత్వం', '', '', '', '', '2026-05-02 13:56:30'),
