(12530, 2, 'మతకం', 'n', 'కపటం, కుత్సితం,  మాయ, గుట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(12531, 2, 'మతకరి', 'n', 'మాయకలవాడు, మాయలాడి;', '', '', '', '', '2026-05-02 13:56:30'),
(12532, 2, 'మతప్రచారకులు', 'n', 'మతాన్ని ప్రచారం చేసేవారు;', '', '', '', '', '2026-05-02 13:56:30'),
(12533, 2, 'మతల్లి', 'n', 'శ్రేష్ఠురాలు; మతల్లిక', '', '', '', '', '2026-05-02 13:56:30'),
(12534, 2, 'మతి', 'n', 'బుద్ది, జ్ఞానం,   మనస్సు, వాంఛ, వాక్కు, తలపువిధం, కోరిక, తెలివి, స్మృతి, రీతి', '', '', '', '', '2026-05-02 13:56:30'),
(12535, 2, 'మతోనోదం', 'n', 'మతపిచ్చి;', '', '', '', '', '2026-05-02 13:56:30'),
(12536, 2, 'మత్కుణం', 'n', 'నల్లి,   కొబ్బరికాయ, దున్నపోతు, కొబ్బరిచెట్టు, దంతాలులేని ఏనుగు', '', '', '', '', '2026-05-02 13:56:30'),
(12537, 2, 'మత్తు', 'n', '1 మదం, మత్తా, 2 మైకం (నిద్దుర మత్తు) కొవ్వు', '', '', '', '', '2026-05-02 13:56:30'),
(12538, 2, 'మత్తుడు', 'n', 'మదించినవాడు;   ఉత్కటుడు, క్షీబుడు, శాండుడు', '', '', '', '', '2026-05-02 13:56:30'),
(12539, 2, 'మత్తుపానీయాలు', 'n', 'మత్తును కలిగించే ద్రావకాలు;', '', '', '', '', '2026-05-02 13:56:30'),
(12540, 2, 'మత్సరం', 'n', 'అసూయ, ఓర్వ / పోవడం,   క్రోధం, ఆత్మధిక్కారం, ద్వేషం, గర్వం, లోభం;', '', '', '', '', '2026-05-02 13:56:30'),
(12541, 2, 'మత్స్యం', 'n', 'చేప, మీనరాశి, ఒక పురాణం,  మాంసం హరించే ఇచ్చతో హర్షించేది', '', '', '', '', '2026-05-02 13:56:30');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(12542, 2, 'మత్స్యావతారం', 'n', 'శ్రీవిష్ణుని  దశావతారాలలో మొదటి అవతారం;', '', '', '', '', '2026-05-02 13:56:30'),
(12543, 2, 'మథనం', 'n', 'చిలకడం,   చిలికేది, నశింపజేసేది, ధ్వంసంచేయడం', '', '', '', '', '2026-05-02 13:56:30'),
(12544, 2, 'మథనపడు', '', 'మిక్రి మానసిక సంఘర్షణ చెందు, బాధపడు;', '', '', '', '', '2026-05-02 13:56:30'),
(12545, 2, 'మథుర', 'n', 'యమునానదీ తీరంలోని శ్రీకృష్ణుని జన్మస్థానమైన పట్టణం', '', '', '', '', '2026-05-02 13:56:30'),
(12546, 2, 'మదజలం', 'n', 'మదపుటేనుగు గండస్థలాల నుంచి స్రవించే కొవ్వు,  మదింపజేసేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12547, 2, 'మదమడగు', '', 'మిక్రి బలహీనుడగు గర్వాన్ని అణచు;', '', '', '', '', '2026-05-02 13:56:30'),
(12548, 2, 'మదర్', 'n', 'తల్లి, అమ్మ, మాత మూలం, (ఇక్కడ మదర్ థెరిసా);', '', '', '', '', '2026-05-02 13:56:30'),
(12549, 2, 'మదింపు', 'n', 'అంచనా, ఇంత అని వెల  వంటి వాటిని ఊహించడం', '', '', '', '', '2026-05-02 13:56:30'),
(12550, 2, 'మది', 'n', 'మనస్సు,   బుద్దీ, ఇచ్చ, చషకం (పానపాత్రం), కృషిసాధనం;', '', '', '', '', '2026-05-02 13:56:30'),
(12551, 2, 'మదిరాక్షి', 'n', 'స్త్రీ,  మదం కప్పిన కళ్ళు గలది; మోహింపచేసే', '', '', '', '', '2026-05-02 13:56:30'),
(12552, 2, 'మదీయం', 'n', 'నాది, నా  సంబంధమైనది;', '', '', '', '', '2026-05-02 13:56:30'),
(12553, 2, 'మద్దతు', '', 'దే తోడ్పాటు, సాహాయ్యం,  మద్దత్తు', '', '', '', '', '2026-05-02 13:56:30'),
(12554, 2, 'మద్ది', 'n', 'సాలం, అర్జునం,  ఒకజాతిచెట్టు;', '', '', '', '', '2026-05-02 13:56:30'),
(12555, 2, 'మద్దెల', 'n', 'మృదంగం; మద్యం', '', '', '', '', '2026-05-02 13:56:30'),
(12556, 2, 'మద్యపానం', 'n', 'కల్లుతాగడం;', '', '', '', '', '2026-05-02 13:56:30'),
(12557, 2, 'మద్యపానుడు', 'n', 'కల్లుతాగిన వాడు;', '', '', '', '', '2026-05-02 13:56:30'),
(12558, 2, 'మధుకం', 'n', 'తుమ్మెద,  పూదేనెను చేసేది,  భిక్షాన్నం, జీవన వృక్షం', '', '', '', '', '2026-05-02 13:56:30'),
(12559, 2, 'మధుకోశం', 'n', 'తేనెపట్టు;', '', '', '', '', '2026-05-02 13:56:30'),
(12560, 2, 'మధుపం', 'n', 'తుమ్మెద, తేనెటీగ,  మధువు (తేనె)ను పానం చేసేది', '', '', '', '', '2026-05-02 13:56:30'),
(12561, 2, 'మధుపర్కం', 'n', 'పెరుగు, నేయి, నీరు, తేనె, పంచదార అనే అయిదువస్తువుల సముదాయం,  1 పెరుగుతో కలసిన తేనె, 2 పెళ్ళిలో వధూవరులకిచ్చే వస్త్రాలు', '', '', '', '', '2026-05-02 13:56:30'),
(12562, 2, 'మధుమాసం', 'n', 'వసంతం;', '', '', '', '', '2026-05-02 13:56:30'),
(12563, 2, 'మధురం', 'n', 'తియ్యనిది,   మనోహరమైనది, శోభనం, వరి, జీలకర్ర, విషం, తగరం, శర్కరలో ఒక విధం', '', '', '', '', '2026-05-02 13:56:30'),
(12564, 2, 'మధుర స్మృతులు', 'n', 'తీయని తలపులు;', '', '', '', '', '2026-05-02 13:56:30'),
(12565, 2, 'మధురిమ', 'n', 'మాధుర్యం తియ్యదనం, కమ్మదనం, చక్కదనం;', '', '', '', '', '2026-05-02 13:56:30'),
(12566, 2, 'మధువు', 'n', 'తేనె,   పాలు, నీరు, కల్లు, మకరందం, చైత్రం, వసంతరువు, ఇప్పచెట్టు, నెయ్యి, ఒక రక్కసుడు, పాలకూర', '', '', '', '', '2026-05-02 13:56:30'),
(12567, 2, 'మధువ్రతం', 'n', 'తుమ్మెద, పాలచెట్టు,  పూదేనెను మాత్రం తాగే వ్రతం కలది', '', '', '', '', '2026-05-02 13:56:30'),
(12568, 2, 'మధుసూదనుడు', 'n', 'విష్ణువు,  మధువు అనే రాక్షసుని చంపినవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12569, 2, 'మధ్యం', 'n', 'నడిమిది, నడుము,   అవకాశం, న్యాయం, నడితరముది, పక్షపాతంలేనిది', '', '', '', '', '2026-05-02 13:56:30'),
(12570, 2, 'మధ్యందినం', 'n', 'మధ్యాహ్నం, పట్టపగలు', '', '', '', '', '2026-05-02 13:56:30'),
(12571, 2, 'మధ్యమం', 'n', 'నడుమనున్నది; నడుము, నడిమిది, ఒక స్వరం', '', '', '', '', '2026-05-02 13:56:30'),
(12572, 2, 'మధ్యమ పురుష', 'n', 'నీవు, మీరు కర్తలుగా కలది, ప్రథమ మధ్యమ ఉత్తమ పురుషములలో నడిమిది; ఎదుటి వారి గురించి చెప్పేది', '', '', '', '', '2026-05-02 13:56:30'),
(12573, 2, 'మధ్యరాత్రం', 'n', 'అర్థరాత్రం, నిశీథం, నడిరేయి;', '', '', '', '', '2026-05-02 13:56:30'),
(12574, 2, 'మధ్యవర్తి', 'n', 'రెండు పక్షాల వాదం విని తీర్పు చెప్పువాడు;', '', '', '', '', '2026-05-02 13:56:30'),
(12575, 2, 'మధ్యాహ్నం', 'n', 'మధ్యందినం, పట్టపగలు, దివాభాగం  మధ్యకాలం;', '', '', '', '', '2026-05-02 13:56:30'),
(12576, 2, 'మనం', 'n', 'మనసు,   బుద్ధి, నీవు నేను', '', '', '', '', '2026-05-02 13:56:30'),
(12577, 2, 'మననం', 'n', 'ధ్యానం, ఆలోచన,   జ్ఞానం, యుక్తులచే పొందబడిన సిద్దాంతం', '', '', '', '', '2026-05-02 13:56:30'),
(12578, 2, 'మననీడు', 'v', 'ఉండనీయడు;', '', '', '', '', '2026-05-02 13:56:30'),
(12579, 2, 'మనవడు', 'n', 'పౌత్రుడు, కొడుకు,  లేదా కూతురు కొడుకు,  మనుమడు', '', '', '', '', '2026-05-02 13:56:30'),
(12580, 2, 'మనవి', 'n', 'విన్నపం, విజ్ఞప్తి, ప్రార్థన', '', '', '', '', '2026-05-02 13:56:30'),
(12581, 2, 'మనవు', '', 'దే కాపురం, జీవనం, పెండ్లి,   వృత్తి, ప్రవర్తన, కాపురం', '', '', '', '', '2026-05-02 13:56:30'),
(12582, 2, 'మనసారా', '', ',అవ్య మనసుపూర్తిగా;', '', '', '', '', '2026-05-02 13:56:30'),
(12583, 2, 'మనసిచ్చు', 'v', 'గుట్టుచెప్పు, రహస్యం తెలుపు;', '', '', '', '', '2026-05-02 13:56:30'),
(12584, 2, 'మనసిజుడు', 'n', 'మన్మథుడు,  మనస్సులో ఉదయించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12585, 2, 'మనసు', 'n', 'చిత్తం, ఉల్లం,  మనస్సు,  హృదయం, లింగశరీరా వయవం, తలపు, కోరిక, మణిసిల, అభిప్రాయం, వలపు, అనురాగం జీవాత్మకంటే భిన్నమైన జ్ఞానజనక ద్రవ్యం', '', '', '', '', '2026-05-02 13:56:30'),
(12586, 2, 'మనసులో ముల్లు', '', 'మివి ఎక్కువ బాధ;', '', '', '', '', '2026-05-02 13:56:30'),
(12587, 2, 'మనస్కరించు', 'v', 'ఇష్టపడు, ఇష్టమగు;', '', '', '', '', '2026-05-02 13:56:30'),
(12588, 2, 'మనస్తత్వాలు', '', 'నంవి మనస్సు (స్థితులు) స్వభావాలు;', '', '', '', '', '2026-05-02 13:56:30'),
(12589, 2, 'మనస్తాపం', 'n', 'మానసికబాధ, అనుతాపం, పశ్చాత్తాపం;', '', '', '', '', '2026-05-02 13:56:30'),
(12590, 2, 'మనస్వి', 'n', '1 ప్రశస్తమైన మనస్సు గలవాడు 2 విద్వాంసుడు', '', '', '', '', '2026-05-02 13:56:30'),
(12591, 2, 'మనికి', '', 'దేవి బతుకు, జీవనం,   ఉనికి, నెలవు, స్థానం', '', '', '', '', '2026-05-02 13:56:30'),
(12592, 2, 'మనియార్డరు', 'n', 'సొమ్ము చెల్లింపుకు వంపే ఆజ్ఞాపత్రం నిర్దిష్టమైన, (సాధారణంగా పోస్టాఫీసులో లేదా బ్యాంకులో కానీ జారీ చేస్తారు)', '', '', '', '', '2026-05-02 13:56:30'),
(12593, 2, 'మనీష', 'n', 'బుద్ధి, తెలివి,  అన్నింటిని తెలిసికొనేది', '', '', '', '', '2026-05-02 13:56:30'),
(12594, 2, 'మనీషి', 'n', 'వండితుడు, తెలివిగలవాడు,  బుద్ధికలవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12595, 2, 'మను', 'v', 'బ్రతుకు, జీవించు దేవి మట్టి, భూమి; మనుబోతు; ఒకజాతి జింక,   వృద్ధినొందు, వర్తిల్లు, ఉండు, పుట్టు, శోభిల్లు, ధన్యుడగు;', '', '', '', '', '2026-05-02 13:56:30'),
(12596, 2, 'మనుగడ', 'n', 'జీవనం,   సుఖజీవనం, జీవిక', '', '', '', '', '2026-05-02 13:56:30'),
(12597, 2, 'మనుచు', 'v', 'బ్రతికించు,  మంచు, మన్చు,  పెంచు, నిలుపు, పోషించు, రక్షించు', '', '', '', '', '2026-05-02 13:56:30'),
(12598, 2, 'మనుజుడు', 'n', 'మనుష్యుడు, మానిసి,  మనువువల్ల పుట్టినవాడు (నరుడు),   మానుషుడు, మర్త్యుడు, మానవుడు, నరుడు, పంచజనుడు, మానిసి, మనిషి మనిసి, పురుషుడు, పూరుషుడు, జనుడు', '', '', '', '', '2026-05-02 13:56:30'),
(12599, 2, 'మనుమరాలు', 'n', 'దౌహిత్రి, కూతురుపుత్రి, కొడుకు కూతురు;', '', '', '', '', '2026-05-02 13:56:30'),
