(12949, 2, 'మీరు', 'v', 'ఉల్లంఘించు, దాటు,   నిరసించు, అతిక్రమించు, ఒప్పు, అతిశయించు, కలుగు, గతించు, సఫలమగు', '', '', '', '', '2026-05-02 13:56:30'),
(12950, 2, 'మీలితం', 'n', 'మూయబడినది; మీసం', '', '', '', '', '2026-05-02 13:56:30'),
(12951, 2, 'ముంగల', 'n', 'ముందు, ముందుచోటు పురోభాగం ,  ముంగడ, ముందర', '', '', '', '', '2026-05-02 13:56:30'),
(12952, 2, 'ముంగాలు', 'n', 'పాదాగ్రం; (ముందు +కాలు)', '', '', '', '', '2026-05-02 13:56:30'),
(12953, 2, 'ముంగి', '', 'దే ముంగిస, నకులం,  ముంగిస,  కోటీరం, కౌశికం, పింగళం, బభ్రువు, వంచకం, సర్పారి, బలి, శుచివక్రం, ఎక్కువగా మాట్లాడని వ్యక్తి ముంగిలి', '', '', '', '', '2026-05-02 13:56:30'),
(12954, 2, 'ముంగురులు', 'n', 'అలకలు, నొసలి పై ఆడే ఉంగరపు వెంట్రుకలు', '', '', '', '', '2026-05-02 13:56:30'),
(12955, 2, 'ముంగొంగు', 'n', 'చెంగుకొన,  మునికొంగు', '', '', '', '', '2026-05-02 13:56:30'),
(12956, 2, 'ముంచు', 'v', 'మునగజేయు,   ఆచ్చాదించు, నశింపజేయు, అతిశయించు, కలుగు, విజృంభించు', '', '', '', '', '2026-05-02 13:56:30'),
(12957, 2, 'ముంచెత్తు', '', '\'దేక్రి మునగజేయు;', '', '', '', '', '2026-05-02 13:56:30'),
(12958, 2, 'ముంజె', 'v', 'దేవి లేత తాటికాయలోని గిజురు (మెత్తటి పదార్థం)', '', '', '', '', '2026-05-02 13:56:30'),
(12959, 2, 'ముండ', 'n', 'విధవ, విశ్వస్త,   దాసి, ఉంపుడుకత్తె, దూర్తురాలు, కొన్ని నియమాలున్న భిక్షుకులు', '', '', '', '', '2026-05-02 13:56:30'),
(12960, 2, 'ముండమోపి', 'n', 'విధవ, ముండమోసినది; వితంతువు, భర్తపోయిన స్త్రీ', '', '', '', '', '2026-05-02 13:56:30'),
(12961, 2, 'ముండమోయు', 'v', 'వైధవ్యం పొందు;', '', '', '', '', '2026-05-02 13:56:30'),
(12962, 2, 'ముండ్లపంది', 'n', 'ఏదుపంది, శల్యం;', '', '', '', '', '2026-05-02 13:56:30'),
(12963, 2, 'ముంత', '', 'దే దార్వాది కలశం, మానిక,   చెంబు, కుండ, మానిక,మూడున్నర సేరు', '', '', '', '', '2026-05-02 13:56:30'),
(12964, 2, 'ముందంజ', 'n', 'ముందడుగు;', '', '', '', '', '2026-05-02 13:56:30'),
(12965, 2, 'ముందటేడు', 'n', 'కడచిన సంవత్సరానికి పూర్వ సంవత్సరం (ముందు + ఏడు);', '', '', '', '', '2026-05-02 13:56:30'),
(12966, 2, 'ముందడుగు', 'n', 'అభివృద్ధి, మొదటి పాదం;', '', '', '', '', '2026-05-02 13:56:30'),
(12967, 2, 'ముందర', '', 'దే ముందుభాగం, పురోభాగం,   వెనుక, మొదటికాలం, భవిష్యత్కాలం, పూర్వకాలం;', '', '', '', '', '2026-05-02 13:56:30'),
(12968, 2, 'ముందస్తు', 'n', 'మొదట;', '', '', '', '', '2026-05-02 13:56:30'),
(12969, 2, 'ముందు', 'n', 'పూర్వకాలం;   తొలి, తొల్లి, తొలుత, పూర్వం, ముందర, మునుపు,  భవిష్యత్కాలం, ఉత్తరకాల ఫలం, పురోభాగం, సమ్ముఖం;', '', '', '', '', '2026-05-02 13:56:30'),
(12970, 2, 'ముందెన్నడు', '', 'అవ్య పూర్వం ఎప్పుడు;', '', '', '', '', '2026-05-02 13:56:30'),
(12971, 2, 'ముంపు', '', 'దేవి ముంచడం,   వద్ది, వెల్లువ, గుంపు, అతిశయం, లక్ష్యం', '', '', '', '', '2026-05-02 13:56:30'),
(12972, 2, 'ముకుందుడు', 'n', 'విష్ణువు,  మోక్షం ఇచ్చేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(12973, 2, 'ముకుటం', 'n', 'కిరీటం,  తురాయి, పర్వతశిఖరం', '', '', '', '', '2026-05-02 13:56:30'),
(12974, 2, 'ముకుదాడు', 'n', 'నాథం, ఎడ్లకు  ముక్కున గుచ్చేదారం;', '', '', '', '', '2026-05-02 13:56:30'),
(12975, 2, 'ముకుదూలం', 'n', 'ముక్కునడిమి ఎముక;', '', '', '', '', '2026-05-02 13:56:30'),
(12976, 2, 'ముకుబంటి', 'n', 'ముక్కులోతు;', '', '', '', '', '2026-05-02 13:56:30'),
(12977, 2, 'ముకురం', 'n', 'అద్దం,  దీనిచే అలంకరింపబడతారు,  మల్లె చెట్టు, రేగుచేటు, పొగడచెట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(12978, 2, 'ముకుళించు', 'v', 'మోడ్చు, ముడుచుకొను;', '', '', '', '', '2026-05-02 13:56:30'),
(12979, 2, 'ముక్కంటి', '', 'దేవి శివుడు, త్రిలోచనుడు,  మూడు కన్నులు ఉన్నవాడు', '', '', '', '', '2026-05-02 13:56:30');
