(12982, 2, 'ముక్కర', '', 'దే ముక్కుకు అలంకరించుకొనే వలయాకార ఆభరణం, నత్తు ,  ముంగర', '', '', '', '', '2026-05-02 13:56:30'),
(12983, 2, 'ముక్కారు', 'n', 'మూడు కాలాలు; మూడు పంటలు; (మూడు + కారులు)', '', '', '', '', '2026-05-02 13:56:30'),
(12984, 2, 'ముక్కాలిపీట', 'n', 'మూడుకాళ్ళు అమర్చిన ఎత్తుబల్ల ,  ముక్కలిపీట(మూడు+కాళులు+పీట)', '', '', '', '', '2026-05-02 13:56:30'),
(12985, 2, 'ముక్కాలు', 'n', 'ముప్పాతిక; ముప్పావు, నాలుగువంతుల్లో మూడువంతులు(మూడు+కాళులు)', '', '', '', '', '2026-05-02 13:56:30'),
(12986, 2, 'ముక్కిడి', 'n', 'ముక్కులేనివాడు, ముక్కులేనిది;', '', '', '', '', '2026-05-02 13:56:30'),
(12987, 2, 'ముక్కు', 'n', 'నాసిక, నోటికి పై భాగంలో ఉండే అవయవం,   మూర్కొను (వాసనచూసే) సాధనం   ఘాణం, గన్జవహ, ఫణ, నాస, నశ్య, ముక్కు,  శ్వాసం స్తంభించు, స్తనాగ్రం, తుద, చెడిపోవు;', '', '', '', '', '2026-05-02 13:56:30'),
(12988, 2, 'ముక్కు కరచి', 'v', 'ముక్కుతో పట్టుకొని;', '', '', '', '', '2026-05-02 13:56:30'),
(12989, 2, 'ముక్కు విరుచు', 'v', 'నిరసించు, ఆక్షేపించు, ఇష్టపడకపోవు, అసంతృప్తి పొందు;', '', '', '', '', '2026-05-02 13:56:30'),
(12990, 2, 'ముక్కుపుటాలు', 'n', 'ముక్కు రంధ్రాలు;', '', '', '', '', '2026-05-02 13:56:30'),
(12991, 2, 'ముక్కోటి', 'n', 'వైకుంఠ ఏకాదశి ధనుర్మాసంలో వచ్చే శుక్లఏకాదశి(మూడు + కోటులు)', '', '', '', '', '2026-05-02 13:56:30'),
(12992, 2, 'ముక్కోపి', '', 'మివిణ శీఘ్రంగా కోపం వచ్చేవాడు;ఎక్కువకోపం ఉండే వ్యక్తి', '', '', '', '', '2026-05-02 13:56:30'),
(12993, 2, 'ముక్తకం', 'n', 'ఏకశ్లోక రూపమైన ఖండకావ్యం,   అస్త్రం, గద్యం,', '', '', '', '', '2026-05-02 13:56:30'),
(12994, 2, 'ముక్తకంఠం', 'n', 'పైకి గట్టిగా అనడం, ఐక్యకంఠం, ఏకకంఠం', '', '', '', '', '2026-05-02 13:56:30'),
(12995, 2, 'ముక్తాయింపు', 'n', 'ముగింపు, ముగించడం;', '', '', '', '', '2026-05-02 13:56:30'),
(12996, 2, 'ముక్తాహారం', 'n', 'ముత్యాలదండ;', '', '', '', '', '2026-05-02 13:56:30'),
(12997, 2, 'ముక్తి', 'n', '1 మోక్షం,  శరీర ఇంద్రియాలవల్ల ఆత్మ విడువ బడడం, ఆత్మను సంసార బంధాలవల్ల విడిపించేది; 2 విడుపు, విడుదల విక', '', '', '', '', '2026-05-02 13:56:30'),
(12998, 2, 'ముఖం', 'n', 'నోరు, మోము;   వక్రం, ఆస్యం, వదనం, తుణం, ఆననం, ఆపనం, ప్రతీకం, మొగం, మోర, వాయి, మూతి,  మొగం, మాట, నోరుతల, చనుమొన, ద్వారంవైపు, పీఠిక, పైభాగం, ప్రభావం, ఉపాయం, మొదలు, ఆధారం, ఊరిముందరి భూమి, రాగి, ఆరంభం, నాటకంలో ఒక సంధి', '', '', '', '', '2026-05-02 13:56:30'),
(12999, 2, 'ముఖద్వారం', 'n', 'నది సముద్రంలో కలిసే చోటు,   నది సముద్రంలో కలిసే చోటు', '', '', '', '', '2026-05-02 13:56:30'),
(13000, 2, 'ముఖమార్జనం', 'n', 'మొహం కడుక్కోవడం;', '', '', '', '', '2026-05-02 13:56:30'),
