(13006, 2, 'ముఖ్యాశయం', 'n', 'ప్రధానమైన ఆశయం, ప్రధానోద్దేశం;', '', '', '', '', '2026-05-02 13:56:30'),
(13007, 2, 'ముగింపు', 'n', 'సమాప్తి; ముగియు', '', '', '', '', '2026-05-02 13:56:30'),
(13008, 2, 'ముగ్గ', 'n', 'ఒకానొక శృంగార నాయిక,  ఉదయిస్తున్న యవ్వనం గలది, 16 సంకు మించని వయసుగల బాలిక,  యౌవనం ఉదయిస్తున్న స్త్రీ, తెలివిలేనిది, కొత్తది, చక్కనిది', '', '', '', '', '2026-05-02 13:56:30'),
(13009, 2, 'ముగ్గు', 'n', 'రంగవల్లి; సున్నంపొడి, సుద్ద;', '', '', '', '', '2026-05-02 13:56:30'),
