(13012, 2, 'ముచ్చట', 'n', 'వేడుక,   సల్లాపం, కోరిక, ప్రేమ, వృత్తాంతం, రమ్యం,', '', '', '', '', '2026-05-02 13:56:30'),
(13013, 2, 'ముచ్చటపడు', 'v', 'ఎక్కువకోరు తహతహపడు;', '', '', '', '', '2026-05-02 13:56:30'),
