(13356, 2, 'మొరగు', 'v', 'మోసగించు, వంచించు, కప్పిపుచ్చు మొర పెట్టు; అరచు, కూయు,   ప్రలాపించు, ప్రలాపం కుక్క అరుపు, పేలడం, పెద్ద గా మాట్లాడు;', '', '', '', '', '2026-05-02 13:56:30'),
(13357, 2, 'మొరటు', 'n', 'మోటు, మొద్దు;', '', '', '', '', '2026-05-02 13:56:30'),
(13358, 2, 'మొరడు', '', 'దే మోడు, స్థాణువు మొద్దు;', '', '', '', '', '2026-05-02 13:56:30'),
(13359, 2, 'మొరయు', 'v', 'మ్రోయు, ధ్వనించు,   కూయు, ప్రవర్తిల్లు', '', '', '', '', '2026-05-02 13:56:30'),
(13360, 2, 'మొర్రి', 'n', 'అంగన్యూనత, కొరత వెలితి, అవయవలోపం;', '', '', '', '', '2026-05-02 13:56:30'),
(13361, 2, 'మొల', 'n', 'నడుము, కటిప్రదేశం;   కటి, కటీరం, జమునం, నితంబం, శ్రోణి,   కట్టుబట్ట, చీల, మేకు, త్రాసుముల్లు', '', '', '', '', '2026-05-02 13:56:30'),
(13362, 2, 'మొలక', '', 'అంకురం,   నిసువు, మొక్క, మొటిక, మొట్టిక, మోకు, మోటిక, మోసు,   అం కురిత బీజం, లేత,', '', '', '', '', '2026-05-02 13:56:30'),
(13363, 2, 'మొలకలెత్తు', '', 'దేక్రి అంకురించు, కలుగు,  మొలకెత్తు;', '', '', '', '', '2026-05-02 13:56:30'),
(13364, 2, 'మొలచు', 'v', 'పుట్టు, జనించు,  మొల్చు,  ప్రత్యక్షమగు, ప్రాప్తించు', '', '', '', '', '2026-05-02 13:56:30'),
(13365, 2, 'మొలతాడు', 'n', 'కటిసూత్రం,  మొలకు కట్టుకొనే తాడు', '', '', '', '', '2026-05-02 13:56:30'),
(13366, 2, 'మొలతామర', 'n', 'మొలగజ్జి;', '', '', '', '', '2026-05-02 13:56:30'),
(13367, 2, 'మొలనూలు', 'n', 'స్త్రీలు అలంకారార్థం ధరించే కటిసూత్రం, రశన  కలాపం, కాంచి, మేఖల, రశన, రసన, సప్తకి, సారసం', '', '', '', '', '2026-05-02 13:56:30'),
(13368, 2, 'మొలాం', '', 'దేవి బంగారు  వంటి వాని పూత,  మలాము, మొల్లాము, మోలం, మోళం,  బంగారు  వంటివాటి పూత, పుండ్లకు పూసే మందు', '', '', '', '', '2026-05-02 13:56:30'),
(13369, 2, 'మొల్లం (బు)', '', 'మివి అధికం, హెచ్చు,   గుంపు, సాంద్రత, పెంపు, ధనం', '', '', '', '', '2026-05-02 13:56:30'),
(13370, 2, 'మొల్ల', '', 'దే మల్లెపూవు, బొడ్డుమల్లె;', '', '', '', '', '2026-05-02 13:56:30'),
(13371, 2, 'మొవ్వు', 'n', 'అరటిచెట్టు  వంటి వాటిలో పుట్టెముడుత వీడని లేత ఆకుమొలక ,  మొవు, మోవు', '', '', '', '', '2026-05-02 13:56:30'),
(13372, 2, 'మొసలి', '', 'దే జలజంతు విశేషం, మకరం; !   అంబుగజం, అంబుమర్కటం, అసి దంష్ట్రం, కుంభ, క్షీరశుక్లం, కుంభీరం, జలగ్రాహం, గ్రాహం, జలకంటకం, జలకపి, జిలజిహ్వం , జలసూకరం, జలసూచి, రుషం, రషాశనం, నక్రం, హోదగ్రహం, కడలిరాతత్తడి, మరునిడాలు, కంటకం', '', '', '', '', '2026-05-02 13:56:30'),
(13373, 2, 'మొహమాటం', 'n', 'సంకోచం, జంకు; చూ మొకమాటం', '', '', '', '', '2026-05-02 13:56:30'),
(13374, 2, 'మొహరు', 'n', 'ముద్ర;', '', '', '', '', '2026-05-02 13:56:30'),
(13375, 2, 'మొహర్రం', 'n', 'ముస్లిముల పీర్లపండుగ;', '', '', '', '', '2026-05-02 13:56:30'),
(13376, 2, 'మోకరిల్లు', 'v', 'మోకాళ్ళు నేలమీద ఆనేటట్టు ముందు కొరుగు, నమస్కరించు;', '', '', '', '', '2026-05-02 13:56:30'),
(13377, 2, 'మోకాలు', 'n', 'జానువు, తొడపిక్కల సంధిభాగం, కీలుభాగం   ముడుకు, ముడుము, కుర్బరం, జానువు; మోకాలొడ్డు', '', '', '', '', '2026-05-02 13:56:30'),
(13378, 2, 'మోకు', 'n', 'లావుతాడు;', '', '', '', '', '2026-05-02 13:56:30'),
(13379, 2, 'మోక్షం', 'n', 'ముక్తి, చావు, విడుదల,  జీవుని కష్టాల నుంచి విడిపించేది, దుఃఖాది దురవస్థల వినాశనం   కైవల్యం, నిర్వాణం, శ్రేయం, అమృతం, అపవర్గం,  మృత్యువు, మొక్కపుచెట్టు, విడుపు, గ్రహణం తుద', '', '', '', '', '2026-05-02 13:56:30'),
(13380, 2, 'మోక్షపదం', 'n', 'మోక్షస్థానం, మోక్షపదవి;', '', '', '', '', '2026-05-02 13:56:30'),
(13381, 2, 'మోచు', 'v', 'మోయు, వహించు,   వహించు, ఎత్తికొను, స్పృశించు, ఆక్రమించు, అంటుకొనిపోవు, పొందు, పోషించు, గుణి సేయు, నిండు', '', '', '', '', '2026-05-02 13:56:30'),
(13382, 2, 'మోచేయి', 'n', 'కూర్పరం, భుజానికీ ముంజేయికీ మధ్య ఉండే కీలుభాగం,  మోచెయ్యి, మోచేయి   కపణి, కపోణి, కూర్పరం, కీలం, కూబరం,', '', '', '', '', '2026-05-02 13:56:30'),
(13383, 2, 'మోజు', 'n', 'అభిలాష, ఆశ;', '', '', '', '', '2026-05-02 13:56:30'),
(13384, 2, 'మోటబావి', 'n', 'పెద్దబావి, (పొలంకోసం మోటకొట్టేబావి);', '', '', '', '', '2026-05-02 13:56:30'),
(13385, 2, 'మోటరు', '', 'ఇవి యంత్రం, చలింపజేసేది, చలన హేతువు;', '', '', '', '', '2026-05-02 13:56:30'),
(13386, 2, 'మోటించు', 'v', 'ఆధారంగా నిలుపు, పోటీగా నిలుపు;', '', '', '', '', '2026-05-02 13:56:30'),
(13387, 2, 'మోటు', '', 'దేని మోడు, పరుషం, మొద్దు,   స్థూలం, మొద్దు', '', '', '', '', '2026-05-02 13:56:30'),
(13388, 2, 'మోడుమాకు', 'v', 'దేవి ఎండిన చెట్టు, మోడు మ్రాకు', '', '', '', '', '2026-05-02 13:56:30'),
(13389, 2, 'మోడ్చు', 'v', 'జోడించు,  మోడుచు,  మూడు, ముడుచు, కన్నులుమూయు, చేతులు జోడించు', '', '', '', '', '2026-05-02 13:56:30'),
(13390, 2, 'మోత', 'n', '1 మోయడం, వహించడం,  మోత 2 భారం, బరువు, ధ్వని', '', '', '', '', '2026-05-02 13:56:30'),
(13391, 2, 'మోతాదు', 'n', 'ఒకసారి ఇచ్చేమందు, హెచ్చు తగ్గుకాని పదార్థం ఎక్కువ తక్కువ కానిది', '', '', '', '', '2026-05-02 13:56:30'),
(13392, 2, 'మోతుబరి', 'v,n', 'ఘనతగల, గొప్ప, నమ్మదగిన;', '', '', '', '', '2026-05-02 13:56:30'),
(13393, 2, 'మోదం', 'n', 'సంతోషం;', '', '', '', '', '2026-05-02 13:56:30'),
(13394, 2, 'మోదకం', 'n', 'ఆనందించేది; n  కుడుము, లడ్లు,  ఉండం, గుండ్రం,', '', '', '', '', '2026-05-02 13:56:30'),
(13395, 2, 'మోదడం', 'v', 'కొట్టడం, ప్రహరించడం;', '', '', '', '', '2026-05-02 13:56:30'),
(13396, 2, 'మోదుగు', '', '\'దేక్రి నలుగు, బాగానోటికి వచ్చు, విషయం బాగా పరిశీలనలో పడు,,  ధాన్యం పొట్టు పోయేటట్లు సలగు, బాగావచ్చు, బలహీనుడగు', '', '', '', '', '2026-05-02 13:56:30'),
(13397, 2, 'మోనపోవు', 'v', 'భంగవడు; వంచితుడగు;', '', '', '', '', '2026-05-02 13:56:30'),
(13398, 2, 'మోపు', 'v', 'ఆనించు,   వహింప జేయు, చేర్చు, ఆరోపించు, గుచ్చు, గడ్డి, కట్ట, గుంపు, మూట, భారం, బాధ్యత, నారి, ఆధిక్యం', '', '', '', '', '2026-05-02 13:56:30'),
(13399, 2, 'మోపెడు', 'n', 'గుంపు, చాలమంది;', '', '', '', '', '2026-05-02 13:56:30'),
(13400, 2, 'మోము', 'n', 'ముఖం,  మొగము చూ మొకము', '', '', '', '', '2026-05-02 13:56:30'),
(13401, 2, 'మోయు', '', 'దేక్ర\' వహించు, తాకు', '', '', '', '', '2026-05-02 13:56:30'),
(13402, 2, 'మోర', '', 'దేవి, ముట్టె, వశ్వాదుల దీర్ఘముఖం !', '', '', '', '', '2026-05-02 13:56:30'),
(13403, 2, 'మోరగించు', 'v', 'మొగం మీదికెత్తు;', '', '', '', '', '2026-05-02 13:56:30');
