(13409, 2, 'మోస్తరు', 'n', 'మాదిరి;', '', '', '', '', '2026-05-02 13:56:30'),
(13410, 2, 'మోహం', 'n', 'అజ్ఞానం,  దుః ఖం,   వలపు, పొరపాటు, బాధ, ఆశ్చర్యం, మూర్చ, చిత్తవికలత్వం, నివ్వెరపాటు', '', '', '', '', '2026-05-02 13:56:30'),
