(13412, 2, 'మోహరం', 'n', 'మొగ్గరం, వ్యూహం,,  సేన, సమూహం', '', '', '', '', '2026-05-02 13:56:30'),
(13413, 2, 'మోహరించు', 'v', 'ఎదుర్కొను, ప్రతిఘటించు, మోహించు;', '', '', '', '', '2026-05-02 13:56:30'),
(13414, 2, 'మోహిని', 'n', 'ఒకానొక అప్సర,   అచ్చర, అమృతం పంచి పెట్టేటప్పుడు రాక్షసులను మోసపుచ్చడం కోసం విష్ణువు తాల్చిన ఒక సుందర స్త్రీ రూపం, ఒక జాతి మల్లెపూవు', '', '', '', '', '2026-05-02 13:56:30'),
(13415, 2, 'మౌంజి', 'n', 'ముంజి, ముంజదర్భ మొలతాడు', '', '', '', '', '2026-05-02 13:56:30'),
(13416, 2, 'మౌక్తికం', 'n', 'ముత్తెం, ముత్యం,  ముత్యపు చిప్ప నుంచి విడువబడినది', '', '', '', '', '2026-05-02 13:56:30'),
(13417, 2, 'మౌఖిక సంప్రదాయం', 'n', 'ముఖతఃనేర్చుకొనే పద్దతి;', '', '', '', '', '2026-05-02 13:56:30'),
(13418, 2, 'మౌఢ్యం', 'n', 'మూఢత్వం, తెలివి / పోవడం,   అజ్ఞానం, అవిద్య, గ్రహాలకు సూర్యసంబంధం', '', '', '', '', '2026-05-02 13:56:30'),
(13419, 2, 'మౌనం', 'n', 'మాట్లాడకుండటం,  అన్యులకు తావం కలిగింపనిది, నిశ్శబ్దం పాటించడం', '', '', '', '', '2026-05-02 13:56:30'),
(13420, 2, 'మౌని', 'n', 'మునీ, రుషి,   మౌనం దాల్చేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(13421, 2, 'మౌనీంద్రులు', 'n', 'మునులలో శ్రేష్ఠమైనవారు', '', '', '', '', '2026-05-02 13:56:30'),
(13422, 2, 'మౌర్వి', 'n', 'వింటినారి, అల్లెత్రాడు;', '', '', '', '', '2026-05-02 13:56:30'),
(13423, 2, 'మౌలికం', 'n', 'మొదటిది, శ్రేష్ఠమైనది;', '', '', '', '', '2026-05-02 13:56:30'),
(13424, 2, 'మౌల్వీ', 'n', 'ఇస్లాం పండితుడు;', '', '', '', '', '2026-05-02 13:56:30'),
