(13828, 2, 'రుచి', 'n', '(వెలుగు), కాంతి, చవి,   ఆకలి, రంగు, కోరిక, సూర్యకిరణం, అభిరుచి, సిరి, రీతి, కమ్మన, ఒకరీతి కౌగిలి', '', '', '', '', '2026-05-02 13:56:30');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(13829, 2, 'రుచిరం', 'n', 'మనోహరమైనది,   సుందరమైనది, మధురమైనది, కుంకుమపువ్వు,', '', '', '', '', '2026-05-02 13:56:30'),
(13830, 2, 'రుజువు', 'n', 'సాక్ష్యం, దృష్టాంతం; ప్రం జ్ఞాపకార్థంగా ఆయన బొమ్మతో తపాలాబిళ్ళ విడుదల చేయడం పై వాటికి రుజువు', '', '', '', '', '2026-05-02 13:56:30'),
(13831, 2, 'రుడు', 'n', 'శాశ్వతుడు, దైవం, శని, రాహువు, చపలత్వం లేని వాడు, కార్తికేయుడు, దైవం', '', '', '', '', '2026-05-02 13:56:30'),
(13832, 2, 'రుణం', 'n', 'అప్పు, పర్యుపంచనం; రుణాలు మూడు 1) దేవరుణం 2)రుషిరుణం,  నీరు, తీసివేత, దుర్గభూమి ,  ఋణం', '', '', '', '', '2026-05-02 13:56:30'),
(13833, 2, 'రుద్దు', 'v', 'తోము, మర్దించు, ఒకరి తప్పు మరొకరి పైనెట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(13834, 2, 'రుద్రభూమి', '', 'నంవి శ్మశానం, ఒలుకులమిట్ట,   ఈశ్వరుని నివాస స్థలం,   వల్లకాడు, రుద్రభూమి', '', '', '', '', '2026-05-02 13:56:30'),
(13835, 2, 'రుద్రాక్షం', 'n', 'రుద్రాక్షపుపూస, ఒకానొకచెట్టు;', '', '', '', '', '2026-05-02 13:56:30'),
(13836, 2, 'రుద్రాక్షపిల్లి', '', 'మివి వంచకుడు; మనస్సులో ఉన్నభావాన్ని కప్పిపుచ్చి పైకి సాధువుగా కనబడే వంచకుడు, మంచివాడి మాదిరిగా ఉండి మోసగించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(13837, 2, 'రుద్రాణి', 'n', 'పార్వతి,   రుద్రునిభార్య,  గంగ, రుద్రజడ చెట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(13838, 2, 'రుద్రుడు', 'n', 'శివుడు,   అసురులను రోదనం చేయించే వాడు, దుఃఖాన్ని పోగొట్టేవాడు,  అగ్ని, 11సంఖ్యకు సంకేతం', '', '', '', '', '2026-05-02 13:56:30'),
(13839, 2, 'రుధిరం', 'n', 'రక్తం, నెత్తురు,  మణిభేదం, ఎర్రరంగు, అంగారకగ్రహం, ,  కుంకుమపువ్వు, మణిభేదం, ఎర్రరంగు, అంగారక గ్రహం', '', '', '', '', '2026-05-02 13:56:30'),
(13840, 2, 'రుధిరోద్గారి', 'n', 'అరవై తెలుగు సంవత్సరాలలో ఒకటి', '', '', '', '', '2026-05-02 13:56:30'),
(13841, 2, 'రుబ్బురోలు', 'n', 'నానినపప్పు  వంటివాటిని రుబ్బడానికి రాతితో చేసిన సాధనం;', '', '', '', '', '2026-05-02 13:56:30'),
(13842, 2, 'రుబ్ళు', 'v', 'నానిన పప్పు  వంటి వాటిని రోటిలో వేసి పొత్తరంతో మెదుపు, చదువు  వంటి కంఠోపాఠంచేయు;', '', '', '', '', '2026-05-02 13:56:30'),
(13843, 2, 'రుమాలు', 'n', 'తలగుడ్డ, చేతిగుడ్డ;', '', '', '', '', '2026-05-02 13:56:30'),
(13844, 2, 'రువ్వు', 'v', 'విసరు, వీచు, చిమ్ము, గుద్దు;', '', '', '', '', '2026-05-02 13:56:30'),
(13845, 2, 'రుస రుసలాడు', 'v', 'చిరాకుపడు, కోపించు;', '', '', '', '', '2026-05-02 13:56:30'),
(13846, 2, 'రుసుం', 'n', 'లాభం, లంచం, ఫీజు', '', '', '', '', '2026-05-02 13:56:30'),
(13847, 2, 'రూం', 'n', 'గది;', '', '', '', '', '2026-05-02 13:56:30'),
(13848, 2, 'రూక', '', 'దేవి ఒకానొక నాణెం, ధనం రూఢి', '', '', '', '', '2026-05-02 13:56:30'),
(13849, 2, 'రూపం', 'n', 'ఆకారం,   శుక్లాది వర్ణం, అందం, స్వభావం, స్థితి, స్వరూపం, సామ్యం, ఒకటి, రూపకం, రూప్యం, శబ్దం, మృగం, పద్యం, పేరు, అగ్నిగుణం', '', '', '', '', '2026-05-02 13:56:30'),
(13850, 2, 'రూపకం', 'n', 'దృశ్యకావ్యం (నాటకం  వంటివి) వివ', '', '', '', '', '2026-05-02 13:56:30'),
(13851, 2, 'రూపకల్పన', 'n', 'నిర్మాణం,   రూపాన్ని కల్పించడం', '', '', '', '', '2026-05-02 13:56:30'),
(13852, 2, 'రూపసి', '', 'దే విణ సౌందర్యవతి, సౌందర్యవంతుడు; వ్యతి', '', '', '', '', '2026-05-02 13:56:30'),
(13853, 2, 'రూపాం', '', 'రచియించు,  ఏర్పరచు, నిర్ణయించు, నిర్మించు, చేయు, సిద్ధపరచు', '', '', '', '', '2026-05-02 13:56:30'),
(13854, 2, 'రూపాయ', 'n', 'ఒక వెండినాణెం, వంద పైసలకు సమానమైన ద్రవ్యమానం;', '', '', '', '', '2026-05-02 13:56:30'),
(13855, 2, 'రూపించు', 'v', 'నిర్ణయించు, విమర్శించు;', '', '', '', '', '2026-05-02 13:56:30'),
(13856, 2, 'రూపు', 'n', 'ఆకారం,  సౌందర్యం, దేహం, విధం, స్థితి, నిజం;', '', '', '', '', '2026-05-02 13:56:30'),
(13857, 2, 'రూపుమాపు', 'v', 'నశింపజేయు, చంపు', '', '', '', '', '2026-05-02 13:56:30'),
(13858, 2, 'రూపురేఖలు', '', 'మివి ఆకారాన్నిచ్చే పంక్తులు, ఆకారం', '', '', '', '', '2026-05-02 13:56:30'),
(13859, 2, 'రూపొందించు', 'v', 'ఆకారం కల్పించు, ఏర్పరుచు;', '', '', '', '', '2026-05-02 13:56:30'),
(13860, 2, 'రూలు', 'n', 'నియమం, నిబంధన; 2 ఇంక్రి పరిపాలించు; 3 ఇంక్రి గీత', '', '', '', '', '2026-05-02 13:56:30'),
(13861, 2, 'రూలుగర్ర', '', 'మివి గీతలు గీసే కర్ర', '', '', '', '', '2026-05-02 13:56:30'),
(13862, 2, 'రెండవమారు', 'n', 'రెండోసారి;', '', '', '', '', '2026-05-02 13:56:30'),
(13863, 2, 'రెండు', 'n', 'ద్విశబ్దార్థకం, ఒకటి తరవాత సంఖ్య   అక్షి, చక్షువు, కరం, నేత్రం, లోచనం, బాహువు, కర్ణం, పక్షం, దృష్టిద్వయం, యుగ్మం, అంబకం, నయనం, ఈక్షణం', '', '', '', '', '2026-05-02 13:56:30'),
(13864, 2, 'రెక్క', '', 'దే పక్షం, భుజం   ఎరక, గరుత్తు, గరి, చట్టుప, ఛదం, ఛదనం, తనూరుహం, పక్షం, నేరి, పతత్రం, వాజం', '', '', '', '', '2026-05-02 13:56:30'),
(13865, 2, 'రెక్కలార్చు', 'v', 'రెక్కలాడించు, పక్షాలు కదలించు', '', '', '', '', '2026-05-02 13:56:30'),
(13866, 2, 'రెక్కాడితేనే బుక్కాడు', 'v', 'కష్టపడితేనే తిండి దొరుకు, కష్టపడితేనే కడుపు నిండు;', '', '', '', '', '2026-05-02 13:56:30'),
(13867, 2, 'రెచ్చు', 'v', 'విజృంభించు, చెలరేగు;', '', '', '', '', '2026-05-02 13:56:30'),
(13868, 2, 'రెట్ట', 'n', 'పక్షిమలం,  భుజం, పక్షిరెక్క', '', '', '', '', '2026-05-02 13:56:30'),
(13869, 2, 'రెట్టవేయు', 'v', 'మలవిసర్జనం చేయు రెట్టింపు', '', '', '', '', '2026-05-02 13:56:30'),
(13870, 2, 'రెప రెప', '', '\'దేవి 1 గాలివీచే ధ్వనికి అనుకరణం 2 నిప్పుమండే ధ్వనికి అనుకరణం, రవంత కొట్టుకోవడం, కొనప్రాణంతో కొట్టుకులాడటం', '', '', '', '', '2026-05-02 13:56:30'),
(13871, 2, 'రెమ్మ', 'n', 'ఉపశాఖ, కొమ్మ; పూరేకు,  రెబ్బ', '', '', '', '', '2026-05-02 13:56:30'),
(13872, 2, 'రెయిన్ కోటు', 'n', 'వర్షపుచొక్కా,   వర్షంలో తడవకుండా వేసుకునే (చొక్కా) కోటు', '', '', '', '', '2026-05-02 13:56:30'),
(13873, 2, 'రెల్లు', 'n', 'కాశం, ఒకజాతిదర్భ ,  జెల్లు   ఇక్ష్వాలిక, ఇషిక, గుండ్ర, గుచ్చపుష్టిక, కాండ్రేక్షువు, చామర ముష్పం, నాదేయం, లేఖనం, వాయ సేక్షుకం, శారదం, శ్వేత చామరకం', '', '', '', '', '2026-05-02 13:56:30'),
(13874, 2, 'రెవిన్యూ', 'n', 'ప్రభుత్వంవారికి దేశం మీద వచ్చే ద్రవ్యంరాబడి, పన్ను', '', '', '', '', '2026-05-02 13:56:30'),
(13875, 2, 'రెవెన్యూ', 'n', 'భూమిశిస్తు, రాబడి; చూ రెవిన్యూ', '', '', '', '', '2026-05-02 13:56:30'),
(13876, 2, 'రేకు', 'n', 'పుష్పదళం,', '', '', '', '', '2026-05-02 13:56:30'),
(13877, 2, 'రేకెత్తించు', 'v', 'చెలరేగచేయు,విజృంభింపజేయు 2 వృద్ధి పొందించు', '', '', '', '', '2026-05-02 13:56:30'),
(13878, 2, 'రేకొత్తు', 'v', 'పుష్ప దళాలువాడు, పుష్పదళాలు రాలు', '', '', '', '', '2026-05-02 13:56:30'),
(13879, 2, 'రేఖ', 'n', 'గీత, గీటు,  హస్తరేఖ, వృక్షపంక్తి, గీర, అదృష్టం, వరుస, మోసం, దారి, రీతి, వెడల్పు, లేఖ, ఆకృతి, శిఖ', '', '', '', '', '2026-05-02 13:56:30'),
(13880, 2, 'రేఖమీద రేగడి', 'n', 'బంకమన్ను ,  రేవడి', '', '', '', '', '2026-05-02 13:56:30'),
(13881, 2, 'రేగు', 'v', '1 ఎగయు, ఉబుకు, 2 దేవి  బదరీ వృక్షం   ఆమ్లం, కర్కంధువు, కంటకి, కువలి, కోలి, కోరంటి, కోలం, గూఢఫలం, ఘోరట, చండి, దృఢబీజం, పిచ్చలదళ, బదరి, యుగకంటక, స్నిగ్ధచ్చద, హస్తికోలం,విజృంభించు, కోపించు, వృద్ధినొందు,', '', '', '', '', '2026-05-02 13:56:30'),
(13882, 2, 'రేచీకటి ?', 'v', 'దేవి రాత్రివేళ కన్నులు కనిపించని ఒకజబ్బు ,  రేజీకటి', '', '', '', '', '2026-05-02 13:56:30'),
(13883, 2, 'రేచు', 'n', 'కుక్క, శునకం, వేటకుక్క, క్రి ఎగరగొట్టు, చెదరగొట్టు, పురిగొల్పు, కోపంవచ్చేట్లు చేయు', '', '', '', '', '2026-05-02 13:56:30'),
(13884, 2, 'రేడియో', 'n', 'ఆకాశవాణి', '', '', '', '', '2026-05-02 13:56:30'),
(13885, 2, 'రేడు', 'n', 'రాజు, ప్రభువు, భర్త  ,  జేడు వ్యతి', '', '', '', '', '2026-05-02 13:56:30'),
(13886, 2, 'రేణం', 'n', 'మిక్కిలి చిన్నదూడ పేడ', '', '', '', '', '2026-05-02 13:56:30'),
(13887, 2, 'రేణుక', 'n', 'జమదగ్ని భార్య,  పరశురామునితల్లి', '', '', '', '', '2026-05-02 13:56:30'),
(13888, 2, 'రేణువు', 'n', 'ఇసుక  వంటివాటి అణువు,  దుమ్ము, పుప్పొడి, స్త్రీగంధ ద్రవ్యవిశేషం', '', '', '', '', '2026-05-02 13:56:30'),
(13889, 2, 'రేతిరి', 'n', 'రాత్రి, రాతిరి', '', '', '', '', '2026-05-02 13:56:30'),
(13890, 2, 'రేపకడ', 'n', 'ప్రాతఃకాలం, వేకువ, ఉదయం ;', '', '', '', '', '2026-05-02 13:56:30'),
(13891, 2, 'రేపు', 'n', 'మరుసటిదినం, ఎల్లి, నేటి తరవాతిదినం,  ప్రాతఃకాలం, పూర్వాష్ట్రం వ్యతి', '', '', '', '', '2026-05-02 13:56:30'),
