(14262, 2, 'వక్షోత్సవాలు', 'n', '75 సంవత్సరాలు నిండిన తర్వాత చేసే ఉత్సవాలు; 25 సంలు నిండాక చేసేది \'రజతోత్సవం\', 50 సంలు నిండాక చేసేది \'స్వర్ణోత్సవం\', 75 సంలు నిండాక చేసేది \'వజోత్సవం\'', '', '', '', '', '2026-05-02 13:56:30'),
(14263, 2, 'వగచు', 'v', 'దుఃఖించు,  పశ్చాత్తాపపడు, సంశయించు, భావించు, విమర్శించు', '', '', '', '', '2026-05-02 13:56:30'),
(14264, 2, 'వగపు', 'n', 'దుఃఖం,,   కీడు, విధం', '', '', '', '', '2026-05-02 13:56:30'),
(14265, 2, 'వగరించు', 'v', 'వగరు, నిట్టూర్చు', '', '', '', '', '2026-05-02 13:56:30'),
(14266, 2, 'వగర్చు', 'v', 'నిట్టూర్చు', '', '', '', '', '2026-05-02 13:56:30'),
(14267, 2, 'వగలాడి', 'n', 'విలాసవతి, ఒయారి (వగలు+ ఆడి)', '', '', '', '', '2026-05-02 13:56:30'),
(14268, 2, 'వగలాడు', '', 'దేనివిలాస పురుషుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14269, 2, 'వగలుపోవు', 'v', 'కులు కు, విలాసం చూపు', '', '', '', '', '2026-05-02 13:56:30'),
(14270, 2, 'వగవడం', 'n', 'దుఃఖించడం', '', '', '', '', '2026-05-02 13:56:30'),
(14271, 2, 'వగైరా', 'n', 'మొదలయినవి', '', '', '', '', '2026-05-02 13:56:30'),
(14272, 2, 'వచనరచన', 'n', 'వచనం కూర్పు, మాటల కూర్పు', '', '', '', '', '2026-05-02 13:56:30'),
(14273, 2, 'వచియించు', 'v', 'చెప్పు, పలుకు, వచించు,  అను, నుడువు, వక్కాణించు, ఆడు, వినుచు, వాక్రుచ్చు, భాషించు', '', '', '', '', '2026-05-02 13:56:30');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(14274, 2, 'వచ్చు', 'v', 'ఏతెంచు, దరిచేరు,  సంభవించు, లాభించు, కలుగు, మొలచు, లభించు, చెందు, పూను, అను కూలమగు, వనన్నమగు, అలవడు, అగు, సాటి యుగు, ప్రవర్తించు, ప్రసక్తమగు, వర్థిల్లు, సమర్థమగు, సిద్దించు, స్రవించు, పొంగు, తగు, శక్యమగు, తలచు', '', '', '', '', '2026-05-02 13:56:30'),
(14275, 2, 'వజీరు', 'n', 'మంత్రి,  వజీరు, వజ్రేడు, శూరుడు, సామంతరాజు', '', '', '', '', '2026-05-02 13:56:30'),
(14276, 2, 'వజ్రం', 'n', 'నవరత్నాలలో ఒకటి అయిన వజ్రమణి, కఠినమైనది, క్రూరమైంది, పాయులై నది, అడ్డంగా ఉన్నది, వ్యూహభేదం, పిడుగు, రత్నాలకు బెజ్జంవేసే వజ్రపుసూది, పులిగంజి, బంక, ఉక్కు, అభ్రకం, పరుష భాషణం, బాలకుడు, నువ్వు పువ్వు, 27 యోగాలలో ఒకటి, ఒకవిధమైన  గట్టి సున్నం', '', '', '', '', '2026-05-02 13:56:30'),
(14277, 2, 'వటపత్రసాయి', 'n', 'విష్ణువు,  వటపత్రం (తెల్లతులసి, మర్రి ఆకు) పై శయనించువాడు', '', '', '', '', '2026-05-02 13:56:30'),
(14278, 2, 'వటబీజం', 'n', 'మర్రి విత్తనం', '', '', '', '', '2026-05-02 13:56:30'),
(14279, 2, 'వటువు', 'n', 'బ్రహ్మచారి,  బాలుడు వట్టం', '', '', '', '', '2026-05-02 13:56:30'),
(14280, 2, 'వట్టాభిషేకం', '', 'నంవిరాజులకు నొసట పట్టంగట్టి చేసే అభిషేక సంస్కారం,  యువరాజుకు పట్టం కట్టేటప్పుడు చేసే ఉత్సవ విశేషం', '', '', '', '', '2026-05-02 13:56:30'),
(14281, 2, 'వట్టి', 'n', 'శూన్యం , ఏమీలేనిది,,   ప్రయోజనంలేనిది, నిష్కారణం, శుష్కం, పాలుడిగినది', '', '', '', '', '2026-05-02 13:56:30'),
(14282, 2, 'వట్టిపోవు', 'v', 'ఎండిపోవు, వాడిపోవు', '', '', '', '', '2026-05-02 13:56:30'),
(14283, 2, 'వట్టివేరు', 'n', 'ఉశీరం, వట్టివేరు, నలదం', '', '', '', '', '2026-05-02 13:56:30'),
(14284, 2, 'వట్రువ', 'n', 'వ్యంజనంతో చేరిన ఋకారానికి గుర్తు, వర్తులం (గుండ్రం) వట్రువ, వట్రుసుడి వట్రువసుడి', '', '', '', '', '2026-05-02 13:56:30'),
(14285, 2, 'వడ', 'n', 'వేడిమి, పరితాపం,  శ్రమం, ఆకలిబాధ, దాహం, మంచు', '', '', '', '', '2026-05-02 13:56:30'),
(14286, 2, 'వడకు', 'v', 'కంపించు, కదురు  వంటి వాటిని తిప్పి దూదిని నూలుగా తీయు, వణకు, వడకు, వడుకు, నూలువడకు, మంచు', '', '', '', '', '2026-05-02 13:56:30'),
(14287, 2, 'వడగల్లు', 'n', 'వడగండ్లు, వానకురిసేటప్పుడు పడే రాళ్ళు', '', '', '', '', '2026-05-02 13:56:30'),
(14288, 2, 'వడగాలి', 'n', 'వేసవిలో పడమర నుంచి వీచే నిప్పుగాలి', '', '', '', '', '2026-05-02 13:56:30'),
(14289, 2, 'వడపప్పు', 'n', 'శ్రమ పరిహారార్థమై నానబెట్టిన పెసరపప్పు', '', '', '', '', '2026-05-02 13:56:30'),
(14290, 2, 'వడపోత', 'n', 'వడియకట్టు, వడగట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(14291, 2, 'వడముడి', 'n', 'భీముడు, శత్రువులను తపింపచేసే గ్రంథి లాంటివాడు', '', '', '', '', '2026-05-02 13:56:30'),
(14292, 2, 'వడలు', 'v', '1 పుష్పాలు వాడిపోవు, 2 మినపగారెలు', '', '', '', '', '2026-05-02 13:56:30'),
(14293, 2, 'వడి', 'n', 'వేగం,  శౌర్యం, కాలం, దారంపిరి, పురిబిగువు, పురిబిగువున పడే చిక్కు, శక్తి,తైక్ష్యం వడియపోత', '', '', '', '', '2026-05-02 13:56:30'),
(14294, 2, 'వడి పెట్టు', 'v', 'మెలి పెట్టు, నులుము', '', '', '', '', '2026-05-02 13:56:30'),
(14295, 2, 'వడిగలవాడు', 'n', 'శూరుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14296, 2, 'వడియం', 'n', 'వంటకం, భోజనంలో నంజుకొనే వ్యంజన విశేషం', '', '', '', '', '2026-05-02 13:56:30'),
(14297, 2, 'వడుగు', 'n', 'వడుగైన బాలుడు, బ్రహ్మచారి, ఉపనయనం;', '', '', '', '', '2026-05-02 13:56:30'),
(14298, 2, 'వడులు', 'n', 'వేగాలు; చూవడి,', '', '', '', '', '2026-05-02 13:56:30'),
(14299, 2, 'వడువు', 'n', 'విధం, రీతి,  బ్రహ్మచారి, కుమారుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14300, 2, 'వడ్డించు', 'v', '1 తినే పదార్థాలను పాత్రలలో పెట్టడం, 2 కర్ర  వంటి వాటితో కొట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(14301, 2, 'వడ్డి', 'n', 'అప్పిచ్చినవానికి అప్పుతీసుకున్న వాడివల్ల నెలకు నూటికి ఇంత అని పెచ్చుగా వచ్చే ధనం; ప్రకృవృద్ధి', '', '', '', '', '2026-05-02 13:56:30'),
(14302, 2, 'వడ్డికాసులస్వామి', 'n', 'వడ్డి కాసులవాడు, వేంకటేశ్వరుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14303, 2, 'వడ్డీవ్యాపారులు', '', 'మివిఅప్పులు ఇచ్చి ధనాన్ని సంపాదించేవారు', '', '', '', '', '2026-05-02 13:56:30'),
(14304, 2, 'వడ్రంగం', 'n', 'వడ్రంగిపని, కర్రపని', '', '', '', '', '2026-05-02 13:56:30'),
(14305, 2, 'వడ్రంగి', 'n', 'కర్రపనిచేసేవాడు,  వడ్లంగి; వ ర్యావడ్ల వాడు, కౌటతక్షుడు, రక్ష, త్వష్ట రథకారుడు, వర్దకి 2 వడ్రంగిపిట్ట', '', '', '', '', '2026-05-02 13:56:30'),
(14306, 2, 'వడ్లు', 'n', 'శాలిధాన్యం; అకృష్టం, తృణధాన్యం, నీవారం, నివ్వరిధాన్యం,', '', '', '', '', '2026-05-02 13:56:30'),
(14307, 2, 'వణకు', 'v', 'చలించు, కంపించు, వడకు, కంపం, భయం, మంచు', '', '', '', '', '2026-05-02 13:56:30'),
(14308, 2, 'వణిక్కు', 'n', 'వణిజుడు, వర్తకం చేసేవాడు, బేహారి, తులారాశి', '', '', '', '', '2026-05-02 13:56:30'),
(14309, 2, 'వతంసం', 'n', 'సిగబంతి;రూఅవతంసం', '', '', '', '', '2026-05-02 13:56:30'),
(14310, 2, 'వతంసుడు', 'n', 'సిగబంతి లాంటి వాడు, శ్రేష్టమైనవాడు, అవతంసుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14311, 2, 'వత్త', 'n', 'వరుగు', '', '', '', '', '2026-05-02 13:56:30'),
(14312, 2, 'వత్తాసు', 'n', 'మద్దతు,', '', '', '', '', '2026-05-02 13:56:30'),
(14313, 2, 'వత్సం', 'n', 'దూడ, శిశువు, కొడిసె చెట్టు, సంవత్సరం, కౌశాంబీపురం రాజధానిగా గల దేశం', '', '', '', '', '2026-05-02 13:56:30'),
(14314, 2, 'వత్సరం', 'n', 'ఏడాది,సంవత్సరం, పన్నెండు నెల్ల పరిమితిగల కాలం', '', '', '', '', '2026-05-02 13:56:30'),
(14315, 2, 'వదంతి', 'n', 'సంభాషణ, జనశ్రుతి, జనప్రవాదం', '', '', '', '', '2026-05-02 13:56:30'),
(14316, 2, 'వదరుబోతు', 'n', 'ఊరికే ప్రేలేవాడు, పేలరీ; జల్పాకుడు, ప్రలాపి, బహుగర్ఘ్య వాక్కు, వాచాటుడు, వాచాలుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14317, 2, 'వదలు', 'v', 'సడలు, వీడిపోవు, జారు, క్షీణించు, ఎడతెగు, త్యజించు, శిథిలం', '', '', '', '', '2026-05-02 13:56:30'),
(14318, 2, 'వదాన్య నగం', 'n', 'కల్పవృక్షం, పారిజాతం', '', '', '', '', '2026-05-02 13:56:30'),
(14319, 2, 'వదాన్యుడు', 'n', 'గొప్పదాత, వాగ్మి, మర్యాదగా మాట్లాడు వాడు, దానశీలుడు', '', '', '', '', '2026-05-02 13:56:30'),
(14320, 2, 'వది', 'n', 'జంతువులను పట్టడానికి తవ్విన గోయి, పల్లం, మరుగు, అధికం', '', '', '', '', '2026-05-02 13:56:30'),
(14321, 2, 'వదిన', 'n', 'భార్య అక్క,వదినె,,  , అన్న భార్య, తనకంటే పెద్దదైన మేనత్త, మేన మామల కూతురు', '', '', '', '', '2026-05-02 13:56:30'),
(14322, 2, 'వద్ద', 'n', 'సమీపం, ఒద్ద', '', '', '', '', '2026-05-02 13:56:30'),
(14323, 2, 'వద్దు', 'v', 'అక్కరలేదు,  \'వలయు\' ధాతువు  వ్యతిరేకార్థక రూపం ఇది సామాన్యంగా అన్నంత క్రియలకు అను ప్రయుక్తమై కానవస్తున్నది ఉదా', '', '', '', '', '2026-05-02 13:56:30'),
(14324, 2, 'వధ', 'n', 'చంపడం, హత్య,వధం,  దెబ్బ, పక్షవాతం, అంతర్ధానం, కూడిక', '', '', '', '', '2026-05-02 13:56:30'),
(14325, 2, 'వధించు', 'v', 'చంపు', '', '', '', '', '2026-05-02 13:56:30'),
(14326, 2, 'వధువు', 'n', 'పెళ్ళికూతురు,  ఆడది, కోడలు, పెళ్ళాం, సంపంగి మొగ్గ, పిక్కచెట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(14327, 2, 'వధూటి', 'n', 'స్త్రీ, ఆడది,   కన్యక, కోడలు', '', '', '', '', '2026-05-02 13:56:30'),
(14328, 2, 'వధూవరులు', 'n', 'పెళ్ళికూతురు, పెళ్ళి కొడుకు', '', '', '', '', '2026-05-02 13:56:30'),
