(14605, 2, 'వికటం', 'n', 'వికృతమైనది, భయంకరమైనది, పెద్దది, గర్వంకలది, సుందరమైనది, ముఖం చిట్టించుకునేది, గూఢమైనది, మారిన ఆకారం కలది, మిట్టపల్లాలు కలది, కురుపు', '', '', '', '', '2026-05-02 13:56:30'),
(14606, 2, 'వికటకవి', 'n', 'హాస్యకవి, హాస్యకరుడు, వరిహాసం కోసం వికటంగా మాట్లాడేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(14607, 2, 'వికటించు', 'v', 'ప్రతికూలించు', '', '', '', '', '2026-05-02 13:56:30'),
(14608, 2, 'వికలం', 'n', 'కలత నొందినది, లోపం కలది, శూన్యమైనది, బెదరినది, నిరుపయోగం, తప్పినది, క్షీణించినది', '', '', '', '', '2026-05-02 13:56:30'),
(14609, 2, 'వికలాంగులు', 'n', 'అవయవ లోపం ఉన్నవారు, 1 వికలమైన అవయవాలు గలవారు, 2 వికారమైన అవయవాలు గలవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(14610, 2, 'వికల్పం', 'n', 'విచికిత్స, సంశయం, ఊహ, కల్పనం, విధం, అజ్ఞానం, తారతమ్యం', '', '', '', '', '2026-05-02 13:56:30'),
(14611, 2, 'వికవిక', '', 'దేవినవ్వే ధ్వనికి అనుకరణం', '', '', '', '', '2026-05-02 13:56:30'),
