(14629, 2, 'విఘటించు', 'v', 'చెడు, తప్పిపోవు విఘాతం; n అడ్డంకి, విఘ్నం,   నాశం, చంపడం, పెద్ద దెబ్బ, త్యాగం', '', '', '', '', '2026-05-02 13:56:30'),
(14630, 2, 'విఘ్నం', 'n', 'ఆటంకం, అంతరాయం, శ్రమం, కలివెచెట్టు', '', '', '', '', '2026-05-02 13:56:30'),
(14631, 2, 'విఘ్నేశ్వరుడు', 'n', 'గణపతి, ఈశ్వరుని పుత్రుడు, విఘ్నాలకు ప్రభువు; వినాయకుడు, ద్వైమాతురుడు, గణాధిపుడు, ఏకదంతుడు, హేరంబుడు, లంబోదరుడు, గజా ననుడు, ఇద్దరు తల్లుల ముద్దు బిడ్డడు, పని చెరుపుల దొర, చేట చెవుల వేల్పు, వంకర తొండం వాడు, ఏనుగు మొగంబు దేవర, పాప జందెముల మేటి, గరిక పూజల మెచ్చు గబ్బి వేలు, మొక్కు వారల పనుల్ చక్కజేసెడు సామి, పెద్ద కడుపు వేల్పు, పిళ్ళారి, గుజ్జు వేలు, వెనకయ్య  వంటి', '', '', '', '', '2026-05-02 13:56:30'),
(14632, 2, 'విచక్షణ', 'n', 'వివేకం, సూక్ష్మదృష్టి విమర్శ', '', '', '', '', '2026-05-02 13:56:30'),
(14633, 2, 'విచక్షణుడు', 'n', 'విద్వాంసుడు, విశేషంగా పలికేవాడు, వివేక శాలి, బుద్ధిమంతుడు, నిపుణుడు, చదువరి', '', '', '', '', '2026-05-02 13:56:30'),
