(14635, 2, 'విచారణ', 'n', 'పరీక్ష, పరిశోధనం,  ఆలోచన, నంశయం, మీమాంసా శాస్త్రం', '', '', '', '', '2026-05-02 13:56:30'),
(14636, 2, 'విచారించు', 'v', 'పరామర్శించు,  పరిశీలించు, ఆలోచించు చికిత్స', '', '', '', '', '2026-05-02 13:56:30'),
(14637, 2, 'విచిత్రం', 'n', 'ఆశ్చర్యం, ఏంత; నాసా,  వర్ణాలు కలది, వివిధం, మనోహరం', '', '', '', '', '2026-05-02 13:56:30'),
(14638, 2, 'విచ్చలవిడి', 'n', 'స్వేచ్ఛ, ఇష్టం వచ్చినట్లు,  స్వాతంత్ర్యం, నిరాటంకంగా', '', '', '', '', '2026-05-02 13:56:30'),
