(14677, 2, 'వితండవాదం', 'n', 'అడ్డదిడ్డపువాదం, స్వపక్షస్థాపనం  /  పరపక్షాన్ని ఖండించే వాదం, వితండవాదం, స్వవక్ష పాతంగా వాదించే మూర్ఖనాదం', '', '', '', '', '2026-05-02 13:56:30'),
(14678, 2, 'వితంతువు', 'n', 'విధవ, ముండమోపి, మంచిగుర్రం, మంగళసూత్రం లేనిది', '', '', '', '', '2026-05-02 13:56:30'),
(14679, 2, 'వితతి', 'n', 'సమూహం, గుంపు,  వ్యాప్తి, పంక్తి', '', '', '', '', '2026-05-02 13:56:30'),
