(14682, 2, 'వితర్కం', 'n', 'యుక్తులతో ఆలోచించడం, ఊహ, తలంపు, సంశయం, • పర్యా లోచనం', '', '', '', '', '2026-05-02 13:56:30'),
(14683, 2, 'వితర్థి', 'n', 'వేదిక, వితర్దిక', '', '', '', '', '2026-05-02 13:56:30'),
(14684, 2, 'వితాకు', 'n', 'పరాకు, సంతాపం, పారవశ్యం, నిశ్చేష్టత', '', '', '', '', '2026-05-02 13:56:30'),
