(14689, 2, 'విదగుడు', '', 'నంవివండితుడు, విద్వాంసుడు, నేర్పరి, కపటియైనవాడు, పొగరుబోతు', '', '', '', '', '2026-05-02 13:56:30'),
(14690, 2, 'విదల్చు', 'v', 'దులుపు, ఇచ్చు, చలింప చేయు, ప్రచురింప చేయు, ఇచ్చు, తొలగించు, జాడించు, విదలించు', '', '', '', '', '2026-05-02 13:56:30'),
(14691, 2, 'విదారకం', 'n', 'చీల్చేది, విభజించేది,  చెలమ, ఆనకట్ట, చవుటినేల', '', '', '', '', '2026-05-02 13:56:30'),
