(14698, 2, 'విదుషీమణి', 'n', 'విద్వాంసురాలు, శ్రేష్ఠురాలు, పాండిత్యం ఉన్న వ్యక్తి', '', '', '', '', '2026-05-02 13:56:30'),
(14699, 2, 'విదూషకుడు', 'n', 'శృంగార నాయక సహాయకుడు,  సచివులలో ఒకడై వరిపోనం కోనం ఇతరులను విశేషంగాను, చమత్కారం గాను దూషించేవాడు, పాడుచేసేవాడు, దూషించే వాడు, చమత్కారి, శృంగార నాయక సహాయకుడు', '', '', '', '', '2026-05-02 13:56:30'),
