(14716, 2, 'విద్వాంసుడు', 'v', 'సంవిణతెలిసినవాడు, పండితుడు వి పశ్చిత్తు, విదుడు, దోషజ్ఞుడు, సుధా, కోవిదుడు, బుధుడు, ధీరుడు, మనీషి, ప్రాజ్ఞుడు, సంఖ్యా వంతుడు, కవి, ధీమంతుడు, సూరి, కృతి, కృషి లబ్దవర్ణుడు, విచక్షణుడు, దూరదర్ని', '', '', '', '', '2026-05-02 13:56:30'),
(14717, 2, 'విధం', 'n', 'రకం, రీతి, జీవం, ఏనుగు, కబళం, ఉపాయం , వ్యథ, సృష్టి', '', '', '', '', '2026-05-02 13:56:30'),
(14718, 2, 'విధవ', 'n', 'ముండమోపి, పూర్వ సువాసిని, పోయిన ధవుడు (భర్త) కలది', '', '', '', '', '2026-05-02 13:56:30'),
(14719, 2, 'విధాత', 'n', 'బ్రహ్మ, దైవం, ధాత, దైవం, విశ్వకర్మ, మన్మథుడు, అధర్మం', '', '', '', '', '2026-05-02 13:56:30'),
(14720, 2, 'విధాతృడు', 'n', 'బ్రహ్మదేవుడు, సర్వాన్ని సృజించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(14721, 2, 'విధానం', 'n', 'ఏర్పాటు, ఆచరించడం, ఆచరించడం, సృష్టి, ఉపయోగం, శాసనం, శాస్త్ర విధి, శాస్త్ర విహిత కర్మానుష్టానం, పద్దతి, సొధనం, సంస్కారం, లాభం, గజకబళం, ధనం, బాధ, విరోధకార్యం', '', '', '', '', '2026-05-02 13:56:30'),
(14722, 2, 'విధాలు కలది వివేకం', 'n', 'దేహాత్మాది విభేద జ్ఞానం, విభేదం, విచారం', '', '', '', '', '2026-05-02 13:56:30'),
(14723, 2, 'విధించు', 'v', 'చేయు, నియమించు', '', '', '', '', '2026-05-02 13:56:30'),
(14724, 2, 'విధి', 'n', 'ఆచరించడం, పని, ఆజ్ఞ, ధాత, కాలం, ఏర్పాటు, భాగ్యం, విధం, ఆధారం, నిబంధనం, ఆజ్ఞ, మత విషయకమైన కర్మ, స్థితి, నడవడి, సృష్టించేవాడు, అదృష్టహీనత', '', '', '', '', '2026-05-02 13:56:30'),
(14725, 2, 'విధి /', '', 'మివిణతప్పని పరిస్థితులలో,', '', '', '', '', '2026-05-02 13:56:30'),
