(15077, 2, 'వేణి', 'n', 'సొగసుగా అల్లిన జడ, వేలాడేజుట్టు, ప్రవాహం, ప్రయాగ క్షేత్రం', '', '', '', '', '2026-05-02 13:56:30'),
(15078, 2, 'వేణీ సంహారం', 'n', 'జుట్టు జడగా అల్లడం, జుట్టు ముడి వేయడం, భట్టనారాయణుడు రచించిన • సంస్కృత నాటకం', '', '', '', '', '2026-05-02 13:56:30'),
(15079, 2, 'వేణు', '', 'తమి కావాలి', '', '', '', '', '2026-05-02 13:56:30'),
