(15087, 2, 'వేదవిదుడు', 'n', 'వేదవేత్త, వేదాలు బాగా తెలిసిన వాడు, విష్ణువు', '', '', '', '', '2026-05-02 13:56:30'),
(15088, 2, 'వేదవ్యాసుడు', 'n', 'పరాశరునివల్ల సత్యవతికి పుట్టిన మహర్షి ,వేదాలను విభాగంచేసి లోకవ్యాప్తి చేసిన ముని', '', '', '', '', '2026-05-02 13:56:30'),
