(15119, 2, 'వేషం', 'n', 'వస్త్రభూషణాది అలంకారం, ఇతరుల ఆకార చేష్టలను తనమీద ఆరోపించుకోవడం', '', '', '', '', '2026-05-02 13:56:30'),
