(15122, 2, 'వేసారు', 'v', 'విసుగుచెందు, వేసరు, శ్రమపడు, బాధపడు, విచారం పొందు', '', '', '', '', '2026-05-02 13:56:30'),
(15123, 2, 'వైకల్పికం', 'n', 'వికల్పంగా ప్రాప్తించేది, రెండర్థాలు కలది, నిశ్చితంకానిది', '', '', '', '', '2026-05-02 13:56:30'),
