INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(15128, 2, 'వైఖరి', 'n', '1 రీతి, పద్దతి, 2 అర్థ బోధకమైన కంఠాది స్థానాలలో ఉచ్చరింపబడే ద్వని విశేషం; వ్యు', '', '', '', '', '2026-05-02 13:56:30'),
(15129, 2, 'వైఖానసుడు', '', 'వైఖానస పద్ధతిలో విష్ణ్వాలయంలో పూజచేసే అర్చకుడు, నంబి, వానప్రస్థులలో ఒక తెగవాడు, విష్ణు దేవాలయంలోని అర్చకుడు,  వానప్రస్థుడు,', '', '', '', '', '2026-05-02 13:56:30'),
(15130, 2, 'వైచిత్రి', 'n', 'విచిత్రత, వింత, విశేషం,,  రూప త్వం, కొత్తదనం, మనసుకు నాటడం, అద్భుతం', '', '', '', '', '2026-05-02 13:56:30'),
(15131, 2, 'వైజయంతి', 'n', 'ధ్వజం, జెండా; టెక్కం, పతాక, పూలదండ,వనమాల', '', '', '', '', '2026-05-02 13:56:30'),
(15132, 2, 'వైజ్ఞానిక', 'n', 'విజ్ఞాన సంబంధమైన శాస్త్ర సంబంధమైన', '', '', '', '', '2026-05-02 13:56:30'),
(15133, 2, 'వైజ్ఞానికుడు', 'n', 'నేర్పరి, నిపుణుడు వైడూర్యం', '', '', '', '', '2026-05-02 13:56:30'),
(15134, 2, 'వైణవికుడు', 'n', 'వేణువు వాయించేవాడు, పిల్లనగ్రోవి ఊదేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15135, 2, 'వైణికుడు', 'n', 'వీణవాయించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
