(15137, 2, 'వైతాళికుడు', 'n', 'స్తోత్రపాఠకుడు,వ్యు', '', '', '', '', '2026-05-02 13:56:30'),
(15138, 2, 'వైదగ్యం', 'n', 'నేర్పు, నైపుణ్యం,  చక్కదనం, ఉపాయం , చమత్కారం', '', '', '', '', '2026-05-02 13:56:30'),
(15139, 2, 'వైదరి', 'n', 'రుక్మిణి, విదర్భ రాజైన భీముని కూతురు, దమయంతి,లోపాముద్ర, కావ్యరచనా భేదం(రీతి)', '', '', '', '', '2026-05-02 13:56:30'),
(15140, 2, 'వైదికమతం', '', 'నంవివేదమార్గాన్ని అనుసరించే మతం', '', '', '', '', '2026-05-02 13:56:30'),
