(15511, 2, 'శ్లేష్మం', 'n', 'కఫం;', '', '', '', '', '2026-05-02 13:56:30'),
(15512, 2, 'శ్లోకం', 'n', 'నాలుగు పాదాలు కలిగిన ఛందోబద్దమైన వాక్యవిశేషం,  అనుష్టుప్చందస్సు, సూక్తి, వృత్తం, సమాఖ్య, కీర్తి, పొగడ, లోకోక్తి', '', '', '', '', '2026-05-02 13:56:30'),
(15513, 2, 'శ్వానం', 'n', 'కుక్క  ఇటు అటు తిరిగేది', '', '', '', '', '2026-05-02 13:56:30'),
(15514, 2, 'శ్వాస', 'n', 'ఊపిరి;,  శ్వాసం,  నిట్టూర్పు, గాలి, ఉబ్బసం, వర్లోచ్చారణ కోసం చేసే బాహ్య ప్రయత్నాలలో ఒకటి', '', '', '', '', '2026-05-02 13:56:30'),
(15515, 2, 'శ్వేతం', 'n', 'తెలనిది, వెండి', '', '', '', '', '2026-05-02 13:56:30'),
(15516, 2, 'శ్వేత వాహనుడు', 'n', 'అర్జునుడు  తెల్లటి గుర్రాలు వాహనంగా కలవాడు,  అర్జునుడు, చంద్రుడు, ఇంద్రుడు', '', '', '', '', '2026-05-02 13:56:30'),
(15517, 2, 'శ్వేతద్వీపం', 'n', '1 18 ద్వీపాల్లో ఒకటి; 2 విష్ణు దేవుని నివాసమైన వైకుంఠం;', '', '', '', '', '2026-05-02 13:56:30'),
(15518, 2, 'శ్వేతముఖులు', 'n', 'తెల్లదొరలు;', '', '', '', '', '2026-05-02 13:56:30'),
(15519, 2, 'సంకటి', 'n', 'వండిన రాగి పిండి  వంటిచిక్కని కాచిన అంబలితోవ, పిష్టవిశేషం', '', '', '', '', '2026-05-02 13:56:30'),
(15520, 2, 'సంకర్షణుడు', 'n', 'బలరాముడు;వ్వు శత్రువులను, ప్రళయంలోజనులను సంహరించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15521, 2, 'సంకలనం', 'n', 'సమ కూర్చడం,చేర్చడం, కలపడం,సంకలన, సంకలం,  పోగుచేయడం, సంబంధం, సంముట్టనం, కూడ బెట్టడం, సమకూర్చడం', '', '', '', '', '2026-05-02 13:56:30'),
(15522, 2, 'సంకలిత', 'n', 'కూడిన', '', '', '', '', '2026-05-02 13:56:30'),
(15523, 2, 'సంకల్పం', 'n', 'ఆలోచన, తలంపు, భావన, మనోనిశ్చయం, లక్ష్యం, అభిప్రాయం , కోరిక, భావన, మనస్సు, ప్రతిజ్ఞ, ఫలనిరీక్షణం', '', '', '', '', '2026-05-02 13:56:30'),
(15524, 2, 'సంకాశం', 'n', 'సమానమైనది,  పోలినది సంకీర్ణం', '', '', '', '', '2026-05-02 13:56:30'),
(15525, 2, 'సంకీర్ణ సమయం', 'n', 'కఠిన సమయం ,, విధాల సమయం', '', '', '', '', '2026-05-02 13:56:30'),
(15526, 2, 'సంకీర్తనం', 'n', 'దేవతా గుణాలను గానం చేయడం,  స్తోత్రం చేయడం, భగవన్నామం పలుమారు ఉచ్చరించడం', '', '', '', '', '2026-05-02 13:56:30'),
(15527, 2, 'సంకు', 'n', 'శంఖం, శంఖవలయం,అంచు; ప్రకృశంఖం', '', '', '', '', '2026-05-02 13:56:30'),
(15528, 2, 'సంకుచిత', 'n', 'ముడుచుకొన్నది,తగ్గినది', '', '', '', '', '2026-05-02 13:56:30'),
(15529, 2, 'సంకుల సమరం', 'n', 'విస్తరించిన  యుద్దం, ఒకరితో ఒకరు ఒరుసుకునే యుద్ధం', '', '', '', '', '2026-05-02 13:56:30'),
(15530, 2, 'సంకేతం', 'n', 'గుర్తు, చిహ్నం, సన్న,  పేరు, ఒడబాటు, సంజ్ఞ, ముందుగా మాట్లాడుకొని నిష్కర్ష చేసుకున్న స్థలం, ఏర్పాటు', '', '', '', '', '2026-05-02 13:56:30');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(15531, 2, 'సంకోచం', 'n', 'ముడుచుకోవడం,  కుంకుమ పువ్వు, సంక్షేపం, ముకుళ భావం, చేపబంధం, బిడియం, సంశయం', '', '', '', '', '2026-05-02 13:56:30'),
(15532, 2, 'సంకోచించు', 'v', 'వెనుదీయు, జంకు, సంకుచితం చేయు, అనుమానించు', '', '', '', '', '2026-05-02 13:56:30'),
(15533, 2, 'సంక్తివం', 'n', 'సంగ్రహం,సంక్షేపింపబడినది', '', '', '', '', '2026-05-02 13:56:30'),
(15534, 2, 'సంక్రందనుడు', 'n', 'ఇంద్రుడు ,శత్రు వును అక్రందనం (మొర)పెట్టించేవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15535, 2, 'సంక్రమించు', 'v', 'ప్రాప్తించు,ప్రవేశించు, కలయు, దాటు, కలసివచ్చు, చెందు', '', '', '', '', '2026-05-02 13:56:30'),
(15536, 2, 'సంక్రాంతి', 'n', 'మకర సంక్రమణం ,సూర్యుడు మేషాది రాసులలో ఒక రాశి నుంచి మరొక రాశికి ప్రవేశించడం;,  కలయిక, ఒక అంశం నుంచి మరొక అంశానికి పోవడం, ఇతరులకిచ్చి వేయడం, ప్రతిబింబం, చిత్రం, బోధనా శక్తి', '', '', '', '', '2026-05-02 13:56:30'),
(15537, 2, 'సంక్లిష్టం', 'n', 'కష్టంతో కూడినది,  గాయపడినది, నలగకొట్ట బడినది, కాంతి చేడినది', '', '', '', '', '2026-05-02 13:56:30'),
(15538, 2, 'సంక్షేమం', 'n', 'మంచి, మేలు, శుభం', '', '', '', '', '2026-05-02 13:56:30'),
(15539, 2, 'సంక్షోభం', '', 'నంవినంచలనం,కలవరపాటు, కంప, వ్యత్యస్తం కావడం, గర్వం', '', '', '', '', '2026-05-02 13:56:30'),
(15540, 2, 'సంఖ్యాపురాణం', 'n', 'లెక్కకలపడం', '', '', '', '', '2026-05-02 13:56:30'),
(15541, 2, 'సంఖ్యావాచకం', 'n', 'సంఖ్యను తెలిపేది, సంఖ్యను తెలిపే పదం', '', '', '', '', '2026-05-02 13:56:30'),
(15542, 2, 'సంగం', 'n', 'మైత్రి, కలయిక;', '', '', '', '', '2026-05-02 13:56:30'),
(15543, 2, 'సంగడీడు', 'n', 'స్నేహితుడు, చెలికాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15544, 2, 'సంగతి', 'n', 'విషయం, సహవాసం;++విధం, సంసర్గం, ఔచిత్యం, దర్శనం, దైవికంగా తటస్థించడం, జ్ఞానం, విశేష జ్ఞానం కోసం ప్రశ్నించడం', '', '', '', '', '2026-05-02 13:56:30'),
(15545, 2, 'సంగమం', 'n', 'సంయోగం, కలియడం; సమీపించడం, కూడిక, చేరిక, అనురాగం, పోట్లాట, సాంగత్యం, నదులు కలిసే చోటు, స్నేహితుల గుంపు', '', '', '', '', '2026-05-02 13:56:30'),
(15546, 2, 'సంగరం', 'n', 'యుద్ధం, బుద్ది, విషం, అంగీకారం, ప్రతిజ్ఞ, ఆపద', '', '', '', '', '2026-05-02 13:56:30'),
(15547, 2, 'సంగాతకాడు', 'n', 'చెలికాడు, మిత్రుడు సంగీతం', '', '', '', '', '2026-05-02 13:56:30'),
(15548, 2, 'సంగ్రహం', 'n', 'సంక్షిప్తం', '', '', '', '', '2026-05-02 13:56:30'),
(15549, 2, 'సంగ్రామం', 'n', 'యుద్ధం', '', '', '', '', '2026-05-02 13:56:30'),
(15550, 2, 'సంఘం', 'n', 'ప్రాణిసమూహం, గుమి, గుంపు, సన్నిహిత సంబంధం, సమాజం', '', '', '', '', '2026-05-02 13:56:30'),
(15551, 2, 'సంఘజీవి', 'n', 'కలిసి జీవించేవాడు; కూలివాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15552, 2, 'సంఘటన', 'n', 'సంయోగం, కూర్పు', '', '', '', '', '2026-05-02 13:56:30'),
(15553, 2, 'సంఘసంస్కర్త', '', 'సంవిణసంఘాన్ని సంస్కరించినవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15554, 2, 'సంచకరువు', 'n', 'బయానా, అడ్వాన్సు;,  సంచకర్వు, సంచకరు, సంచేకరం, సంచే కరువు, సంచకారం,క్రయ, విక్రయా దులకు పూర్వం బేరం స్థిరత్వానికై ఇచ్చే ధనం', '', '', '', '', '2026-05-02 13:56:30'),
(15555, 2, 'సంచయం', '', 'కూడబెట్టడం, నిలువ చేయడం, రాశి, మొత్తం సముదాయంపేరు, కూడబెట్టడం', '', '', '', '', '2026-05-02 13:56:30'),
(15556, 2, 'సంచలనం', 'n', 'కదలిక,  క్షోభం, వడకు, కలవరపాటు', '', '', '', '', '2026-05-02 13:56:30'),
(15557, 2, 'సంచలనాత్మక', 'n', 'కదలికతో కూడిన', '', '', '', '', '2026-05-02 13:56:30'),
(15558, 2, 'సంచారం', 'n', 'గమనం, తిరగడం,  ఒక చోటనుంచి మరో చోటికి మారడం, దారి, కష్టప్రయాణం, కష్టం, పురికొల్పడం, సహాయం చేయడం, తోవచూపడం, పాము పడగమీది మణి, సూర్యుడొక రాశి నుంచి మరో రాశిలో ప్రవేశించడం', '', '', '', '', '2026-05-02 13:56:30'),
(15559, 2, 'సంచార వైద్యశాల', '', 'నంవితిరిగే ఆసుపత్రి', '', '', '', '', '2026-05-02 13:56:30'),
(15560, 2, 'సంచి', 'n', 'గుడ్డలు  వంటి వాటితో కుట్టిన తిత్తి, సంచీ, గోతం; అసిమి గోనె, గోణి, జోలె, పట్టా', '', '', '', '', '2026-05-02 13:56:30'),
(15561, 2, 'సంజ', 'n', 'సంధ్యాకాలం; ప్రకృసంధ్య', '', '', '', '', '2026-05-02 13:56:30'),
(15562, 2, 'సంజయుడు', 'n', 'ధృతరాష్ట్రుని  ఆంతరంగిక భృత్యుడు;వివసంజయుడు వ్యాసమహర్షి వరం వల్ల యుద్ధసమాచారాలన్నింటినీ గ్రహించి జాత్యంధుడైన ధృత రాష్ట్రునికి తెలుపుతూ ఉండేవాడు కురు పాండవులకు సంధి చేయడానికి ఇతడు రాయబారం జరిపాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15563, 2, 'సంజాయిషీ', '', 'హింవిసమాధానం', '', '', '', '', '2026-05-02 13:56:30'),
(15564, 2, 'సంజీవని', 'n', 'చచ్చినవారిని బతికించే ఒక ఓషధి, సంజీవకరణి,  బతికించడం, ఆహారం, కాళిదాస కావ్యత్రయానికి మల్లినాధుడు వ్రాసిన వ్యాఖ్య పేరు', '', '', '', '', '2026-05-02 13:56:30'),
(15565, 2, 'సంజ్ఞ', 'n', 'హస్త చాలనాదులచేత అర్థాన్ని సూచించడం, చైతన్యం, బుద్ది, జ్ఞానం, సన్న, పేరు,', '', '', '', '', '2026-05-02 13:56:30'),
(15566, 2, 'సంత', '', 'ప్రదీప్తమై ఉండేదో అనిపించక మానదు సంతకం', '', '', '', '', '2026-05-02 13:56:30'),
(15567, 2, 'సంతతం', '', 'సంక్రివిణఎల్లప్పుడు, వ్యాపింపచేయబడినది, ఎడ తెగనిది, శాశ్వతమైనది, అధికమైనది', '', '', '', '', '2026-05-02 13:56:30'),
(15568, 2, 'సంతతి', 'n', 'సంతానం, అపత్యం', '', '', '', '', '2026-05-02 13:56:30'),
(15569, 2, 'సంతప్తుడు', 'n', 'ఎక్కువ బాధపడిన వాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15570, 2, 'సంతరించుకొను', 'v', 'చక్కబరచుకొను, సంపాదించుకొను', '', '', '', '', '2026-05-02 13:56:30'),
(15571, 2, 'సంతర్పణ', 'n', 'తృప్తి, తృప్తిపరచడం;రూసంతర్పణం, విందు,  ఆమెత (విందు), ఉల్లాస పరచడం, ఒక భక్ష్య విశేషం', '', '', '', '', '2026-05-02 13:56:30'),
(15572, 2, 'సంతసం', 'n', 'సంతోషం, ఆనందం,', '', '', '', '', '2026-05-02 13:56:30'),
(15573, 2, 'సంతానం', 'n', 'అపత్యం, సంతతి, ఒక కల్పవృక్షం, లెస్సగా కోరికలను తీర్చేది,  బిడ్డ, కులం, పౌత్ర పారంపర్యం', '', '', '', '', '2026-05-02 13:56:30'),
(15574, 2, 'సంతాపం', 'n', 'చనువుతో ఒకరితో ఒకరు మాట్లాడు కోవడం; వ్యు', '', '', '', '', '2026-05-02 13:56:30'),
