(15893, 2, 'సమ్రాట్టు', 'n', 'చక్రవర్తి, దిగ్విజయం చేసి రాజసూయం చేసినవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15894, 2, 'సయితం', '', 'వైఅవ్యకూడా, సైతం', '', '', '', '', '2026-05-02 13:56:30'),
(15895, 2, 'సయ్యాట', 'n', 'పరిహాసం,సయాట,', '', '', '', '', '2026-05-02 13:56:30'),
(15896, 2, 'సయ్యొద్ద', 'n', 'చేరిక,సయ్యోద్దె, సయోధ్య', '', '', '', '', '2026-05-02 13:56:30'),
(15897, 2, 'సరం', 'n', 'దండ, హారం, నీరు,స్వరం, మాంసం, గమనం, చెరువు, సెలయేరు, బాణం, ఉప్పు, మీగడ,ముక్కుగాలి', '', '', '', '', '2026-05-02 13:56:30'),
(15898, 2, 'సరంగు', 'n', 'నావికుడు సరకు', '', '', '', '', '2026-05-02 13:56:30'),
(15899, 2, 'సరకు సేయు', 'v', 'లెక్కచేయు,లక్ష్య పెట్టు, గణించు, ప్రేమించు', '', '', '', '', '2026-05-02 13:56:30'),
(15900, 2, 'సరటం', 'n', 'బల్లి, తొండ, వాయువు', '', '', '', '', '2026-05-02 13:56:30'),
(15901, 2, 'సరణి', 'n', 'మార్గం, విధం, రుజురేఖ, తిన్ననిగీత, ఒక విధమైన కంద రోగం', '', '', '', '', '2026-05-02 13:56:30'),
(15902, 2, 'సరత్', 'n', 'ప్రవహిస్తూ ఉన్న', '', '', '', '', '2026-05-02 13:56:30'),
(15903, 2, 'సరదా', 'n', 'వినోదం, విలాసం', '', '', '', '', '2026-05-02 13:56:30'),
(15904, 2, 'సరదారు', 'n', 'నాయ కుడు,ప్రధానోద్యోగి, సర్దారు', '', '', '', '', '2026-05-02 13:56:30'),
(15905, 2, 'సరఫరా', 'n', 'కావలసిన వాటిని సంపాదించడం', '', '', '', '', '2026-05-02 13:56:30'),
(15906, 2, 'సరభసం', 'n', 'వేగంతో కూడినది, ఉగ్రమైనది, ఉద్రిక్తమైనది, హర్షం గలది', '', '', '', '', '2026-05-02 13:56:30'),
(15907, 2, 'సరళం', 'n', 'వక్రంకానిది, తిన్నని,  ఋజువైన, సహజమైన, అగ్ని, దేవదారు వృక్షం, గకారాది వర్గ తృతీయాక్షరం, పూరికాష్ఠం', '', '', '', '', '2026-05-02 13:56:30'),
(15908, 2, 'సరళాలు', 'n', 'గ, జ, డ, ద, బ అనే అక్షరాలు, మృదూచ్చారణ ఉండే అక్షరాలు', '', '', '', '', '2026-05-02 13:56:30'),
(15909, 2, 'సరళి', 'n', 'విధానం, విధం, కలయికలు ఉన్న సప్తస్వరాల (సరిగమపదని) గ్రామం', '', '', '', '', '2026-05-02 13:56:30'),
(15910, 2, 'సరసం', 'n', 'పరిహాసం, సయ్యాట,  రసంతో కూడినది, రుచిగలది, తడి గలది, చెమటచే తడియైనది, భావపూర్ణమైనది, ప్రేమగలది,', '', '', '', '', '2026-05-02 13:56:30'),
(15911, 2, 'సరస రచయిత్రి', 'n', 'భావపూర్ణమైన రచయిత్రి, సరసమైన రచయిత్రి', '', '', '', '', '2026-05-02 13:56:30'),
(15912, 2, 'సరసన', 'n', 'పక్కన, ఆసనార్థంలో వరసన', '', '', '', '', '2026-05-02 13:56:30'),
(15913, 2, 'సరసర', 'n', 'శీఘ్రం , చరచర,  గమనాదుల ధ్వనికి అనుకరణం, మిక్కిలి వేగంగా', '', '', '', '', '2026-05-02 13:56:30'),
(15914, 2, 'సరసి', 'n', 'క్రమం, వరుస, తీరు,అందం నరసజ్ఞుడు', '', '', '', '', '2026-05-02 13:56:30'),
(15915, 2, 'సరసీవనం', 'n', 'సరస్సు(లోని) నీరు, సరస్సు కలిగిన అడవి', '', '', '', '', '2026-05-02 13:56:30'),
(15916, 2, 'సరసుడు', 'n', 'రసికుడు, రసజ్ఞుడు, భావ పూర్ణుడు', '', '', '', '', '2026-05-02 13:56:30'),
(15917, 2, 'సరస్వతి', 'n', 'వాగ్గేవత, పలుకు చెలి , అంతటా వ్యాపించి ఉండేది, బ్రహ్మలోకంలో బ్రహ్మ సరస్సును ఆశ్రయించి నదీరూపంగా', '', '', '', '', '2026-05-02 13:56:30'),
(15918, 2, 'సరాగం', 'n', 'ఆనుకూల్యం, ఒద్దిక, ఒప్పిదం, రాగంతో కూడినది, రంగుకలది, రక్తవర్ణం కలది సరాసరి', '', '', '', '', '2026-05-02 13:56:30'),
(15919, 2, 'సరి', 'n', 'సాటి, తగినది, హారం,  యుక్తు, సమం, సమాప్తం, అంగీకారార్థం, పూర్ణంగా, మిట్టపల్లాలు లేనిది, సమాన సంఖ్య, రుజువు, సాటి, నీటిబుగ్గ,పోలిక, సమర్థతగలవాడు', '', '', '', '', '2026-05-02 13:56:30'),
(15920, 2, 'సరిత్తు', 'n', 'నది, ఏరు, సూత్రం; తటిని, ధుని', '', '', '', '', '2026-05-02 13:56:30'),
(15921, 2, 'సరిహద్దు', 'n', 'పొలిమేర', '', '', '', '', '2026-05-02 13:56:30'),
(15922, 2, 'సరీసృపం', 'n', 'పాము, వక్రంగా పోయేది', '', '', '', '', '2026-05-02 13:56:30'),
(15923, 2, 'సర్కసు', 'n', 'జెట్టీలు గుర్రాలు  వంటిజంతువుల మీద మొగ్గలు  వంటి విద్యలు చేసే స్థలం', '', '', '', '', '2026-05-02 13:56:30'),
(15924, 2, 'సర్కారు', 'n', 'ప్రభుత్వం,సరకారు', '', '', '', '', '2026-05-02 13:56:30'),
(15925, 2, 'సర్గం', 'n', 'సృష్టి,   పరిచ్చేదం, నిజం, ప్రయత్నం, యుక్తి, స్వభావం,వదలడం, నిశ్చయం, అంగీకారం,  అధ్యాయం, మూర్చ, అశ్వం', '', '', '', '', '2026-05-02 13:56:30'),
(15926, 2, 'సర్డు', 'n', 'సరుదు, సవరించు సర్దుకుపోవడం', '', '', '', '', '2026-05-02 13:56:30'),
(15927, 2, 'సర్దారుడు', 'n', 'నాయకుడు', '', '', '', '', '2026-05-02 13:56:30'),
(15928, 2, 'సర్దుబాటు', 'v', 'సరిపుచ్చుకొను,పరిష్కరించు, దిద్దుబాటు', '', '', '', '', '2026-05-02 13:56:30'),
(15929, 2, 'సర్పం', 'n', 'పాము, వక్రగమనం కలది;ప్పదాకువు, భుజంగం, భుజగం, భుజంగమం, ఆశీవిషం విషధరం, చక్రి, వ్యాళం, సరీసృపం, కుండలి, గూఢపం, చక్షుశ్రవం, కాకోదరం, ఫణి, దర్వీకరం, దీరప్పష్టం, దందశూకం, బిలేశయం, ఉరగం, పన్నగం, భోగి, జిహ్వగం, పవనాశనం, లేలిహానం, ద్విరసనం, కుంభీనసం, సారంగం, హరి, పాము, నిడుపడు, పడగదారి, గాలిమేతరి, విషదారి, కానిరానికాళ్ళది, చిల్వ, వీనులకంటి, పుట్టదిట్ట, పుట్ట కాపరి, కను వినికి, గుడ్డుకానుపు, చట్టుపురుగు, తొట్టు, త్రోచు, నిడుదవెన్ను, బుసకొట్టు, పురుగు, ముక్కంటి సొమ్ము, వెల్చ, సౌదరం', '', '', '', '', '2026-05-02 13:56:30'),
(15930, 2, 'సర్పి', 'n', 'నేయి,  పాకేది, జారేది,వంకరగా నడిచేది, కదలేది, ఒక విధమైన చర్మవ్యాధి', '', '', '', '', '2026-05-02 13:56:30'),
(15931, 2, 'సర్వం', '', 'సంసర్వఅన్ని, ఎల్ల; ++ పూర్ణమైనది, నిశ్శేషమైనది,జలం', '', '', '', '', '2026-05-02 13:56:30'),
(15932, 2, 'సర్వంకషం', 'n', 'సర్వశక్తిమంతం,సర్వాన్ని నాశనం చేసేది సర్వకాలీనం', '', '', '', '', '2026-05-02 13:56:30'),
(15933, 2, 'సర్వంసహ', 'n', 'భూమి,  అంతా (అన్నిటిని) సహించేది', '', '', '', '', '2026-05-02 13:56:31'),
(15934, 2, 'సర్వజనీనం', 'n', 'ప్రసిద్ధం, ప్రఖ్యాతం ,ఎల్లరకూతెలిసినది, ఎల్లరకూ హితమైనది, ఎల్లరకూ తెలిసినది', '', '', '', '', '2026-05-02 13:56:31'),
(15935, 2, 'సర్వజ్ఞుడు', 'n', 'శివుడు, సర్వమూ తెలిసినవాడు,  బుద్ధుడు, స్త్రీ, దుర్గ, పరమాత్ముడు, అన్నీ తెలిసిన వాడు', '', '', '', '', '2026-05-02 13:56:31'),
(15936, 2, 'సర్వతోముఖం', 'n', 'అన్ని విధాలైనది;వ్యు', '', '', '', '', '2026-05-02 13:56:31'),
(15937, 2, 'సర్వత్రా', '', 'సంఅవ్యఅతటా, అన్నిచోట్లా,అన్నివేళల్లో,', '', '', '', '', '2026-05-02 13:56:31'),
(15938, 2, 'సర్వధా', '', 'సంఅవ్యఅన్నివిధాల, ఎల్లవేళలా, పూర్తిగా, నిశ్శేషంగా, అతిశయంగా సర్వదమనుడు', '', '', '', '', '2026-05-02 13:56:31'),
(15939, 2, 'సర్వనామం', 'n', 'నామానికి మారుగా ఉపయోగింపదగిన పదం; \'సర్వ\' మొదలైన పదాలు సర్వనామాలు', '', '', '', '', '2026-05-02 13:56:31'),
(15940, 2, 'సర్వనాశనం', 'n', 'పూర్తి నాశనం', '', '', '', '', '2026-05-02 13:56:31'),
(15941, 2, 'సర్వభక్షుడు', 'n', 'అగ్ని, అన్నిటినీ  భక్షించే (తినే)వాడు, సమస్తాన్ని తినేవాడు సర్వమంగళ n పార్వతి, సమస్తమైన', '', '', '', '', '2026-05-02 13:56:31'),
(15942, 2, 'సర్వమంగళం', 'n', 'శూన్యం', '', '', '', '', '2026-05-02 13:56:31'),
(15943, 2, 'సర్వసమానతా సిద్దాంతం', 'n', 'అందరూ సమానం అనే నిర్ణయం', '', '', '', '', '2026-05-02 13:56:31'),
(15944, 2, 'సర్వసాక్షి', 'n', 'పరమాత్మ, అన్నిటికీ సాక్షి, వాయుదేవుడు,', '', '', '', '', '2026-05-02 13:56:31');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(15945, 2, 'సర్వహరం', 'n', 'మృత్యువు, అన్నిటినీ హరించేది', '', '', '', '', '2026-05-02 13:56:31'),
(15946, 2, 'సర్వాంగీణం', 'n', 'అన్ని అంశాలకు సంబంధించినది, అన్ని అంశాల్లో వ్యాపించినది', '', '', '', '', '2026-05-02 13:56:31'),
(15947, 2, 'సర్వాత్మనా', 'n', 'అంతటా, అందరిలో, అన్ని విధాలా', '', '', '', '', '2026-05-02 13:56:31'),
(15948, 2, 'సర్వీసు', 'n', 'సేవ, నౌకరి, ఉద్యోగం', '', '', '', '', '2026-05-02 13:56:31'),
(15949, 2, 'సర్వేజనాః', 'n', 'జనులంతా', '', '', '', '', '2026-05-02 13:56:31'),
(15950, 2, 'సర్వేశుడు', 'n', 'పరమాత్ముడు, శివుడు, చక్రవర్తి సర్వోత్తమం', '', '', '', '', '2026-05-02 13:56:31'),
(15951, 2, 'సలక్షణం', 'n', 'సమాన క్షణాలు ఉన్నది, లక్షణంతో కూడినది సలలితం', '', '', '', '', '2026-05-02 13:56:31'),
(15952, 2, 'సలసల', 'n', 'కాగడంలో, తెర్లడంలో ధ్వనికి అనుకరణం', '', '', '', '', '2026-05-02 13:56:31'),
(15953, 2, 'సలహా', 'n', 'ఆలోచన, సమ్మతి', '', '', '', '', '2026-05-02 13:56:31'),
(15954, 2, 'సలహాదారు', 'n', 'ఆలోచన చెప్పేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(15955, 2, 'సలహాసహకారాలు', '', 'మివిఆలోచనా సహాయాలు', '', '', '', '', '2026-05-02 13:56:31'),
(15956, 2, 'సలాం', 'n', 'నమస్కారం, వందనం', '', '', '', '', '2026-05-02 13:56:31'),
(15957, 2, 'సలాక', 'n', 'బంగారం  వంటివాటి కమ్మి,వెదురు  వంటి వాటి బద్ద', '', '', '', '', '2026-05-02 13:56:31'),
