(16034, 2, 'సాంద్రం', 'n', 'చిక్కనిది, దట్టమైనది, ఎడంలేనిది, మోటైనది, క్రిక్కిరిసి నది, దృఢమైనది, సమృద్ధమైనది, గాఢమైనది, జిడ్డుగలది, నున్ననిది, మెత్తనిది, మనోహరం, రాశి (గుంపు),పొద', '', '', '', '', '2026-05-02 13:56:31'),
(16035, 2, 'సాంధ్యరాగం', 'n', 'ఉదయ, సాయంసంధ్యలకు సంబంధించిన ఎరుపు సాంప్రదాయికం', '', '', '', '', '2026-05-02 13:56:31'),
(16036, 2, 'సాంబమూర్తి', 'n', 'శివుడు, అంబ (జగన్మాత)తో కూడుకొని ఉండేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16037, 2, 'సాంబశివుడు', 'n', 'ఈశ్వరుడు ,అంబ (జగత్తులకు తల్లి)తో కూడుకొని ఉండేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16038, 2, 'సాంబారు', '', 'తవిఒక విధమైన పప్పుచారు,పులుసు', '', '', '', '', '2026-05-02 13:56:31'),
(16039, 2, 'సాంబ్రాణి', 'n', 'ఊదు, ధూపద్రవ్య విశేషం,సాంబ్రాణి, సామ్రాణి, సంబరేను చెట్టువల్ల కలిగినది,  ఒక దేశం, సాంబ్రాణి దేశపు గుర్రం, సాంబ్రాణి దేశంలో పుట్టినది', '', '', '', '', '2026-05-02 13:56:31'),
(16040, 2, 'సాంవత్సరీకం', 'n', 'వార్షికం, ఆబ్దికం ,ఏడాదికోసారి జరిగేది, సంవత్సరంలో జరిగేది', '', '', '', '', '2026-05-02 13:56:31'),
(16041, 2, 'సాంసారికం', 'n', 'ఐహికం, ప్రాపంచికం, సంసారానికి సంబంధించినది', '', '', '', '', '2026-05-02 13:56:31'),
(16042, 2, 'సాంస్కృతిక పునరుజ్జీవనం', 'n', 'కుళ్ళిపోతున్న సమాజానికి, శిథిలమవుతున్న సంస్కృతికి కొత్త ప్రాణం పోయడం (1850 తర్వాత) కాలాన్ని సాంస్కృతిక వనరుజ్జీవనానికి సంబంధించిన కాలంగా చరిత్ర కారులు గుర్తిస్తారు', '', '', '', '', '2026-05-02 13:56:31'),
(16043, 2, 'సాకల్యం', 'n', 'సకలత్వం, పూర్ణత్వం సాంస్కృతిక విశేషసంస్కృతికి సంబంధించిన', '', '', '', '', '2026-05-02 13:56:31'),
(16044, 2, 'సాకారం', 'n', 'ఆకారం దాల్చు, రూపం ధరించు', '', '', '', '', '2026-05-02 13:56:31'),
(16045, 2, 'సాకు', '', 'కక్రిచాలు, వద్దు, (కన్న) చాలు, (తే) పెంచు, రక్షించు, నెపం', '', '', '', '', '2026-05-02 13:56:31'),
(16046, 2, 'సాకులు', 'n', 'మిష వ్యాజం, నెపం సాక్షీభూతం', '', '', '', '', '2026-05-02 13:56:31'),
(16047, 2, 'సాక్షాత్కరించు', 'v', 'ప్రత్యక్షమవు, కనిపింపచేయు', '', '', '', '', '2026-05-02 13:56:31'),
(16048, 2, 'సాక్షి', 'n', 'సాక్ష్యం ఇచ్చేవాడు, ప్రత్యక్ష జ్ఞానం ఉన్నవాడు, చూసేది, రుజువు చేసేది, నిర్ధారించేది, పరమాత్ముడు, కనివిని తెలుసుకున్న వాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16049, 2, 'సాక్ష్యం', 'n', 'సాక్షి కని విని చెప్పిన మాట, రుజువు, ఏకాదశాహశ్రాద్ధం (షో డశం)', '', '', '', '', '2026-05-02 13:56:31'),
(16050, 2, 'సాగనంపు', 'v', 'వెంట వెళ్ళు, అనుగమించు; ప్రయాణమై వెళ్ళే వారిని కొంత దూరం తీసుకొని పోయి విడవడం', '', '', '', '', '2026-05-02 13:56:31'),
(16051, 2, 'సాగరం', 'n', 'సముద్రం, సగర పుత్రుల చేత యజ్ఞాశ్న అన్వేషణకోసం తవ్వబడి నది,  సంద్రం, ఏనుగు చెవి మందం, నూనె నెయ్యి  వంటి నింపిన సిద్దెల వోడు ఒక జాతి మృగం', '', '', '', '', '2026-05-02 13:56:31'),
(16052, 2, 'సాగరతుల్యం', 'n', 'సముద్రంతో సమానమైనది', '', '', '', '', '2026-05-02 13:56:31'),
