(16056, 2, 'సాగించు', 'v', 'జరుపు, కానించు, నిర్వర్తించు, నెరవేర్చు,నడిపించు, ప్రవర్తించు, యత్నించు', '', '', '', '', '2026-05-02 13:56:31'),
