(16066, 2, 'సాతాళించు', 'n', 'ఉడికించి పోపున పెట్టు;నానిన గింజలు  వంటి వాటిని చమురు కొంచెం వేసి పక్వం చేయడం', '', '', '', '', '2026-05-02 13:56:31'),
(16067, 2, 'సాత్త్యికం', 'n', 'ఒక భావం, సత్యగుణంవల్ల పుట్టిన భావం,  యథార్థం, నిజమై నది, నిష్కపటం, సాధువు, శక్తిమంతం, సత్యగుణం కలది, మనస్సులో పుట్టినది', '', '', '', '', '2026-05-02 13:56:31'),
(16068, 2, 'సాత్త్విక భావాలు', 'n', 'స్తంభం,ప్రళయం, రోమాంచం, కంపం, స్వేదం, వైస్వర్యం, వైవర్ణ్యం, అశ్రుపాతం అనే ఎనిమిది సాత్విక భావాలు', '', '', '', '', '2026-05-02 13:56:31'),
(16069, 2, 'సాదం', 'n', 'అన్నం; n దిగబడటం,  అస్తమించడం, దిగబడటం,విసువు, కృశించడం, నశించడం, బాధ,  స్వచ్ఛత, గమనం', '', '', '', '', '2026-05-02 13:56:31'),
(16070, 2, 'సాదరం', 'n', 'దయ ఉన్నది ,ఆదరంతో కూడినది', '', '', '', '', '2026-05-02 13:56:31'),
(16071, 2, 'సాదా', 'v,n', 'సాధారణం, నగిషీలేనిది, మల్లవిద్యా విశేషం', '', '', '', '', '2026-05-02 13:56:31'),
(16072, 2, 'సాదృశ్యం', 'n', 'పోలిక,సామ్యం ,  ప్రతిరూపం, ప్రతిమ', '', '', '', '', '2026-05-02 13:56:31'),
(16073, 2, 'సాధకబాధకాలు', 'n', 'కష్టనష్టాలు, సాధించేవి బాధించేవి', '', '', '', '', '2026-05-02 13:56:31'),
(16074, 2, 'సాధనం', 'n', 'సాధించడం,  సౌఖ్యం, మృతసంస్కారం, స్వాధీనం, ఉపాయం , ఉపకరణం, హేతువు, ధనం, తపం, చెలిమి, ముక్తి, హింస', '', '', '', '', '2026-05-02 13:56:31'),
(16075, 2, 'సాధన సంపత్తి', 'n', 'నెరవేర్చడానికి అవసరమైన సంపద', '', '', '', '', '2026-05-02 13:56:31'),
