(16077, 2, 'సాధనాలు', '', 'నంవి పరికరాలు,ఉపకరణాలు', '', '', '', '', '2026-05-02 13:56:31'),
(16078, 2, 'సాధారణం', '', 'నంవి సామాన్యం, అందరికీ వర్తించే విధి, సామాన్య నియమం, జాతి లక్షణం', '', '', '', '', '2026-05-02 13:56:31'),
(16079, 2, 'సాధారణీకరణం', 'n', 'సామాన్యం చేయడం, విశ్వజనీనం చేయడం, నిర్విశేషం చేయడం, పరిశుద్ధం చేయడం', '', '', '', '', '2026-05-02 13:56:31'),
(16080, 2, 'సాధించేస్తున్నావు', 'v', 'చంపేస్తున్నావు', '', '', '', '', '2026-05-02 13:56:31'),
(16081, 2, 'సాధికారం', 'n', 'అధికారంగలది,ప్రభుత్వం గలది, రాజనియోగ బలం కలది', '', '', '', '', '2026-05-02 13:56:31'),
(16082, 2, 'సాధు', '', 'సంఅవ్యబాగు, మేలు; బళా,చాలు, సరి', '', '', '', '', '2026-05-02 13:56:31'),
(16083, 2, 'సాధుపాఠం', 'n', 'మంచిపాఠం', '', '', '', '', '2026-05-02 13:56:31'),
(16084, 2, 'సాధుపుంగవులు', 'n', 'మంచివారిలో శ్రేష్ఠమైనవారు', '', '', '', '', '2026-05-02 13:56:31'),
(16085, 2, 'సాధువు', 'n', 'మంచిది, శ్రేష్టమైనది, బుద్ద దేవుడు, మంచివాడు, తగినది, ముదుసలితనం, వడ్డికిచ్చి బతికేవాడు, మునీశ్వరుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16086, 2, 'సాధ్యం', 'n', 'సాధింప తగినది', '', '', '', '', '2026-05-02 13:56:31'),
(16087, 2, 'సాధ్వి', 'n', 'పతివ్రత, ఒక దినుసు దుంప, ఒక వృత్తం, (భ, న, జ, న, స, న, న, భ, గురువుగల వృత్తం8, 1,2, 22 యతిస్థానం)', '', '', '', '', '2026-05-02 13:56:31'),
(16088, 2, 'సాన', 'n', 'ఒరపురాయి, అస్త్రం  వంటిపదును పెట్టే రాయి;ఒరగల్లు, కరసాన, కటీక, కషం, కషోపలం, టీకం, నికషం, శాణం, శాణి, గంధంకోసం గంధం చెక్కతో బాదే రాయి, మణుల మొక్కలు పోయేటట్లుగా రాసే రాయి, గంధం తీసుకొనే రాయి', '', '', '', '', '2026-05-02 13:56:31'),
(16089, 2, 'సానబట్టు', 'v', 'వ దును బెట్టు, మెరుగుబెట్టు', '', '', '', '', '2026-05-02 13:56:31'),
(16090, 2, 'సాని', '', 'వి,సీ, వేశ్య, రాణి, భార్య,తల్లి అని అర్థం వచ్చే ప్రత్యయం, దొర సాని, మంత్రసాని', '', '', '', '', '2026-05-02 13:56:31'),
