(16322, 2, 'సుదర్శనం', 'n', 'విష్ణుచక్రం పేరు, చుట్టువాలు, సుడివాలు, వట్రు వాలు, బటువువాలు, వేయంచుల వాలు, పది నూరంచుల వాలు, బల్ల వాలు, చక్రం, చక్రాయుధం, కడిదులుగు, గుడుసు కైదువు, గుడుసు వాలు, చుట్టుకైదువు, బటువు కైదువు, బటువడిదం, బటువు గత్తి, వేమొనలలుగు, సుడి కత్తి, సుడి అగిదం, చుట్టులుగు, అరి, ఆయుధేంద్రం, అమరావతి, జంబూ ద్వీపం,మేరుపర్వతం పై నేరేడు', '', '', '', '', '2026-05-02 13:56:31'),
(16323, 2, 'సుదినం', 'n', 'మంచిరోజు, మబ్బులేని రోజు', '', '', '', '', '2026-05-02 13:56:31'),
(16324, 2, 'సుదీర్ఘం', 'n', 'మిక్కిలి పొడవైనది, ఒక విధమైన దోసకాయ', '', '', '', '', '2026-05-02 13:56:31'),
(16325, 2, 'సుదుర్లభం', 'n', 'బొత్తిగా లభించనిది,  అరుదైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16326, 2, 'సుదూరం', 'n', 'ఎక్కువ దూరం,మిక్కిలి దూరంలో ఉన్నది', '', '', '', '', '2026-05-02 13:56:31'),
(16327, 2, 'సుదృఢం', 'n', 'ఎక్కువ గట్టిది,  ఎక్కువ బలమైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16328, 2, 'సుద్ద', 'n', 'తెల్లమట్టి, (శుద్ధమృత్తిక); ఖటిని, కఠీనిక, ఖడి, ధవల మృత్తిక, పాకశుక్ల, వర్ణిక, శ్వేతధాతువు సు, ముచ్చటి, సల్లాపం,  మాట, వృత్తాంతం, ప్రసంగం, జాడ,శుచియైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16329, 2, 'సుద్దిచేయు', 'v', 'శుద్ధిపరచు సుద్దులాడు (సుద్దులు+ఆడు), మాట్లాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16330, 2, 'సుధ', 'n', 'అమృతం, సుఖంగా పానం చేయబడేది, సున్నం, పాలు, ఇటుక, జెముడుమొక్క, రసం,తేనె, మెరుపుతీగ', '', '', '', '', '2026-05-02 13:56:31'),
(16331, 2, 'సుధాకరుడు', 'n', '(సుధాంశుడు) చంద్రుడు, అమృత మయములైన కిరణాలు కలవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16332, 2, 'సుధాపూరం(బు)', 'n', 'అమృతంతో నిండినది', '', '', '', '', '2026-05-02 13:56:31'),
(16333, 2, 'సుధారసం', 'n', 'అమృతం', '', '', '', '', '2026-05-02 13:56:31'),
(16334, 2, 'సుధీ', 'n', 'విద్యావంతుడు, పండితుడు;రూసుధి, లెస్సగా విచారించే వాడు,  ఎక్కువ తెలివిగలది,మేలైన మేధాశక్తి, మేధావంతుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16335, 2, 'సునయన', 'n', 'అందమైన కళ్ళుగలఆడది, స్త్రీ,', '', '', '', '', '2026-05-02 13:56:31'),
(16336, 2, 'సునాయాసం', 'n', 'తేలిక, ఎక్కువ సులభం', '', '', '', '', '2026-05-02 13:56:31'),
(16337, 2, 'సునీతి', 'n', 'సత్రవర్తన, యోగ్యత,సన్మార్గం, ధ్రువుని తల్లి పేరు', '', '', '', '', '2026-05-02 13:56:31'),
(16338, 2, 'సున్నం', 'n', 'ముత్యం  వంటివి కాల్చిన తెల్లటి ఒక దినుసు పదార్థం, గోడలకు వెల్ల వేసే పొడి', '', '', '', '', '2026-05-02 13:56:31'),
(16339, 2, 'సున్నిఉండలు', 'n', 'బియ్యం  వంటి పిండిఉండలు', '', '', '', '', '2026-05-02 13:56:31'),
(16340, 2, 'సున్నితమైన', 'n', 'కచ్చితమైన,', '', '', '', '', '2026-05-02 13:56:31'),
(16341, 2, 'సుపక్వం', 'n', 'చక్కగా పండినది,  చక్కగా వండబడినది, ఒక రకం మామిడి పండు', '', '', '', '', '2026-05-02 13:56:31'),
(16342, 2, 'సుపరిచితులు', 'n', 'బాగా పరిచయం ఉన్న వారు', '', '', '', '', '2026-05-02 13:56:31'),
(16343, 2, 'సుపర్ణుడు', 'n', 'గరుత్మంతుడు ,మంచి రెక్కలు గలవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16344, 2, 'సుపర్ల', 'n', 'పద్మాల సమూహం, తామరకొలను, గరుడుని తల్లి పేరు, తామరతీగ, పాలపిట్ట, కోడి, గద్ద,కిరణం, రేలచెట్టు , సుపర్ణి', '', '', '', '', '2026-05-02 13:56:31'),
(16345, 2, 'సుపర్వులు', 'n', 'దేవతలు,సుపర్వాణులు, 1 శుభప్రదాలైన ఉత్సవాలు కలవారు, 2 యోగ్యాలైన అంగుళ్యాది గ్రంథులు గలవారు', '', '', '', '', '2026-05-02 13:56:31'),
(16346, 2, 'సుప్తి', 'n', 'నిద్ర;,  టికల, తిమ్మిరి,  మాంద్యం', '', '', '', '', '2026-05-02 13:56:31'),
(16347, 2, 'సుప్రతిష్ణ', 'n', 'కీర్తి, మంచి స్థితి,  స్థాపన, ప్రతిష్టించడం, ఐదవఛందం', '', '', '', '', '2026-05-02 13:56:31'),
(16348, 2, 'సుప్రభాతం', 'n', 'వేకువ, పవిత్రమైన  ఉదయం', '', '', '', '', '2026-05-02 13:56:31');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(16349, 2, 'సుప్రసన్నుడు', 'n', 'కుబేరుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16350, 2, 'సుఫలం', 'n', 'మంచి ఫలం గలది', '', '', '', '', '2026-05-02 13:56:31'),
(16351, 2, 'సుబా', 'n', 'రాజ్యభాగం, రాష్ట్రంలో ఒకభాగం, రాజ్యభాగం, మండలాధిపతి', '', '', '', '', '2026-05-02 13:56:31'),
(16352, 2, 'సుబాహువు', 'n', 'మారీచుని సోదరుడు, మంచి బాహువులు కలవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16353, 2, 'సుబేదారు', 'n', 'సేనాధికారులలో ఒకడు', '', '', '', '', '2026-05-02 13:56:31'),
(16354, 2, 'సుబోధకం', 'n', 'సులభంగా అర్థమయ్యేది', '', '', '', '', '2026-05-02 13:56:31'),
(16355, 2, 'సుభద్ర', 'n', 'అర్జునుని భార్య,అభిమన్యుని తల్లి', '', '', '', '', '2026-05-02 13:56:31'),
(16356, 2, 'సుభాషితం', 'n', 'హితవచనం, సూక్తి, చక్కగా పలుకబడినది, ధారాళమైన వచనం, చమత్కార వాక్యం,మంచి అభిప్రాయం', '', '', '', '', '2026-05-02 13:56:31'),
(16357, 2, 'సుభిక్షం', 'n', 'పాడి పంటల కలిమి,  మంచి బిచ్చం, ఆహారసమృద్ధి', '', '', '', '', '2026-05-02 13:56:31'),
(16358, 2, 'సుమం', 'n', 'పువ్వు', '', '', '', '', '2026-05-02 13:56:31'),
(16359, 2, 'సుమంగ(లి)లి', 'n', 'ముత్తైదువ, పుణ్య', '', '', '', '', '2026-05-02 13:56:31'),
(16360, 2, 'సుమంతుడు', 'n', 'మంచి ఆలోచన చెప్పేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16361, 2, 'సుమతి', 'n', 'మంచి బుద్ధిగలవాడు, మంచి బుద్ది, మైత్రి, దేవతా వరప్రసాదం, ఆశీస్సు, ప్రార్థనాగీతం, కోరిక, సగరుని భార్య పేరు', '', '', '', '', '2026-05-02 13:56:31'),
(16362, 2, 'సుమధురం', 'n', 'బాగా తియ్యనైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16363, 2, 'సుమనస్కులు', 'n', 'దేవతలు;రూసుమనస్సులు, మంచి మనస్సు కలవారు, పూలు, విద్వాంసులు', '', '', '', '', '2026-05-02 13:56:31'),
(16364, 2, 'సుమారు', 'n', 'కొంచెం హెచ్చు తగ్గు', '', '', '', '', '2026-05-02 13:56:31'),
(16365, 2, 'సుముఖుడు', 'n', 'సిద్దమైనవాడు, విద్వాంసుడు, గరుత్మంతుని పేరు, గణపతి పేరు, శివుని పేరు, యతి, గరుడుని కొడుకు, ఒక నాగ పుత్రుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16366, 2, 'సుముహూర్తం', 'n', 'మంచి ఘడియ,మంచి ముహూర్తం', '', '', '', '', '2026-05-02 13:56:31'),
(16367, 2, 'సుయోధనుడు', 'n', 'దుర్యోధనుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16368, 2, 'సురంగం', 'n', 'సొరంగం, భూగర్భ మార్గం, రంధ్రం, ప్రకాశం, మంచిరంగు, నారింజ, రక్తచందనం,సిందూరం', '', '', '', '', '2026-05-02 13:56:31'),
(16369, 2, 'సుర', 'n', 'కల్లు, సారాయం , వేలుపు,గాలి, సుడిగాలి, నీరు, పాము, తుంగముస్తే పానపాత్రం', '', '', '', '', '2026-05-02 13:56:31'),
(16370, 2, 'సురటి', 'n', 'విసనకర్ర, వీవన, మల్లవిద్యావిశేషం, పారావతం, గళరవం', '', '', '', '', '2026-05-02 13:56:31'),
(16371, 2, 'సురతరువు', 'n', 'కల్పవృక్షం', '', '', '', '', '2026-05-02 13:56:31'),
(16372, 2, 'సురపతి', 'n', 'ఇంద్రుడు, దేవతలరాజు', '', '', '', '', '2026-05-02 13:56:31'),
(16373, 2, 'సురభి', 'n', 'కామధేనువు, అందుగు చెట్టు, బంగారు, వసంతరుతువు, ఆవు, చైత్రమాసం, జాజికాయ, సంపెంగ చెట్టు మంచి వాసనగలది, మనోహరమైనది, మద్యము, భూమి', '', '', '', '', '2026-05-02 13:56:31'),
(16374, 2, 'సురలు', 'n', 'దేవతలు', '', '', '', '', '2026-05-02 13:56:31'),
(16375, 2, 'సురలోకం', 'n', 'స్వర్గం, దేవతల పట్టణం (లోకం)', '', '', '', '', '2026-05-02 13:56:31'),
(16376, 2, 'సురవంద్యుడు', 'n', 'విష్ణువు, దేవతల చేత నమస్కరింపదగినవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16377, 2, 'సురసుర', 'n', 'కాలడంలో అనుకరణం,స్రుక్కడంలో అనుకరణం', '', '', '', '', '2026-05-02 13:56:31'),
(16378, 2, 'సురాచార్యుడు', 'n', 'బృహస్పతి ,దేవతల గురువు', '', '', '', '', '2026-05-02 13:56:31'),
(16379, 2, 'సురాధిరాజపదం', 'n', 'ఇంద్రపదవి', '', '', '', '', '2026-05-02 13:56:31'),
(16380, 2, 'సురారిరాజు', 'n', 'రాక్షసరాజు (హిరణ్యకశిపుడు)', '', '', '', '', '2026-05-02 13:56:31'),
(16381, 2, 'సురిగెడు', 'n', 'మాయమయ్యే, రూ సురుగెడు, మరలే, తప్పించు కొనే, నిష్క్రమించే, దాగే, పారిపోయే, మృతినొందే, నశించే, వాడే, వెనుదీసే, బాధ పడే', '', '', '', '', '2026-05-02 13:56:31'),
(16382, 2, 'సురుమా', '', 'ఉర్దూవికాటుక,సుర్మా,సురుమాయి', '', '', '', '', '2026-05-02 13:56:31'),
(16383, 2, 'సురూపం', 'n', 'సుందరం, తెలివిగలది', '', '', '', '', '2026-05-02 13:56:31'),
(16384, 2, 'సురూపుడు', 'n', 'చక్కటి వాడు, విద్వాంసుడు, శివుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16385, 2, 'సురేకారం', 'n', 'దేవిఒక దినుసు ఉప్పు సురేశ్వరుడు (సుర+ఈశ్వరుడు), ఇంద్రుడు, దేవతల ప్రభువు', '', '', '', '', '2026-05-02 13:56:31'),
(16386, 2, 'సులక్షణం', 'n', 'మంచి లక్షణం,   శుభ లక్షణాలు కలది, అదృష్టం కలది,పరిశీలనం, పరీక్ష, నిర్ణయం', '', '', '', '', '2026-05-02 13:56:31'),
(16387, 2, 'సులతాను', 'n', 'తురుష్క ప్రభువు,  ముస్లిం రాజు,సుల్తాను', '', '', '', '', '2026-05-02 13:56:31'),
(16388, 2, 'సులభం', 'n', 'తేలికగా చేయదగినది, సుఖంగా లభించేది, యోగ్యమైనది, సహజం, సులువు', '', '', '', '', '2026-05-02 13:56:31'),
(16389, 2, 'సులువు', 'n', 'సులభం, తేలికైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16390, 2, 'సులోచనం', 'n', 'జింక, కళ్ళజోడు,అందమైన కళ్ళు గలది;', '', '', '', '', '2026-05-02 13:56:31'),
