(16705, 2, 'స్వర్ణం', 'n', 'బంగారుపతకం, బంగారం;++బంగారు నాణెం, గైరిక ధాతువు, ఎర్రటెంకాయచెట్టు, గుజ్జునారికేళం', '', '', '', '', '2026-05-02 13:56:31'),
(16706, 2, 'స్వర్ణకారుడు', 'n', 'అగసాలె, కంసాలి,  బంగారపుపని చేసేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16707, 2, 'స్వర్ణపుష్ప', 'n', 'తుమ్మచెట్టు, బంగారపు వర్ణంలాంటి పూలు కలిగిన చెట్టు, చంపక వృక్షం', '', '', '', '', '2026-05-02 13:56:31'),
