(16709, 2, 'స్వల్పకాలశిక్షణ', 'n', 'కొద్ది కాలం ఇచ్చే శిక్షణ', '', '', '', '', '2026-05-02 13:56:31'),
(16710, 2, 'స్వశక్తి', 'n', 'తన శక్తి', '', '', '', '', '2026-05-02 13:56:31'),
(16711, 2, 'స్వస్తి', '', 'సంఅవ్య క్షేమం, శుభం,ఆశీర్వాదం', '', '', '', '', '2026-05-02 13:56:31'),
(16712, 2, 'స్వస్తిచెప్పు', '', 'మిక్రివదలి పెట్టు, విడుచు', '', '', '', '', '2026-05-02 13:56:31'),
(16713, 2, 'స్వస్థం', 'n', 'నెమ్మదిగా ఉండేది,స్వర్గంలో ఉండేది', '', '', '', '', '2026-05-02 13:56:31'),
(16714, 2, 'స్వస్థత', 'n', 'ఆరోగ్యంగా ఉండటం,ప్రసాదం', '', '', '', '', '2026-05-02 13:56:31'),
(16715, 2, 'స్వహస్తం', 'n', 'తనచేయి', '', '', '', '', '2026-05-02 13:56:31'),
(16716, 2, 'స్వహస్తపాకం', 'n', 'తన చేతి వంట', '', '', '', '', '2026-05-02 13:56:31'),
(16717, 2, 'స్వాంతం', 'n', 'మనస్సు, అనునయించడం, గుహ, రంధ్రం, తన మరణం', '', '', '', '', '2026-05-02 13:56:31'),
(16718, 2, 'స్వాంతుడు', 'n', 'మనస్సుకలవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16719, 2, 'స్వాగతం', 'n', 'సుఖంగా వచ్చారా అని అడగడం, ఒక వృత్తం, న్యాయంగా ఆర్జింపబడినది, అభిమతమైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16720, 2, 'స్వాతంత్ర్యం', 'n', 'స్వతంత్రభావం', '', '', '', '', '2026-05-02 13:56:31'),
(16721, 2, 'స్వాతి', 'n', 'సంజ్ఞాదేవి, సూర్యుని భార్య,  ఒక నక్షత్రం, ఖడ్గం', '', '', '', '', '2026-05-02 13:56:31'),
(16722, 2, 'స్వాదువు', 'n', 'ఇంపైనది, పరిశుద్ధమైనది, దృఢమైనది, మాధుర్యం, బెల్లం,అందం', '', '', '', '', '2026-05-02 13:56:31'),
(16723, 2, 'స్వాధీనం', 'n', 'స్వవశమైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16724, 2, 'స్వాధీనపతిక', 'n', 'నాయికా విశేషం ,స్వాధీనుడగు (తనకు వశుడు) భర్త గల నాయిక', '', '', '', '', '2026-05-02 13:56:31'),
(16725, 2, 'స్వాధీనపరచుకొను', '', 'మిక్రితన వశం  చేసుకొను', '', '', '', '', '2026-05-02 13:56:31'),
(16726, 2, 'స్వాధ్యాయం', 'n', 'వేదాధ్యయనం , తన  వేదాన్ని మాత్రమే అధ్యయనం చేయడం, వేదం, జపం', '', '', '', '', '2026-05-02 13:56:31'),
(16727, 2, 'స్వానుభవం', 'n', 'సొంత అనుభవం', '', '', '', '', '2026-05-02 13:56:31'),
(16728, 2, 'స్వాభావికం', 'n', 'సహజమైనది,  స్వభావంచేత కలిగినది', '', '', '', '', '2026-05-02 13:56:31'),
(16729, 2, 'స్వాభిమానం', 'n', 'ఆత్మగౌరవం', '', '', '', '', '2026-05-02 13:56:31'),
(16730, 2, 'స్వామి', 'n', 'అధిపతి, యజమాని ,స్వ (ధనం) గలవాడు, అధికారి, కుమారస్వామి, దేవుడు, వస్తు స్వాతంత్ర్యం గలవాడు, భర్త, గొప్ప సన్యాసి,ఆచార్యుడు, రాజు', '', '', '', '', '2026-05-02 13:56:31'),
(16731, 2, 'స్వామ్యం', 'n', 'హక్కు, ఆధిపత్యం,', '', '', '', '', '2026-05-02 13:56:31'),
(16732, 2, 'స్వాయత్తం', 'n', 'తనకు అధీనమైనది,తన మీదనే ఆధారపడి ఉండేది', '', '', '', '', '2026-05-02 13:56:31'),
(16733, 2, 'స్వారస్యం', 'n', 'సహజసౌందర్యం కలిగిఉండటం, లాలిత్యం, సహజత్వం', '', '', '', '', '2026-05-02 13:56:31'),
(16734, 2, 'స్వారి', 'n', 'వాహ్యాళి, విహారం', '', '', '', '', '2026-05-02 13:56:31'),
(16735, 2, 'స్వార్జితం', 'n', 'సొంత సంపాదన', '', '', '', '', '2026-05-02 13:56:31'),
(16736, 2, 'స్వార్థం', 'n', 'తన ప్రయోజనం,  ధాత్వాదులకు నిశ్చితమైన అర్థం', '', '', '', '', '2026-05-02 13:56:31'),
(16737, 2, 'స్వార్థ వూరిత', 'n', 'సొంతప్రయోజనంతో నిండిన', '', '', '', '', '2026-05-02 13:56:31'),
(16738, 2, 'స్వార్థపరత', 'n', 'సొంతప్రయోజనం', '', '', '', '', '2026-05-02 13:56:31'),
(16739, 2, 'స్వాస్థ్యం', 'n', 'స్వస్థత, ఆరోగ్య స్థితి, ఆత్మ విశ్వాసం, స్థిరత్వం,సంపద, తృప్తి, ఆరోగ్య స్థితి', '', '', '', '', '2026-05-02 13:56:31'),
(16740, 2, 'స్వాహ', 'n', 'అగ్నిదేవుని భార్య;నానో సర్వ దేవతా సామాన్యమైన ఆహుతి, బుద్దుని భార్య', '', '', '', '', '2026-05-02 13:56:31'),
(16741, 2, 'స్వాహావల్లభుడు', 'n', 'అగ్నిదేవుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16742, 2, 'స్వినం', 'n', 'చెమటతో కూడినది,  ఉడికినది', '', '', '', '', '2026-05-02 13:56:31'),
(16743, 2, 'స్వీకరించు', '', 'నంక్రిగ్రహించు, అంగీకరించు, అవధరించు', '', '', '', '', '2026-05-02 13:56:31'),
(16744, 2, 'స్వీకర్త', 'n', 'స్వీకరించేవాడు, గ్రహించేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16745, 2, 'స్వీకారం', 'n', 'గ్రహణం, అంగీకారం,పాణిగ్రహణం', '', '', '', '', '2026-05-02 13:56:31'),
(16746, 2, 'స్వీకృతం', 'n', 'గ్రహింపబడినది,అంగీకరింపబడినది', '', '', '', '', '2026-05-02 13:56:31'),
(16747, 2, 'స్వీట్లు', 'n', 'మధుర పదార్థాలు, తీపి పదార్థాలు', '', '', '', '', '2026-05-02 13:56:31'),
(16748, 2, 'స్వీయ', 'n', 'ఒక నాయిక, తన భర్తమీద మాత్రం అనురాగం ఉన్న నాయిక', '', '', '', '', '2026-05-02 13:56:31'),
(16749, 2, 'స్వీయచరిత్ర', 'n', 'తన చరిత్ర, తన కథ', '', '', '', '', '2026-05-02 13:56:31'),
(16750, 2, 'స్వీయుడు', 'n', 'తనవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16751, 2, 'స్వేచ్చానువాదం', 'n', 'స్వతంత్రానువాదం', '', '', '', '', '2026-05-02 13:56:31'),
(16752, 2, 'స్వేచ్ఛ', 'n', 'ఇష్టం, స్వెరిత', '', '', '', '', '2026-05-02 13:56:31'),
(16753, 2, 'స్వేచ్ఛాజీవి', 'n', 'తన ఇష్టం వచ్చినట్లు బతికేవాడు', '', '', '', '', '2026-05-02 13:56:31'),
(16754, 2, 'స్వేదం', 'n', 'చెమట, ఒకసాత్త్యిక భావం, ఉష్ణం, ఆవిరి ,', '', '', '', '', '2026-05-02 13:56:31'),
(16755, 2, 'స్వేదజం', 'n', 'నల్లి, పేను; ,చెమటవల్ల పుట్టినది', '', '', '', '', '2026-05-02 13:56:31'),
(16756, 2, 'స్వైరం', 'n', 'స్వేచ్ఛ, స్వతంత్రత,  తన ఇష్టం వచ్చినట్లు సంచరించేది, స్వేచ్ఛతో కూడినది, రహస్యమైనది, ఋజువైనది, మందమైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16757, 2, 'స్వైరవిహారి', 'n', 'అడ్డులేకుండా సంచరించేది', '', '', '', '', '2026-05-02 13:56:31'),
(16758, 2, 'స్వైరిణి', 'n', 'కులట, ఇష్టానుసారంగా  సంచ రించే స్త్రీ', '', '', '', '', '2026-05-02 13:56:31'),
(16759, 2, 'హంగామ', 'v,n', 'హడావిడి, గందరగోళం; ఆర్భాటం;', '', '', '', '', '2026-05-02 13:56:31'),
(16760, 2, 'హంగు', 'n', 'ఒనరు, ఆనుకూల్యం,  డాబు, దర్పం, అట్టహాసం, కార్యసిద్ధి కోసం వెనుక నుంచి చేసే ప్రయత్నం', '', '', '', '', '2026-05-02 13:56:31'),
(16761, 2, 'హంత', 'n', 'చంపేవాడు; హింసించేవాడు, తొలగించే వాడు, ధ్వంసం చేసేవాడు, దొంగ, దుష్టురాలు, మాయ, మోసం, మోసగత్తె', '', '', '', '', '2026-05-02 13:56:31'),
(16762, 2, 'హంస', 'n', 'అంచ;  శ్వేతగరుత్తు, మానసౌకసం, సత్వతేజ, పాలూనీరూ వేరుచేసే పులుగు, తెలిపిట్ట, పరమాత్మ, యోగివిశేషం, తెల్లగుర్రం, శరీరవాయు విశేషం, మంత్రభేదం, మాత్సర్యం, దున్నపోతు, తీర్థం, శాఖోత్పత్తి జరిగే చెట్టుభాగం, ఒక చెట్టు, హాస్యరసం, నవ్వు', '', '', '', '', '2026-05-02 13:56:31'),
(16763, 2, 'హంసపాదం', 'n', 'రాతలో తప్పుఉండే చోట ఉండే హంస పాద ఆకారపు గుర్తు ,  హంసపాదు,సిందూరం, పాదరసం', '', '', '', '', '2026-05-02 13:56:31'),
(16764, 2, 'హంసయానం', 'n', 'అంచనడకలాంటి నడక; అంచలుగా లాగబడే వాహనం', '', '', '', '', '2026-05-02 13:56:31'),
(16765, 2, 'హక్కులు', 'n', 'బాధ్యతలు, అధికారం, ఆస్తి మొదలైనవాటి మీద స్వామ్యం', '', '', '', '', '2026-05-02 13:56:31'),
(16766, 2, 'హట్టభూమి', 'n', 'అంగడిభూమి,సంత;', '', '', '', '', '2026-05-02 13:56:31');
INSERT INTO `dictionary_entries` (`id`, `dictionary_id`, `word`, `telugu`, `hindi`, `transliteration`, `part_of_speech`, `example_source`, `example_target`, `created_at`) VALUES
(16767, 2, 'హఠం', 'n', 'పట్టుదల, మొండితనం,మారాం; బలాత్కారం, నాచు, తూటికూర, యోగవిశేషం, దౌర్జన్యం, పీడనం, అత్యావశ్యకత, శత్రువు వెనుక సురుగుట, ఆకస్మికలాభం', '', '', '', '', '2026-05-02 13:56:31'),
(16768, 2, 'హఠాత్తుగా', '', 'అవ్య ఉన్నట్టుండి , తటుక్కున, అకస్మాత్తుగా', '', '', '', '', '2026-05-02 13:56:31'),
(16769, 2, 'హడలిపోవు', 'n', 'మిక్రి భయపడు; చంపడం;కొట్టడం, బాధింపబడినది, నష్టమైనది, కొల్లగొట్టబడినది, నిరాశపొందినది, అడ్డగింప బడినది, దీనమైనది', '', '', '', '', '2026-05-02 13:56:31'),
(16770, 2, 'హడావుడి', 'n', 'తొందరపాటు,కంగారు;', '', '', '', '', '2026-05-02 13:56:31'),
(16771, 2, 'హతం (బుగ) జేయడం', 'v', 'చచ్చేట్టుగా చేయడం, నశింపచేయడం', '', '', '', '', '2026-05-02 13:56:31'),
(16772, 2, 'హతాశుడు', 'n', 'ఆశ కోల్పోయినవాడు కోరికతీరనివాడు, జాలిలేనివాడు విషణుడు, శక్తి హీనుడు, దయారహితుడు, వ్యర్ధుడు, నీచుడు', '', '', '', '', '2026-05-02 13:56:31'),
(16773, 2, 'హతి', 'n', 'దెబ్బ,   నష్టం, అపజయం, లోపం,చంపడం', '', '', '', '', '2026-05-02 13:56:31'),
(16774, 2, 'హతుడు', 'n', 'చంపబడినవాడు,కొట్టబడినవాడు, నిరాశ చెందిన వాడు, అడ్డగింపబడిన వాడు, పూర్తిగా ధ్వంసం చేయబడినవాడు, దీనుడు', '', '', '', '', '2026-05-02 13:56:31'),
