(16909, 2, 'హేతుదృష్టి', 'n', 'భగవంతుని అస్తిత్వ విషయాన్ని సందేహించే స్వభావం;', '', '', '', '', '2026-05-02 13:56:31'),
(16910, 2, 'హేతువాదం', 'n', 'భగవంతుని అస్తిత్వాన్ని సందేహిస్తూ చేసేవాదం; వివాదం, కపటం', '', '', '', '', '2026-05-02 13:56:31'),
(16911, 2, 'హేతువు', 'n', 'కారణం,   మొదలు, తలపు, గురు, సాధనం, ఫలం, ప్రమాణం, ప్రేరకుడు, వెల, ఒక అర్థాలంకారం, పోలిక, నియమం, ఉద్దేశం, హేతు వాదం, విధం', '', '', '', '', '2026-05-02 13:56:31'),
(16912, 2, 'హేమం', 'n', 'బంగారం  లోహాంతరాన్ని కూడి వృద్ధి పొందేది,  ఉమ్మెత్త, మంచు, నల్లగుర్రం, గుర్రం, వైశ్వదేవం, దేవయజ్ఞం, నాగకేసరం, జలం, శీతకాలం', '', '', '', '', '2026-05-02 13:56:31'),
(16913, 2, 'హేమంతం', 'n', 'హేమంత ఋతువు,వ్యు , మార్గశీర్ష పుష్యమాసాలతో కూడిన ఋతువు', '', '', '', '', '2026-05-02 13:56:31'),
(16914, 2, 'హేమాంగం సంపత్తి', 'n', 'సంపద, సమృద్ధి,  భాగ్యాతిశయం, జయం, తగిన స్థితి, పూర్తి, సిద్ది, సమగ్రత', '', '', '', '', '2026-05-02 13:56:31'),
(16915, 2, 'హేమాద్రి', 'n', 'సుమేరు పర్వతం, మేరుపర్వతం,   బంగారు కొండ,  చతుర్వర్గ చింతామణికర్త', '', '', '', '', '2026-05-02 13:56:31'),
